    def _build_statusbar(self):
        sb = QStatusBar()
        self.setStatusBar(sb)
        self.statusBar().showMessage("Ready")
        
        # Add autosave toggle at the right side
        self._autosave_checkbox = QCheckBox("Auto-save")
        self._autosave_checkbox.setChecked(self._autosave_enabled)
        self._autosave_checkbox.toggled.connect(self._toggle_autosave)
        self._autosave_checkbox.setStyleSheet("""
            QCheckBox {
                color: #cccccc;
                spacing: 5px;
                padding: 3px 8px;
            }
            QCheckBox::indicator {
                width: 16px;
                height: 16px;
                border: 1px solid #3e3e42;
                border-radius: 3px;
                background-color: #1e1e1e;
            }
            QCheckBox::indicator:checked {
                background-color: #0e639c;
                border: 1px solid #007acc;
            }
        """)
        self.statusBar().addPermanentWidget(self._autosave_checkbox)

    def _toggle_calendar_view(self, checked: bool):
        self._set_main_view(checked)

    def _set_main_view(self, show_calendar: bool):
        self._is_calendar_view = show_calendar
        if show_calendar:
            self.main_stack.setCurrentWidget(self.calendar_page)
            self._refresh_calendar_data()
            if hasattr(self, "calendar_widget"):
                self._populate_calendar_day_list(self.calendar_widget.selectedDate())
        else:
            self.main_stack.setCurrentWidget(self._main_details_widget)

        if hasattr(self, "act_calendar") and self.act_calendar.isChecked() != show_calendar:
            self.act_calendar.blockSignals(True)
            self.act_calendar.setChecked(show_calendar)
            self.act_calendar.blockSignals(False)

    def show_calendar_view(self):
        self._set_main_view(True)

    def show_details_view(self):
        self._set_main_view(False)

    def show_tasks_view(self):
        self._is_calendar_view = False
        if hasattr(self, "main_stack") and hasattr(self, "tasks_page"):
            self.main_stack.setCurrentWidget(self.tasks_page)
            self._refresh_tasks_view_list()
        if hasattr(self, "act_calendar") and self.act_calendar.isChecked():
            self.act_calendar.blockSignals(True)
            self.act_calendar.setChecked(False)
            self.act_calendar.blockSignals(False)

    def _get_tasks_file_path(self) -> Path:
        username = str(self.settings.value("username", "") or "").strip()
        if not username:
            username = "default"
        safe_name = sanitize_name(username)
        if not safe_name:
            safe_name = "default"
        return self.paths.root / f"tasks_{safe_name}.json"

