    def _build_bid_status_board(self) -> QWidget:
        board = QWidget()
        board.setSizePolicy(QSizePolicy.Policy.MinimumExpanding, QSizePolicy.Policy.Expanding)
        board.setMinimumWidth(600)
        board_layout = QHBoxLayout(board)
        board_layout.setContentsMargins(0, 0, 0, 0)
        board_layout.setSpacing(8)
        movable_statuses = {"Pending", "Takeoff", "Revising"}

        def make_column(title: str, refreshable: bool = False) -> QWidget:
            container = QWidget()
            container_layout = QVBoxLayout(container)
            container_layout.setContentsMargins(0, 0, 0, 0)
            container_layout.setSpacing(6)

            header_row = QHBoxLayout()
            title_label = QLabel(f"<b>{title}</b>")
            header_row.addWidget(title_label)
            header_row.addStretch()
            if refreshable:
                refresh_btn = QPushButton("Refresh")
                refresh_btn.setMaximumWidth(80)
                refresh_btn.clicked.connect(self._refresh_submitted_column)
                header_row.addWidget(refresh_btn)
            container_layout.addLayout(header_row)

            lw = BidBoardStatusListWidget(title, self._on_bid_board_card_dropped, self)
            lw.setUniformItemSizes(True)
            lw.setSelectionMode(QListWidget.SelectionMode.SingleSelection)
            lw.setContextMenuPolicy(Qt.ContextMenuPolicy.CustomContextMenu)
            can_move = title in movable_statuses
            lw.setDragEnabled(can_move)
            lw.setAcceptDrops(can_move)
            lw.setDropIndicatorShown(can_move)
            lw.setDefaultDropAction(Qt.DropAction.MoveAction)
            lw.setDragDropMode(QAbstractItemView.DragDropMode.DragDrop if can_move else QAbstractItemView.DragDropMode.NoDragDrop)
            lw.itemDoubleClicked.connect(lambda item, t=title: self._on_bid_board_double_clicked(t))
            lw.customContextMenuRequested.connect(lambda pos, t=title: self._context_menu_for_bid_board(t, pos))
            # Reduce selection highlight visibility for custom widgets
            lw.setStyleSheet("""
                QListWidget::item:selected {
                    background-color: transparent;
                    border: 1px solid #007ACC;
                }
            """)
            container_layout.addWidget(lw, 1)

            container.setMinimumWidth(220)
            self.bid_status_lists[title] = lw
            return container

        # Pending + Tasks stacked on the left
        left_stack = QWidget()
        left_stack_layout = QVBoxLayout(left_stack)
        left_stack_layout.setContentsMargins(0, 0, 0, 0)
        left_stack_layout.setSpacing(8)
        left_stack_layout.addWidget(make_column("Pending"), 2)

        # Tasks mini-column
        tasks_container = QWidget()
        tasks_container.setMinimumWidth(220)
        tasks_container_layout = QVBoxLayout(tasks_container)
        tasks_container_layout.setContentsMargins(0, 0, 0, 0)
        tasks_container_layout.setSpacing(6)
        tasks_header_row = QHBoxLayout()
        tasks_title_label = QLabel("<b>Tasks</b>")
        tasks_header_row.addWidget(tasks_title_label)
        tasks_header_row.addStretch()
        tasks_container_layout.addLayout(tasks_header_row)
        self.board_tasks_list = QListWidget()
        self.board_tasks_list.setSelectionMode(QListWidget.SelectionMode.SingleSelection)
        self.board_tasks_list.setStyleSheet("""
            QListWidget::item:selected {
                background-color: transparent;
                border: 1px solid #007ACC;
            }
        """)
        self.board_tasks_list.itemDoubleClicked.connect(lambda _item: self.open_task_manager())
        self.board_tasks_list.setContextMenuPolicy(Qt.ContextMenuPolicy.CustomContextMenu)
        self.board_tasks_list.customContextMenuRequested.connect(self._on_board_task_context_menu)
        tasks_container_layout.addWidget(self.board_tasks_list, 1)
        left_stack_layout.addWidget(tasks_container, 1)
        board_layout.addWidget(left_stack, 1)

        for name in ["Takeoff", "Revising"]:
            board_layout.addWidget(make_column(name), 1)

        board_layout.addWidget(make_column("Submitted", refreshable=True), 1)

        right_stack = QWidget()
        right_stack_layout = QVBoxLayout(right_stack)
        right_stack_layout.setContentsMargins(0, 0, 0, 0)
        right_stack_layout.setSpacing(8)
        right_stack_layout.addWidget(make_column("Awarded"), 1)
        right_stack_layout.addWidget(make_column("Archived"), 1)
        board_layout.addWidget(right_stack, 1)

        return board

    def _build_project_status_board(self) -> QWidget:
        board = QWidget()
        board.setSizePolicy(QSizePolicy.Policy.MinimumExpanding, QSizePolicy.Policy.Expanding)
        board.setMinimumWidth(600)
