    def _refresh_submitted_column(self):
        submitted_rows: List[Dict] = []
        if self.paths.submitted.exists():
            for p in sorted(self.paths.submitted.iterdir()):
                if not p.is_dir():
                    continue
                info = self._read_parent_info_cached(p)
                submitted_rows.append({"path": p, "name": p.name, "info": info})
        self._submitted_rows_cache = submitted_rows
        self._include_submitted_in_board = True
        self.refresh_list(refresh_calendar=False)

    def _clear_bid_board_lists(self):
        for lw in self.bid_status_lists.values():
            lw.blockSignals(True)
            lw.clear()
            lw.blockSignals(False)
        if hasattr(self, "board_tasks_list"):
            self.board_tasks_list.clear()

    def _clear_project_board_lists(self):
        for lw in self.project_status_lists.values():
            lw.blockSignals(True)
            lw.clear()
            lw.blockSignals(False)

    def _refresh_board_tasks_list(self):
        """Populate the Tasks mini-panel on the board with incomplete tasks."""
        if not hasattr(self, "board_tasks_list"):
            return
        self.board_tasks_list.clear()
        estimator_filter = self.estimator_combo.currentText().strip() if hasattr(self, "estimator_combo") else "All"
        tasks = self._load_tasks()
        for task in tasks:
            if task.get("completed"):
                continue
            assignee = task.get("assigned_to", "").strip()
            if estimator_filter != "All" and assignee != estimator_filter:
                continue
            name = task.get("name", "")
            due = task.get("due_date", "")
            record_rel = self._task_record_rel_path(task)
            if record_rel:
                bid_name = Path(record_rel).name or "General"
            else:
                bid_name = "General"
            assignee_part = f"  @{assignee}" if assignee else ""
            label = f"[{bid_name}]  {name}  —  {due}{assignee_part}" if due else f"[{bid_name}]  {name}{assignee_part}"
            item = QListWidgetItem(label)
            item.setData(Qt.ItemDataRole.UserRole, task.get("id", ""))
            self.board_tasks_list.addItem(item)

    def _complete_task_from_board(self, task_id: str) -> None:
        tasks = self._load_tasks()
        idx = self._find_task_index(tasks, task_id)
        if idx < 0:
            return
        if bool(tasks[idx].get("completed", False)):
            return
        tasks[idx]["completed"] = True
        tasks[idx]["completed_at"] = now_iso()
        self._save_tasks(tasks)
        self._refresh_board_tasks_list()
        self._refresh_calendar_data()

    def _on_board_task_context_menu(self, pos: QPoint) -> None:
        item = self.board_tasks_list.itemAt(pos)
        if not item:
            return
        task_id = str(item.data(Qt.ItemDataRole.UserRole) or "")
        if not task_id:
            return
        menu = QMenu(self)
        act_complete = menu.addAction("  Mark Complete")
        action = menu.exec(self.board_tasks_list.mapToGlobal(pos))
        if action == act_complete:
            self._complete_task_from_board(task_id)

    def _on_bid_board_double_clicked(self, source_status: str):
        """Handle double-click on board item to open details popup."""
        source_list = self.bid_status_lists.get(source_status)
        if source_list is None:
            return
        item = source_list.currentItem()
        if item is None:
            return

        raw_path = item.data(Qt.ItemDataRole.UserRole)
        if not raw_path:
            return

        self._bid_board_sync_in_progress = True
        try:
            for status_name, lw in self.bid_status_lists.items():
                if status_name == source_status:
                    continue
                lw.clearSelection()
            self._select_path_in_list(Path(str(raw_path)))
            self._show_details_popup()
        finally:
            self._bid_board_sync_in_progress = False

    def _on_bid_board_card_dropped(self, source_status: str, target_status: str, raw_path: str) -> None:
        allowed = {"Pending", "Takeoff", "Revising"}
        if source_status not in allowed or target_status not in allowed:
            self.refresh_list(refresh_calendar=False)
            return
        if source_status == target_status:
            return

        path = Path(str(raw_path))
        if not path.exists():
            self.refresh_list(refresh_calendar=False)
            return

        try:
            info = self._read_parent_info_cached(path)
            previous_status = str(info.get("status", "")).strip() or source_status
            info["status"] = target_status
            write_info(path, info)
            self._invalidate_active_metrics_cache(path)
            self._on_bid_status_updated(path, previous_status, target_status)
            self.refresh_list(refresh_calendar=False)
            self._select_path_in_list(path)
            self.statusBar().showMessage(f"Moved to {target_status}", 3000)
        except Exception as e:
            self.refresh_list(refresh_calendar=False)
            QMessageBox.warning(self, "Move Failed", f"Could not move bid to {target_status}:\n{e}")

    def _sync_bid_board_selection_from_list(self):
        if self._bid_board_sync_in_progress or not self.bid_status_lists:
            return

        selected = self.selected_item()
        selected_path = None
        if selected is not None:
            raw_path = selected.data(Qt.ItemDataRole.UserRole)
            if raw_path:
                selected_path = str(raw_path)

        self._bid_board_sync_in_progress = True
        try:
            for lw in self.bid_status_lists.values():
                lw.clearSelection()

            if not selected_path:
                return

            for lw in self.bid_status_lists.values():
                for row_idx in range(lw.count()):
                    item = lw.item(row_idx)
                    if item is None:
                        continue
                    raw = item.data(Qt.ItemDataRole.UserRole)
                    if raw and str(raw) == selected_path:
                        lw.setCurrentItem(item)
                        return
        finally:
            self._bid_board_sync_in_progress = False

    def _context_menu_for_bid_board(self, source_status: str, pos):
        source_list = self.bid_status_lists.get(source_status)
        if source_list is None:
            return
        viewport = source_list.viewport()
        if viewport is None:
            return
        self._show_context_menu(viewport.mapToGlobal(pos))

