    def _canonical_project_status(self, raw_status: str, fallback: str = "Submittals") -> str:
        status_norm = str(raw_status or "").strip().lower()
        if not status_norm:
            return fallback

        status_map = {
            "active": "Submittals",
            "submittal": "Submittals",
            "submittals": "Submittals",
            "production": "Production",
            "installation": "Installation",
            "install": "Installation",
            "punch list": "Punchlist",
            "punchlist": "Punchlist",
            "punch": "Punchlist",
            "complete": "Complete",
            "completed": "Complete",
        }
        return status_map.get(status_norm, fallback)

    def _normalize_status_for_current_category(self, raw_status: str) -> str:
        if self.current_category == "projects":
            return self._canonical_project_status(raw_status)
        return str(raw_status or "").strip()

    def _configure_status_choices_for_current_category(self) -> None:
        if not hasattr(self, "lbl_status"):
            return

        current_text = self.lbl_status.currentText().strip()
        normalized_text = self._normalize_status_for_current_category(current_text) if current_text else ""
        statuses = PROJECT_STATUSES if self.current_category == "projects" else BID_STATUSES

        self.lbl_status.blockSignals(True)
        self.lbl_status.clear()
        self.lbl_status.addItems(statuses)
        if normalized_text:
            self.lbl_status.setCurrentText(normalized_text)
        else:
            self.lbl_status.setCurrentIndex(-1)
        self.lbl_status.blockSignals(False)

