    def _read_parent_info_cached(self, parent_path: Path) -> Dict:
        """Read parent info.json with mtime-based cache invalidation."""
        cache_key = str(parent_path)
        info_path = parent_path / INFO_FILE

        try:
            stat_result = info_path.stat()
            mtime_ns = stat_result.st_mtime_ns
            size = stat_result.st_size
        except Exception:
            mtime_ns = None
            size = None

        cached = self._parent_info_cache.get(cache_key)
        if cached and cached.get("mtime_ns") == mtime_ns and cached.get("size") == size:
            data = cached.get("data", {})
            return dict(data) if isinstance(data, dict) else {}

        data = read_info(parent_path)
        if not isinstance(data, dict):
            data = {}

        self._parent_info_cache[cache_key] = {
            "mtime_ns": mtime_ns,
            "size": size,
            "data": data,
        }
        return dict(data)

    def _position_matches(self, position_value: str, expected_position: str) -> bool:
        if not position_value or not expected_position:
            return False
        expected = expected_position.strip().lower()
        position_lower = position_value.strip().lower()
        if expected in position_lower:
            return True
        tokens = [token.strip().lower() for token in re.split(r"[,;/|]", position_value) if token.strip()]
        if not tokens:
            tokens = [position_lower]
        return expected in tokens

    def _hidden_bid_statuses(self) -> set:
        """Statuses hidden from general bid pickers/views."""
        return {"submitted", "archived", "awarded"}

    def _migrate_submitted_bids_to_submitted_folder(self):
        """Move already-submitted bids into the submitted folder once per root."""
        migration_key = f"submitted_folder_migrated::{self.paths.root}"
        if self.settings.value(migration_key, False, type=bool):
            return

        moved = 0
        for bid_path in list_bids(self.paths.bids):
            info = read_info(bid_path)
            status = str(info.get("status", "")).strip().lower()
            if status != "submitted":
                continue
            target_path = self.paths.submitted / bid_path.name
            if target_path.exists():
                continue
            try:
                shutil.move(str(bid_path), str(target_path))
                moved += 1
            except Exception:
                continue

        self.settings.setValue(migration_key, True)

    def _migrate_awarded_bids_to_projects_once(self):
        """Convert legacy awarded bids into project records once per data root."""
        migration_key = f"awarded_to_projects_migrated::{self.paths.root}"
        if self.settings.value(migration_key, False, type=bool):
            return

        candidates: List[Path] = []
        seen_paths: set[str] = set()

        def add_candidate(path: Path) -> None:
            if not path.exists() or not path.is_dir():
                return
            try:
                resolved = str(path.resolve())
            except Exception:
                resolved = str(path)
            if resolved in seen_paths:
                return
            seen_paths.add(resolved)
            candidates.append(path)

        for bid_path in list_bids(self.paths.bids):
            info = read_info(bid_path)
            if str(info.get("status", "")).strip().lower() == "awarded":
                add_candidate(bid_path)

        if self.paths.submitted.exists():
            for bid_path in sorted(self.paths.submitted.iterdir()):
                if not bid_path.is_dir() or bid_path.name.startswith('.'):
                    continue
                info = read_info(bid_path)
                if str(info.get("status", "")).strip().lower() == "awarded":
                    add_candidate(bid_path)

        if self.paths.awarded.exists():
            for awarded_entry in sorted(self.paths.awarded.iterdir()):
                if awarded_entry.name.startswith('.'):
                    continue
                try:
                    actual_path = awarded_entry.resolve() if awarded_entry.is_symlink() else awarded_entry
                except Exception:
                    continue
                add_candidate(actual_path)

        for bid_path in candidates:
            try:
                self._convert_bid_to_project(bid_path)
            except FileExistsError:
                continue
            except Exception:
                continue

        self.settings.setValue(migration_key, True)

    def _load_company_position_names(self, expected_position: str) -> List[str]:
        names = []
        if not self.company_contacts_csv.exists():
            return names

        try:
            with open(self.company_contacts_csv, 'r', newline='', encoding='utf-8-sig') as f:
                reader = csv.DictReader(f)
                for row in reader:
                    name = row.get("Contact Name", "").strip()
                    position = row.get("Position", "").strip()
                    if name and self._position_matches(position, expected_position):
                        names.append(name)
        except Exception:
            return []

        return sorted(set(names))

    def _refresh_company_role_lists(self):
        self.estimators_list = self._load_company_position_names("Estimator")
        self.project_managers_list = self._load_company_position_names("Project Manager")

