    def _load_customers(self) -> List[str]:
        """Load customers from customers_info.csv."""
        customers_info_path = self.paths.root / "customers_info.csv"
        
        if not customers_info_path.exists():
            return []
        
        try:
            customers = []
            with open(customers_info_path, 'r', newline='', encoding='utf-8') as f:
                reader = csv.reader(f)
                headers = next(reader, None)
                for row in reader:
                    if row:
                        customer_name = row[0].strip()
                        if customer_name:
                            customers.append(customer_name)
            return sorted(customers)
        except Exception:
            return []

    def _load_customer_contacts(self) -> dict:
        """Load customer contacts from customers_contacts.csv.
        
        Returns:
            {customer_name: [contact_names]}
        """
        customers_contacts_path = self.paths.root / "customers_contacts.csv"
        contacts = {}
        
        if not customers_contacts_path.exists():
            return contacts
        
        try:
            with open(customers_contacts_path, 'r', newline='', encoding='utf-8') as f:
                reader = csv.reader(f)
                headers = next(reader, None)
                for row in reader:
                    if len(row) >= 2:
                        customer_name = row[0].strip()
                        contact_name = row[1].strip()
                        if customer_name and contact_name:
                            if customer_name not in contacts:
                                contacts[customer_name] = []
                            contacts[customer_name].append(contact_name)
            return contacts
        except Exception:
            return {}

    def _load_customer_contact_details(self) -> Dict[str, Dict[str, Dict[str, str]]]:
        """Load customer contact details keyed by customer and contact name.

        Returns:
            {customer_name: {contact_name: {"email": "...", "phone": "..."}}}
        """
        customers_contacts_path = self.paths.root / "customers_contacts.csv"
        details: Dict[str, Dict[str, Dict[str, str]]] = {}

        if not customers_contacts_path.exists():
            return details

        try:
            with open(customers_contacts_path, 'r', newline='', encoding='utf-8') as f:
                reader = csv.reader(f)
                _headers = next(reader, None)
                for row in reader:
                    if len(row) < 2:
                        continue
                    customer_name = row[0].strip()
                    contact_name = row[1].strip()
                    email = row[3].strip() if len(row) >= 4 else ""
                    phone = row[4].strip() if len(row) >= 5 else ""
                    if not customer_name or not contact_name:
                        continue
                    details.setdefault(customer_name, {})[contact_name] = {
                        "email": email,
                        "phone": phone,
                    }
            return details
        except Exception:
            return {}

    def save_details(self, path: Optional[Path] = None):
        """Save edited details back to info.json.
        
        Args:
            path: Optional path to save. If None, uses currently selected path.
        """
        p = path if path is not None else self.selected_path()
        if not p:
            return
        
        try:
            # Save current selection name to restore after refresh
            current_name = p.name
            
            info = read_info(p)
            
            # Update editable fields
            previous_status = info.get("status", "")
            info["status"] = self.lbl_status.currentText().strip()
            # Due date is bid-only.
            if self.current_category == "bids":
                if self.lbl_due.date().isValid() and self.lbl_due.date() != self.lbl_due.minimumDate():
                    info["due_date"] = self.lbl_due.date().toString("yyyy-MM-dd")
                else:
                    info["due_date"] = ""
            info["estimator"] = self.lbl_estimator.currentText().strip()
            info["project_manager"] = self.lbl_project_manager.currentText().strip()
            if self.current_category == "bids":
                info["proposal_type"] = self.lbl_proposal_type.currentText().strip()
            gcs = [self.gc_combo.currentText().strip()]
            for _gc_extra in getattr(self, "gc_extra_combos", []):
                gcs.append(_gc_extra.currentText().strip())
            gcs = [g for g in gcs if g]
            info["gcs"] = gcs
            info["gc"] = gcs[0] if gcs else ""
            pocs = [p.currentText().strip() for p in getattr(self, "poc_combos", [self.poc_combo])]
            info["pocs"] = pocs
            info["point_of_contact"] = pocs[0] if pocs else ""
            invite_docs = [d.text().strip() for d in getattr(self, "invite_doc_edits", [])]
            info["invite_docs"] = invite_docs
            info["address"] = self.edit_address.toPlainText().strip()
            info["project_info"] = self.edit_project_info.toPlainText().strip()
            # Persist only opening count display cache; bid total now comes from
            # workbook totals or explicit manual override to avoid stale values.
            opening_count_text = self.lbl_opening_count.text()
            if opening_count_text and opening_count_text != "-":
                info["cached_opening_count"] = opening_count_text
            
            write_info(p, info)
            self._invalidate_active_metrics_cache(p)
            self._on_bid_status_updated(p, previous_status, info.get("status", ""))
            self._has_unsaved_changes = False
            self._current_editing_path = p
            self.statusBar().showMessage("Details saved", 3000)
            QMessageBox.information(self, "Saved", "Bid details saved successfully.")
            self.refresh_list()  # Refresh in case status or other display fields changed
            
            # Restore selection
            self._select_name_in_list(current_name)
        except Exception as e:
            QMessageBox.critical(self, "Save Details", f"Could not save details:\n{e}")

    def on_sort_field_changed(self, text: str):
        self.sort_field = text
        self.refresh_list(refresh_calendar=False)

    def toggle_sort_order(self):
        self.sort_ascending = not self.sort_ascending
        self.sort_order_btn.setText("▲" if self.sort_ascending else "▼")
        self.refresh_list(refresh_calendar=False)

    def refresh_list(self, refresh_calendar: bool = True):
        self._cancel_async_list_totals_refresh()
        needle = self.search_edit.text().strip().lower()
        self.list_widget.blockSignals(True)
        self.list_widget.setUpdatesEnabled(False)
        self.list_widget.clear()
        self.cached_paths.clear()

        def get_total_text(parent_info: Optional[Dict] = None) -> str:
            if not isinstance(parent_info, dict):
                return "-"
            raw_total = parent_info.get("bid_total")
            if raw_total in (None, ""):
                return "-"
            try:
                return self._format_currency(raw_total)
            except Exception:
                return "-"

        # Get estimator filter
        estimator_filter = self.estimator_combo.currentText() if hasattr(self, 'estimator_combo') else "All"
        # Get project manager filter
        pm_filter = self.pm_combo.currentText() if hasattr(self, 'pm_combo') else "All"
        self._clear_bid_board_lists()
        self._clear_project_board_lists()

        if self.current_category == "bids":
            rows = []
            sort_by_due_date = self.sort_field == "Due date"
            status_map = {
                "pending": "Pending",
                "takeoff": "Takeoff",
                "revising": "Revising",
                "submitted": "Submitted",
                "awarded": "Awarded",
                "archived": "Archived",
            }

            def canonical_status(raw_status: str, fallback: str = "Pending") -> str:
                status_norm = str(raw_status or "").strip().lower()
                if not status_norm:
                    return fallback
                return status_map.get(status_norm, fallback)

            def append_bid_row(path_for_actions: Path, display_name: str, info: Dict, fallback_status: str) -> None:
                if needle and needle not in display_name.lower():
                    return

                status = canonical_status(str(info.get("status", "")), fallback=fallback_status)

                estimator = str(info.get("estimator", "")).strip()
                if estimator_filter != "All" and estimator != estimator_filter:
                    return

                project_manager = str(info.get("project_manager", "")).strip()
                if pm_filter != "All" and project_manager != pm_filter:
                    return

                due_str = info.get("due_date", "")
                due = parse_due_date(due_str)
                rows.append({
                    "path": path_for_actions,
                    "name": display_name,
                    "status": status,
                    "due_str": due_str,
                    "due": due,
                    "info": info,
                })

            # Active bids folder
            for p in list_bids(self.paths.bids):
                info = self._read_parent_info_cached(p)
                append_bid_row(p, p.name, info, fallback_status="Pending")

            # Submitted folder is loaded only on-demand from the Submitted header refresh button.
            if self._include_submitted_in_board:
                for cached in self._submitted_rows_cache:
                    cached_path = cached.get("path")
                    cached_name = str(cached.get("name", "")).strip()
                    cached_info = cached.get("info", {})
                    if isinstance(cached_path, Path) and cached_name:
                        append_bid_row(cached_path, cached_name, cached_info if isinstance(cached_info, dict) else {}, fallback_status="Submitted")

            # Awarded folder (supports symlink entries)
            if self.paths.awarded.exists():
                for p in sorted(self.paths.awarded.iterdir()):
                    if not (p.is_dir() or p.is_symlink()):
                        continue
                    try:
                        actual_path = p.resolve() if p.is_symlink() else p
                    except Exception:
                        continue
                    info = self._read_parent_info_cached(actual_path)
                    append_bid_row(actual_path, p.name, info, fallback_status="Awarded")

            # Projects promoted from awarded bids — show in the Awarded column
            if self.paths.projects.exists():
                for p in sorted(self.paths.projects.iterdir()):
                    if not p.is_dir() or p.name.startswith('.'):
                        continue
                    info = self._read_parent_info_cached(p)
                    if not str(info.get("promoted_at", "")).strip():
                        continue
                    promoted_info = dict(info)
                    promoted_info["status"] = "Awarded"
                    append_bid_row(p, p.name, promoted_info, fallback_status="Awarded")

            # Sorting
            asc = self.sort_ascending
            field = self.sort_field
            if field == "Name":
                rows.sort(key=lambda r: r["name"].lower(), reverse=not asc)
            elif field == "Due date":
                sentinel = date.max if asc else date.min
                rows.sort(
                    key=lambda r: (r["due"] if r["due"] is not None else sentinel, r["name"].lower()),
                    reverse=not asc,
                )
            elif field == "Status":
                rows.sort(key=lambda r: (status_index(r["status"]), r["name"].lower()), reverse=not asc)

            shown = 0
            for r in rows:
                display_name = r["name"]
                total_text = get_total_text(r.get("info"))
                path_text = str(r["path"])
                status = str(r["status"])
                due_str = str(r.get("due_str", "")).strip()

                # Hidden backing list drives existing selection/actions/details behavior.
                item = QListWidgetItem(display_name)
                item.setData(Qt.ItemDataRole.UserRole, path_text)
                item.setData(Qt.ItemDataRole.UserRole + 1, status)
                self.list_widget.addItem(item)
                widget = self._make_list_item_widget(total_text, display_name)
                item.setSizeHint(widget.sizeHint())
                self.list_widget.setItemWidget(item, widget)

                status_list = self.bid_status_lists.get(status)
                if status_list is not None:
                    board_item = QListWidgetItem(display_name)
                    board_item.setData(Qt.ItemDataRole.UserRole, path_text)
                    status_list.addItem(board_item)
                    # Use bid card widget (with due date) for workflow columns, regular widget for terminal statuses
                    if status in ["Pending", "Takeoff", "Revising"]:
                        proposal_type = str(r.get("info", {}).get("proposal_type", ""))
                        info_obj = r.get("info", {}) if isinstance(r.get("info", {}), dict) else {}
                        raw_gcs = info_obj.get("gcs", [])
                        gcs: List[str] = []
                        if isinstance(raw_gcs, list):
                            gcs = [str(x).strip() for x in raw_gcs if str(x).strip()]
                        if not gcs:
                            gc_legacy = str(info_obj.get("gc", "")).strip()
                            if gc_legacy:
                                gcs = [gc_legacy]
                        gc = "Multiple GCs" if len(gcs) > 1 else (gcs[0] if gcs else "")
                        board_widget = self._make_bid_card_widget(total_text, display_name, due_str, proposal_type, gc)
                    else:
                        board_widget = self._make_list_item_widget(total_text, display_name)
                    board_item.setSizeHint(board_widget.sizeHint())
                    status_list.setItemWidget(board_item, board_widget)

                self.cached_paths.append(r["path"])
                shown += 1

            self.statusBar().showMessage(f"{shown} bids shown")

        else:
            rows = []

            for p in list_projects(self.paths.projects):
                if needle and needle not in p.name.lower():
                    continue

                info = self._read_parent_info_cached(p)
                project_manager = str(info.get("project_manager", "")).strip()
                if pm_filter != "All" and project_manager != pm_filter:
                    continue

                due_str = str(info.get("due_date", "")).strip()
                due = parse_due_date(due_str)
                status = self._canonical_project_status(str(info.get("status", "")), fallback="Submittals")
                rows.append({
                    "path": p,
                    "name": p.name,
                    "info": info,
                    "due": due,
                    "due_str": due_str,
                    "project_manager": project_manager,
                    "status": status,
                })

            asc = self.sort_ascending
            field = self.sort_field
            if field == "Due date":
                sentinel = date.max if asc else date.min
                rows.sort(
                    key=lambda r: (r["due"] if r["due"] is not None else sentinel, r["name"].lower()),
                    reverse=not asc,
                )
            else:
                rows.sort(key=lambda r: r["name"].lower(), reverse=not asc)

            shown = 0
            for r in rows:
                display_name = r["name"]
                project_manager = str(r.get("project_manager", "")).strip()
                due_str = str(r.get("due_str", "")).strip()
                status = str(r.get("status", "Submittals"))
                info_bits = []
                if project_manager:
                    info_bits.append(project_manager)
                if due_str:
                    info_bits.append(due_str)
                meta_text = " | ".join(info_bits) if info_bits else "Project"

                item = QListWidgetItem(display_name)
                item.setData(Qt.ItemDataRole.UserRole, str(r["path"]))
                item.setData(Qt.ItemDataRole.UserRole + 1, status)
                self.list_widget.addItem(item)
                widget = self._make_list_item_widget(meta_text, display_name)
                item.setSizeHint(widget.sizeHint())
                self.list_widget.setItemWidget(item, widget)

                status_list = self.project_status_lists.get(status)
                if status_list is not None:
                    board_item = QListWidgetItem(display_name)
                    board_item.setData(Qt.ItemDataRole.UserRole, str(r["path"]))
                    status_list.addItem(board_item)
                    board_widget = self._make_bid_card_widget("", display_name, due_str, "", project_manager)
                    board_item.setSizeHint(board_widget.sizeHint())
                    status_list.setItemWidget(board_item, board_widget)

                self.cached_paths.append(r["path"])
                shown += 1

            self.statusBar().showMessage(f"{shown} projects shown")

        self.list_widget.clearSelection()
        self.list_widget.setCurrentRow(-1)
        self.list_widget.setUpdatesEnabled(True)
        self.list_widget.blockSignals(False)
        self._sync_bid_board_selection_from_list()
        self._sync_project_board_selection_from_list()

        # Reset JSON editor for new list
        self._prev_selected_name = None
        self._clear_details_panel()
        if refresh_calendar:
            self._refresh_calendar_data()

        # Refresh tasks mini-panel on the board
        self._refresh_board_tasks_list()

        # Backfill live workbook totals incrementally without blocking list display.
        self._start_async_list_totals_refresh()

    # ---------- Selection helpers ----------

    def selected_item(self) -> Optional[QListWidgetItem]:
        items = self.list_widget.selectedItems()
        return items[0] if items else None

    def selected_name(self) -> Optional[str]:
        item = self.selected_item()
        return item.text() if item else None

    def selected_path(self) -> Optional[Path]:
        item = self.selected_item()
        return Path(item.data(Qt.ItemDataRole.UserRole)) if item else None

    def selected_status(self) -> Optional[str]:
        if self.current_category != "bids":
            return None
        item = self.selected_item()
        return item.data(Qt.ItemDataRole.UserRole + 1) if item else None

    def _select_name_in_list(self, name: str):
        items = self.list_widget.findItems(name, Qt.MatchFlag.MatchExactly)
        if items:
            self.list_widget.setCurrentItem(items[0])

    def _select_path_in_list(self, target_path: Path) -> bool:
        for row_idx in range(self.list_widget.count()):
            item = self.list_widget.item(row_idx)
            if not item:
                continue
            raw = item.data(Qt.ItemDataRole.UserRole)
            if not raw:
                continue
            try:
                item_path = Path(str(raw))
            except Exception:
                continue
            if item_path == target_path:
                self.list_widget.setCurrentItem(item)
                return True
        return False

    def _enable_item_actions(self, enabled: bool):
        # Toolbar common actions
        self.act_rename.setEnabled(enabled)
        self.act_delete.setEnabled(enabled)
        self.act_open.setEnabled(enabled)
        self.act_duplicate.setEnabled(enabled)

        # Right-pane common buttons
        self.btn_open.setEnabled(enabled)
        self.btn_rename.setEnabled(enabled)
        self.btn_delete.setEnabled(enabled)
        self.btn_duplicate.setEnabled(enabled)
        if hasattr(self, "btn_import_workbook"):
            self.btn_import_workbook.setEnabled(enabled)

        # Bid-only actions/buttons
        in_bids = self.current_category == "bids"
        self.act_change_status.setEnabled(enabled and in_bids)
        self.act_edit_due.setEnabled(enabled and in_bids)

        self.btn_change_status.setEnabled(enabled and in_bids)
        self.btn_edit_due.setEnabled(enabled and in_bids)
        if hasattr(self, "btn_add_task"):
            self.btn_add_task.setEnabled(enabled and in_bids)
        if hasattr(self, "btn_project_task_add"):
            self.btn_project_task_add.setEnabled(enabled)
        if hasattr(self, "btn_project_note_add"):
            self.btn_project_note_add.setEnabled(enabled)
    # ---------- Selection & context ----------

    def _details_popup_title(self) -> str:
        if self.current_category == "projects":
            return "Project Details"
        return "Bid Details"

    def _show_details_popup(self):
        """Show the bid details in a separate popup window."""
        if self._details_popup_window is None:
            # Use None as parent so the Bid Details window is fully independent
            # and does not minimize/restore along with the main (Bids) window.
            self._details_popup_window = DetailsPopupWindow(
                self._details_panel_widget,
                None,
                close_guard=self._confirm_close_details_popup,
                title=self._details_popup_title(),
            )
        else:
            self._details_popup_window.setWindowTitle(self._details_popup_title())
        
        if not self._details_popup_window.isVisible():
            screen = QApplication.primaryScreen()
            if screen is not None:
                avail = screen.availableGeometry()
                self._details_popup_window.setGeometry(avail)
                self._details_popup_window.show()
            else:
                self._details_popup_window.showMaximized()
        self._details_popup_window.raise_()
        self._details_popup_window.activateWindow()

    def _confirm_close_details_popup(self) -> bool:
        """Confirm whether Bid Details popup can close when there are unsaved edits."""
        if not self._has_unsaved_changes or not self._current_editing_path:
            return True

        reply = QMessageBox.question(
            self,
            "Unsaved Changes",
            "You have unsaved changes in the current bid/project. Do you want to save them before closing Bid Details?",
            QMessageBox.StandardButton.Save | QMessageBox.StandardButton.Discard | QMessageBox.StandardButton.Cancel,
            QMessageBox.StandardButton.Save,
        )

        if reply == QMessageBox.StandardButton.Save:
            self.save_details(path=self._current_editing_path)
            return not self._has_unsaved_changes
        if reply == QMessageBox.StandardButton.Cancel:
            return False
        return True

    def _on_list_item_double_clicked(self, _item: QListWidgetItem):
        if self.current_category == "projects" and self.selected_item() is not None:
            self._show_details_popup()

    def _on_selection_changed(self):
        # Don't trigger if we're already handling a selection change
        if self._selection_change_in_progress:
            return

        # Selection responsiveness is higher priority than background list total backfill.
        self._cancel_async_list_totals_refresh()

        self._selection_change_in_progress = True
        try:
            # Check for unsaved changes
            if self._has_unsaved_changes and self._current_editing_path:
                reply = QMessageBox.question(
                    self,
                    "Unsaved Changes",
                    "You have unsaved changes. Do you want to save them?",
                    QMessageBox.StandardButton.Save | QMessageBox.StandardButton.Discard | QMessageBox.StandardButton.Cancel,
                    QMessageBox.StandardButton.Save
                )

                if reply == QMessageBox.StandardButton.Save:
                    # Save using the path that was being edited
                    self.save_details(path=self._current_editing_path)
                elif reply == QMessageBox.StandardButton.Cancel:
                    # Restore previous selection without firing the handler again
                    if self._prev_selected_name:
                        self.list_widget.blockSignals(True)
                        try:
                            self._select_name_in_list(self._prev_selected_name)
                        finally:
                            self.list_widget.blockSignals(False)
                    self._sync_bid_board_selection_from_list()
                    self._sync_project_board_selection_from_list()
                    return
                # If Discard, just continue

            self._prev_selected_name = self.selected_name()
            has_sel = self.selected_item() is not None
            self._enable_item_actions(has_sel)
            self.update_details()
            self._sync_bid_board_selection_from_list()
            self._sync_project_board_selection_from_list()
        finally:
            self._selection_change_in_progress = False

    def _context_menu(self, pos):
        self._show_context_menu(self.list_widget.mapToGlobal(pos))

    def _show_context_menu(self, global_pos):
        if not self.selected_item():
            return
        menu = QMenu(self)
        menu.addAction(self.act_open)
        menu.addSeparator()
        if self.current_category == "bids":
            menu.addAction(self.act_change_status)
            menu.addAction(self.act_edit_due)
            menu.addSeparator()
        menu.addAction(self.act_duplicate)
        menu.addAction(self.act_rename)
        menu.addAction(self.act_delete)

        # Offline copy sub-menu
        menu.addSeparator()
        path = self.selected_path()
        offline_active = False
        if path:
            info = self._read_parent_info_cached(path)
            offline_active = bool(info.get("offline_checkout_active", False))
        offline_menu = menu.addMenu("Offline Copy")
        if not offline_active:
            offline_menu.addAction(self.act_save_offline)
        if offline_active:
            offline_menu.addAction(self.act_return_offline)
            offline_menu.addAction(self.act_clear_offline_flag)

        menu.exec(global_pos)

    # ---------- Details & actions ----------

    def _set_kpi_open_tasks_count(self, open_count: Optional[int]) -> None:
        if not hasattr(self, "_kpi_tasks_label"):
            return
        if open_count is None:
            self._kpi_tasks_label.setText("-")
            self._kpi_tasks_label.setStyleSheet(
                "border: none; background: transparent; font-size: 14px; font-weight: bold;"
            )
            return
        color = "#F44336" if open_count > 0 else "#4CAF50"
        self._kpi_tasks_label.setText(str(open_count))
        self._kpi_tasks_label.setStyleSheet(
            f"border: none; background: transparent; font-size: 14px; font-weight: bold; color: {color};"
        )

    def _update_kpi_strip(self) -> None:
        status_colors = {
            "Pending": "#607D8B",
            "Takeoff": "#9C27B0",
            "Revising": "#E65100",
            "Submitted": "#1565C0",
            "Awarded": "#2E7D32",
            "Archived": "#424242",
        }

        if hasattr(self, "_kpi_status_label"):
            status = self.lbl_status.currentText().strip()
            if self.current_category == "projects":
                status_colors = {
                    "Submittals": "#1565C0",
                    "Production": "#6A1B9A",
                    "Installation": "#EF6C00",
                    "Punchlist": "#00897B",
                    "Complete": "#2E7D32",
                }
            color = status_colors.get(status, "#858585")
            self._kpi_status_label.setText(status or "-")
            self._kpi_status_label.setStyleSheet(
                f"border: none; background: transparent; font-size: 14px; font-weight: bold; color: {color};"
            )

        if hasattr(self, "_kpi_days_label"):
            if self.current_category == "projects":
                pct_text = "-"
                pct_color = "#9ad27f"
                parent_path = self._current_editing_path if getattr(self, "_current_editing_path", None) else self.selected_path()
                if parent_path and parent_path.exists():
                    info = self._read_parent_info_cached(parent_path)
                    raw_pct = str(info.get("percent_complete", "")).strip()
                    if raw_pct:
                        normalized = raw_pct[:-1] if raw_pct.endswith("%") else raw_pct
                        try:
                            value = float(normalized.replace(",", ""))
                            value = max(0.0, min(100.0, value))
                            pct_text = f"{int(round(value))}%" if abs(value - round(value)) < 0.01 else f"{value:.1f}%"
                            if value >= 100:
                                pct_color = "#4CAF50"
                            elif value >= 50:
                                pct_color = "#FFC107"
                            else:
                                pct_color = "#EF6C00"
                        except Exception:
                            pct_text = "-"
                self._kpi_days_label.setText(pct_text)
                self._kpi_days_label.setStyleSheet(
                    f"border: none; background: transparent; font-size: 14px; font-weight: bold; color: {pct_color};"
                )
            else:
                due = self.lbl_due.date()
                today = QDate.currentDate()
                if due.isValid() and self.lbl_due.text().strip() != "-":
                    days = today.daysTo(due)
                    if days < 0:
                        text, color = f"{abs(days)}d Overdue", "#F44336"
                    elif days == 0:
                        text, color = "Due Today", "#FF9800"
                    elif days <= 7:
                        text, color = f"{days}d", "#FF9800"
                    elif days <= 14:
                        text, color = f"{days}d", "#FFC107"
                    else:
                        text, color = f"{days}d", "#4CAF50"
                    self._kpi_days_label.setText(text)
                    self._kpi_days_label.setStyleSheet(
                        f"border: none; background: transparent; font-size: 14px; font-weight: bold; color: {color};"
                    )
                else:
                    self._kpi_days_label.setText("-")
                    self._kpi_days_label.setStyleSheet(
                        "border: none; background: transparent; font-size: 14px; font-weight: bold;"
                    )

        if hasattr(self, "_kpi_type_label"):
            proposal_type = self.lbl_proposal_type.currentText().strip()
            color = "#2E7D32" if proposal_type == "Budget" else "#1565C0" if proposal_type == "Proposal" else "#858585"
            self._kpi_type_label.setText(proposal_type or "-")
            self._kpi_type_label.setStyleSheet(
                f"border: none; background: transparent; font-size: 14px; font-weight: bold; color: {color};"
            )

        if hasattr(self, "lbl_active_bid_total"):
            raw_total = self.lbl_active_bid_total.text().strip()
            total_text = raw_total if raw_total else "-"
            total_color = "#CCCCCC"
            if total_text.startswith("$"):
                total_color = "#4CAF50"
            if hasattr(self, "lbl_bid_total_source") and self.lbl_bid_total_source.text().strip().upper() == "MAN":
                total_color = "#F6AD55"
            self.lbl_active_bid_total.setStyleSheet(
                f"border: none; background: transparent; font-size: 14px; font-weight: bold; color: {total_color};"
            )

    def _update_gc_tab_titles(self) -> None:
        if not hasattr(self, "gc_tab_widget"):
            return
        visible_indices = getattr(self, "_gc_visible_indices", list(range(len(getattr(self, "gc_combos", [])))))
        for tab_pos, idx in enumerate(visible_indices):
            if idx >= len(self.gc_combos) or tab_pos >= self.gc_tab_widget.count():
                continue
            gc_combo = self.gc_combos[idx]
            name = gc_combo.currentText().strip()
            self.gc_tab_widget.setTabText(tab_pos, name if name else f"GC {idx + 1}")

    def _gc_slot_has_data(self, idx: int) -> bool:
        gc_combos = getattr(self, "gc_combos", [])
        poc_combos = getattr(self, "poc_combos", [])
        invite_edits = getattr(self, "invite_doc_edits", [])
        if idx < 0 or idx >= len(gc_combos):
            return False

        if gc_combos[idx].currentText().strip():
            return True
        if idx < len(poc_combos) and poc_combos[idx].currentText().strip():
            return True
        if idx < len(invite_edits) and invite_edits[idx].text().strip():
            return True
        return False

    def _on_add_gc_tab(self) -> None:
        gc_count = len(getattr(self, "gc_combos", []))
        current = getattr(self, "_gc_visible_count", None) or 1
        if current < gc_count:
            self._gc_visible_count = current + 1
            self._sync_gc_tabs(selected_idx=current)
        if hasattr(self, "btn_add_gc"):
            self.btn_add_gc.setEnabled(getattr(self, "_gc_visible_count", 1) < gc_count)

    def _sync_gc_tabs(self, selected_idx: Optional[int] = None, ensure_one_tab: bool = False) -> None:
        if not hasattr(self, "gc_tab_widget"):
            return

        gc_count = len(getattr(self, "gc_combos", []))
        if gc_count == 0:
            return

        if not hasattr(self, "_gc_visible_count") or self._gc_visible_count is None:
            n = max(1, sum(1 for i in range(gc_count) if self._gc_slot_has_data(i)))
            self._gc_visible_count = n

        n = min(self._gc_visible_count, gc_count)
        visible_indices = list(range(n))

        if hasattr(self, "btn_add_gc"):
            self.btn_add_gc.setEnabled(n < gc_count)

        self._gc_visible_indices = visible_indices

        self.gc_tab_widget.blockSignals(True)
        while self.gc_tab_widget.count() > 0:
            self.gc_tab_widget.removeTab(0)

        for idx in visible_indices:
            if idx < len(self._gc_tab_pages):
                self.gc_tab_widget.addTab(self._gc_tab_pages[idx], "")

        self.gc_tab_widget.blockSignals(False)
        self._update_gc_tab_titles()

        target_idx = selected_idx if selected_idx is not None else (visible_indices[-1] if visible_indices else None)
        if target_idx is not None and target_idx in visible_indices:
            self.gc_tab_widget.setCurrentIndex(visible_indices.index(target_idx))

    def _project_view_file_candidates(self, view_key: str) -> List[str]:
        if view_key == "financials":
            return ["Financials.csv"]
        if view_key == "purchase_orders":
            return ["Purchase Orders.csv", "Purchase_Orders.csv", "PurchaseOrders.csv", "POs.csv"]
        if view_key == "work_orders":
            return ["Work Orders.csv", "Work_Orders.csv", "WorkOrders.csv", "WOs.csv"]
        if view_key == "scheduling":
            return ["Schedule.csv"]
        return []

