    def _clear_project_view_table(self, view_key: str) -> None:
        table = getattr(self, "_project_view_tables", {}).get(view_key)
        if table is None:
            return
        table.blockSignals(True)
        table.clear()
        table.setRowCount(0)
        table.setColumnCount(0)
        table.blockSignals(False)
        self._project_view_table_paths[view_key] = None
        if hasattr(self, "_project_view_dirty"):
            self._project_view_dirty[view_key] = False
        if view_key == "financials":
            self._project_change_order_path = None
            if getattr(self, "_project_change_order_table", None) is not None:
                self._project_change_order_table.blockSignals(True)
                self._project_change_order_table.clearContents()
                self._project_change_order_table.setRowCount(0)
                self._project_change_order_table.blockSignals(False)
            self._refresh_project_change_order_markup_ui()

    def _resolve_project_view_csv_path(self, view_key: str) -> Optional[Path]:
        parent_path = self._selected_parent_for_project_views()
        if not parent_path:
            return None

        if view_key == "financials":
            info = self._read_parent_info_cached(parent_path)
            locked_name = str(info.get("locked_financials_csv", "")).strip() or "Locked_Financials.csv"
            locked_candidate = parent_path / locked_name
            if locked_candidate.exists() and locked_candidate.is_file():
                return locked_candidate

        active_workbook = self._get_active_workbook_path(parent_path)
        if not active_workbook:
            return None

        for filename in self._project_view_file_candidates(view_key):
            candidate = active_workbook / filename
            if candidate.exists() and candidate.is_file():
                return candidate
        return None

    def _load_project_detail_table(self, view_key: str, force_reload: bool = False) -> None:
        table = getattr(self, "_project_view_tables", {}).get(view_key)
        if table is None:
            return

        csv_path = self._resolve_project_view_csv_path(view_key)
        cached_path = self._project_view_table_paths.get(view_key)
        if not force_reload and csv_path is not None and cached_path == csv_path and table.rowCount() > 0:
            return

        if csv_path is None:
            self._clear_project_view_table(view_key)
            return

        headers, data_rows = self._read_csv_table(csv_path)
        display_rows = data_rows
        if view_key == "financials" and csv_path.name.lower() == "financials.csv":
            parent_path = self._selected_parent_for_project_views()
            active_workbook = self._get_active_workbook_path(parent_path) if parent_path else None
            if active_workbook and active_workbook.exists():
                display_rows = self._evaluate_financials_formulas_for_display(headers, data_rows, active_workbook)

        table.blockSignals(True)
        table.clear()

        if not headers:
            table.setRowCount(0)
            table.setColumnCount(0)
            table.blockSignals(False)
            self._project_view_table_paths[view_key] = csv_path
            if hasattr(self, "_project_view_dirty"):
                self._project_view_dirty[view_key] = False
            return

        table.setColumnCount(len(headers))
        if view_key != "financials":
            table.setHorizontalHeaderLabels(headers)
        table.setRowCount(len(display_rows))
        for row_idx, row in enumerate(display_rows):
            for col_idx in range(len(headers)):
                cell_text = row[col_idx] if col_idx < len(row) else ""
                table.setItem(row_idx, col_idx, QTableWidgetItem(str(cell_text)))

        table.blockSignals(False)
        self._project_view_table_paths[view_key] = csv_path
        if hasattr(self, "_project_view_dirty"):
            self._project_view_dirty[view_key] = False
        
        # Configure column sizing for Financials to match workbook style
        if view_key == "financials":
            hdr = table.horizontalHeader()
            hdr.setDefaultSectionSize(140)
            hdr.setStretchLastSection(False)
            
            desc_col_idx = self._get_header_index(headers, "Description")
            count_col_idx = self._get_header_index(headers, "Count")
            rate_col_idx = self._get_header_index(headers, "Rate")
            total_col_idx = self._get_header_index(headers, "Total")
            
            for col_idx in range(table.columnCount()):
                hdr.setSectionResizeMode(col_idx, QHeaderView.ResizeMode.Interactive)
            
            if desc_col_idx is not None:
                hdr.setSectionResizeMode(desc_col_idx, QHeaderView.ResizeMode.Stretch)
            if count_col_idx is not None:
                table.setColumnWidth(count_col_idx, 130)
            if rate_col_idx is not None:
                table.setColumnWidth(rate_col_idx, 150)
            if total_col_idx is not None:
                table.setColumnWidth(total_col_idx, 170)
            
            self._load_project_change_order_log()
            self._refresh_project_change_order_markup_ui()

    def _save_project_detail_table(self, view_key: str) -> None:
        table = getattr(self, "_project_view_tables", {}).get(view_key)
        if table is None:
            return

        csv_path = self._project_view_table_paths.get(view_key)
        if csv_path is None:
            csv_path = self._resolve_project_view_csv_path(view_key)
        if csv_path is None:
            QMessageBox.information(self, "Project Details", "No active workbook file is available for this tab.")
            return

        headers: List[str] = []
        for col_idx in range(table.columnCount()):
            header_item = table.horizontalHeaderItem(col_idx)
            headers.append(header_item.text() if header_item else "")

        rows: List[List[str]] = []
        for row_idx in range(table.rowCount()):
            row: List[str] = []
            for col_idx in range(table.columnCount()):
                item = table.item(row_idx, col_idx)
                row.append(item.text() if item else "")
            rows.append(row)

        try:
            with open(csv_path, "w", newline="", encoding="utf-8-sig") as f:
                writer = csv.writer(f)
                if headers:
                    writer.writerow(headers)
                writer.writerows(rows)
        except Exception as e:
            QMessageBox.warning(self, "Project Details", f"Could not save {csv_path.name}:\n{e}")
            return

        self._project_view_table_paths[view_key] = csv_path
        if hasattr(self, "_project_view_dirty"):
            self._project_view_dirty[view_key] = False
        QMessageBox.information(self, "Project Details", f"Saved {csv_path.name}.")

    def _resolve_project_change_order_log_path(self) -> Optional[Path]:
        parent_path = self._selected_parent_for_project_views()
        if not parent_path:
            return None
        return self._ensure_project_change_order_log(parent_path)

    def _next_project_change_order_number(self, storage_path: Path) -> str:
        existing_numbers: set[str] = set()
        for file_name in (
            "Change_Orders.csv",
            "Change_Orders_Costs.csv",
            "Change_Orders_Subcontractor.csv",
            "Change_Orders_Details.csv",
        ):
            file_path = storage_path / file_name
            headers, rows = self._read_csv_table(file_path)
            if not headers:
                continue
            for row in rows:
                if not row:
                    continue
                number = str(row[0] or "").strip()
                if number:
                    existing_numbers.add(number)

        numeric_values = [int(value) for value in existing_numbers if value.isdigit()]
        if numeric_values:
            return str(max(numeric_values) + 1)
        return "1"

    def _load_change_order_summary_rows(
        self,
        source_workbook: Path,
        storage_path: Path,
        source_kind: str,
        source_label: str,
        ohp_rate_override: Optional[float] = None,
    ) -> List[Dict[str, str]]:
        schedule_headers, schedule_rows = self._read_csv_table(source_workbook / "Schedule.csv")
        if not schedule_headers:
            return []

        widget = ChangeOrdersWidget(
            source_workbook,
            (schedule_headers, schedule_rows),
            parent=None,
            change_callback=None,
            storage_path=storage_path,
            ohp_rate_override=ohp_rate_override,
        )

        summaries: List[Dict[str, str]] = []
        try:
            all_numbers = (
                set(widget.alternates_openings_data.keys())
                | set(widget.alternates_costs_data.keys())
                | set(widget.alternates_subcontractor_data.keys())
                | set(widget.alternates_details_data.keys())
            )

            def sort_key(value: str) -> tuple[int, int, str]:
                txt = (value or "").strip()
                if txt.isdigit():
                    return (0, int(txt), txt)
                return (1, 0, txt.lower())

            for change_order_number in sorted(all_numbers, key=sort_key):
                widget.current_alternate = change_order_number
                widget.load_alternate_costs()
                widget.load_alternate_subcontractor()
                widget.load_alternate_details()
                widget._recalculate_current_alternate_sell()

                details = widget.alternates_details_data.get(change_order_number, {})
                description = str(details.get("description", "") or "").strip()
                amount_text = widget.total_sell_value_label.text().strip() or "$0.00"
                if source_kind == "workbook":
                    notes = f"Active workbook: {source_label}"
                else:
                    notes = "Project standalone change order"

                summaries.append(
                    {
                        "date": "",
                        "description": (
                            f"Change Order {change_order_number}: {description}"
                            if description
                            else f"Change Order {change_order_number}"
                        ),
                        "amount": amount_text,
                        "approved_by": "",
                        "notes": notes,
                        "number": change_order_number,
                        "source_kind": source_kind,
                        "source_label": source_label,
                    }
                )
        finally:
            widget.deleteLater()

        return summaries

    def _load_legacy_project_change_order_rows(self, parent_path: Path) -> List[Dict[str, str]]:
        log_path = self._ensure_project_change_order_log(parent_path)
        headers, rows = self._read_csv_table(log_path)
        if not headers:
            headers = ["Date", "Description", "Amount", "Approved By", "Notes"]

        column_map = {str(header or "").strip().lower(): idx for idx, header in enumerate(headers)}

        def get_value(row: List[str], name: str) -> str:
            idx = column_map.get(name.lower(), -1)
            if idx < 0 or idx >= len(row):
                return ""
            return str(row[idx] or "")

        legacy_rows: List[Dict[str, str]] = []
        for row_index, row in enumerate(rows):
            if not any(str(cell or "").strip() for cell in row):
                continue
            legacy_rows.append(
                {
                    "date": get_value(row, "Date"),
                    "description": get_value(row, "Description"),
                    "amount": get_value(row, "Amount"),
                    "approved_by": get_value(row, "Approved By"),
                    "notes": get_value(row, "Notes"),
                    "number": "",
                    "source_kind": "legacy",
                    "source_label": "Legacy Log",
                    "legacy_row_index": str(row_index),
                }
            )
        return legacy_rows

    def _populate_project_change_order_table(self, rows: List[Dict[str, str]]) -> None:
        table = getattr(self, "_project_change_order_table", None)
        if table is None:
            return

        headers = ["Date", "Description", "Amount", "Approved By", "Notes"]
        table.blockSignals(True)
        table.clearContents()
        if table.columnCount() != len(headers):
            table.setColumnCount(len(headers))
        table.setHorizontalHeaderLabels(headers)
        table.setRowCount(len(rows))

        for row_idx, row in enumerate(rows):
            values = [
                row.get("date", ""),
                row.get("description", ""),
                row.get("amount", ""),
                row.get("approved_by", ""),
                row.get("notes", ""),
            ]
            metadata = dict(row)
            for col_idx, value in enumerate(values):
                item = QTableWidgetItem(str(value or ""))
                if col_idx == 0:
                    item.setData(Qt.ItemDataRole.UserRole, metadata)
                table.setItem(row_idx, col_idx, item)

        table.blockSignals(False)
        if rows:
            table.selectRow(0)

    def _open_project_change_order_editor(self, change_order_number: Optional[str] = None) -> None:
        parent_path = self._selected_parent_for_project_views()
        if not parent_path:
            QMessageBox.information(self, "Project Details", "Select a project first.")
            return

        co_markup_cfg = self._get_project_change_order_markup_config(parent_path)
        co_markup_pct = float(co_markup_cfg["rate_pct"])
        co_markup_verified = bool(co_markup_cfg["verified"])

        active_workbook = self._get_active_workbook_path(parent_path)
        if not active_workbook:
            active_workbook = self._prompt_select_active_workbook(parent_path)
        if not active_workbook:
            return

        schedule_headers, schedule_rows = self._read_csv_table(active_workbook / "Schedule.csv")
        if not schedule_headers:
            QMessageBox.information(self, "Project Details", "Schedule.csv was not found in the active workbook.")
            return

        storage_path = self._ensure_project_change_order_storage(parent_path)

        dlg = QDialog(self)
        dlg.setWindowTitle("Project Change Orders")
        dlg.resize(*clamped_size(1400, 860))

        layout = QVBoxLayout(dlg)
        layout.setContentsMargins(10, 10, 10, 10)
        layout.setSpacing(8)

        info_label = QLabel(
            f"Pricing source: {active_workbook.name}   |   CO Markup: {co_markup_pct:.3f}% ({'Verified' if co_markup_verified else 'Unverified'})   |   Save location: {storage_path.name}"
        )
        layout.addWidget(info_label)

        change_orders_widget = ChangeOrdersWidget(
            active_workbook,
            (schedule_headers, schedule_rows),
            parent=dlg,
            change_callback=None,
            storage_path=storage_path,
            ohp_rate_override=(co_markup_pct / 100.0),
        )
        change_orders_widget.apply_theme(self.theme_colors)
        layout.addWidget(change_orders_widget, 1)

        if change_order_number:
            all_numbers = (
                set(change_orders_widget.alternates_openings_data.keys())
                | set(change_orders_widget.alternates_costs_data.keys())
                | set(change_orders_widget.alternates_subcontractor_data.keys())
                | set(change_orders_widget.alternates_details_data.keys())
            )
            if change_order_number not in all_numbers:
                change_orders_widget.alternates_openings_data[change_order_number] = []
                change_orders_widget.alternates_costs_data[change_order_number] = []
                change_orders_widget.alternates_subcontractor_data[change_order_number] = []
                change_orders_widget.alternates_details_data[change_order_number] = {
                    "description": "",
                    "delivery_count": "0",
                    "ot_hours": "0",
                    "sub_ohp": "0",
                    "include_parking": "1",
                    "include_supervision": "1",
                }
                change_orders_widget.changes_made = True
                change_orders_widget.update_alternates_list()

            matches = change_orders_widget.alternates_list.findItems(change_order_number, Qt.MatchFlag.MatchExactly)
            if matches:
                change_orders_widget.alternates_list.setCurrentItem(matches[0])

        button_box = QDialogButtonBox(QDialogButtonBox.StandardButton.Close)
        save_button = QPushButton("Save")
        save_button.setObjectName("primaryButton")
        button_box.addButton(save_button, QDialogButtonBox.ButtonRole.AcceptRole)

        def save_change_orders() -> None:
            change_orders_widget.save_current_alternate_data()
            change_orders_widget.changes_made = True
            change_orders_widget.save_to_csv()
            self._load_project_change_order_log()
            QMessageBox.information(dlg, "Project Change Orders", "Project change orders saved.")

        save_button.clicked.connect(save_change_orders)
        button_box.rejected.connect(dlg.reject)
        layout.addWidget(button_box)

        dlg.exec()

    def _open_selected_project_change_order(self) -> None:
        table = getattr(self, "_project_change_order_table", None)
        if table is None:
            return

        row = table.currentRow()
        if row < 0:
            QMessageBox.information(self, "Project Details", "Select a change order first.")
            return

        item = table.item(row, 0)
        metadata = item.data(Qt.ItemDataRole.UserRole) if item else None
        if not isinstance(metadata, dict):
            return

        source_kind = str(metadata.get("source_kind", "") or "")
        if source_kind == "project":
            self._open_project_change_order_editor(str(metadata.get("number", "") or "").strip() or None)
            return

        if source_kind == "workbook":
            parent_path = self._selected_parent_for_project_views()
            if not parent_path:
                return
            active_workbook = self._get_active_workbook_path(parent_path)
            if not active_workbook:
                active_workbook = self._prompt_select_active_workbook(parent_path)
            if active_workbook:
                self.view_schedule(workbook_path=active_workbook)
            return

        QMessageBox.information(
            self,
            "Project Details",
            "This is a legacy change order log row and cannot be opened in the standalone editor.",
        )

    def _load_project_change_order_log(self) -> None:
        table = getattr(self, "_project_change_order_table", None)
        if table is None:
            return

        self._refresh_project_change_order_markup_ui()

        parent_path = self._selected_parent_for_project_views()
        log_path = self._resolve_project_change_order_log_path()
        self._project_change_order_path = log_path

        ohp_rate_override = None
        if parent_path:
            co_markup_cfg = self._get_project_change_order_markup_config(parent_path)
            ohp_rate_override = float(co_markup_cfg["rate_pct"]) / 100.0

        if not parent_path:
            self._populate_project_change_order_table([])
            self._update_project_change_order_total_display()
            return

        combined_rows: List[Dict[str, str]] = []
        active_workbook = self._get_active_workbook_path(parent_path)
        if active_workbook and active_workbook.exists():
            combined_rows.extend(
                self._load_change_order_summary_rows(
                    active_workbook,
                    active_workbook,
                    "workbook",
                    active_workbook.name,
                    ohp_rate_override=ohp_rate_override,
                )
            )

        project_storage = self._project_change_order_storage_path(parent_path)
        if project_storage.exists() and project_storage.is_dir():
            pricing_workbook = active_workbook if active_workbook and active_workbook.exists() else None
            if pricing_workbook is not None:
                combined_rows.extend(
                    self._load_change_order_summary_rows(
                        pricing_workbook,
                        project_storage,
                        "project",
                        project_storage.name,
                        ohp_rate_override=ohp_rate_override,
                    )
                )

        combined_rows.extend(self._load_legacy_project_change_order_rows(parent_path))
        self._populate_project_change_order_table(combined_rows)
        self._update_project_change_order_total_display()

    def _save_project_change_order_log(self) -> None:
        self._load_project_change_order_log()

    def _add_project_change_order_row(self) -> None:
        parent_path = self._selected_parent_for_project_views()
        if not parent_path:
            QMessageBox.information(self, "Project Details", "Select a project first.")
            return
        storage_path = self._ensure_project_change_order_storage(parent_path)
        self._open_project_change_order_editor(self._next_project_change_order_number(storage_path))

    def _delete_project_change_order_row(self) -> None:
        table = getattr(self, "_project_change_order_table", None)
        if table is None:
            return
        row = table.currentRow()
        if row < 0:
            QMessageBox.information(self, "Project Details", "Select a change order row to delete.")
            return

        item = table.item(row, 0)
        metadata = item.data(Qt.ItemDataRole.UserRole) if item else None
        if not isinstance(metadata, dict):
            return

        source_kind = str(metadata.get("source_kind", "") or "")
        parent_path = self._selected_parent_for_project_views()
        if not parent_path:
            return

        if source_kind == "workbook":
            QMessageBox.information(
                self,
                "Project Details",
                "This change order belongs to the active workbook. Delete it from the workbook Change Orders tab.",
            )
            return

        if source_kind == "legacy":
            log_path = self._ensure_project_change_order_log(parent_path)
            headers, rows = self._read_csv_table(log_path)
            try:
                legacy_index = int(str(metadata.get("legacy_row_index", "-1") or "-1"))
            except Exception:
                legacy_index = -1
            if 0 <= legacy_index < len(rows):
                del rows[legacy_index]
                try:
                    with open(log_path, "w", newline="", encoding="utf-8-sig") as f:
                        writer = csv.writer(f)
                        writer.writerow(headers or ["Date", "Description", "Amount", "Approved By", "Notes"])
                        writer.writerows(rows)
                except Exception as e:
                    QMessageBox.warning(self, "Project Details", f"Could not update {log_path.name}:\n{e}")
                    return
            self._load_project_change_order_log()
            return

        if source_kind == "project":
            storage_path = self._ensure_project_change_order_storage(parent_path)
            change_order_number = str(metadata.get("number", "") or "").strip()
            if not change_order_number:
                return

            for file_name in (
                "Change_Orders.csv",
                "Change_Orders_Costs.csv",
                "Change_Orders_Subcontractor.csv",
                "Change_Orders_Details.csv",
            ):
                file_path = storage_path / file_name
                headers, rows = self._read_csv_table(file_path)
                filtered_rows = [r for r in rows if not r or str(r[0] or "").strip() != change_order_number]
                try:
                    with open(file_path, "w", newline="", encoding="utf-8-sig") as f:
                        writer = csv.writer(f)
                        if headers:
                            writer.writerow(headers)
                        writer.writerows(filtered_rows)
                except Exception as e:
                    QMessageBox.warning(self, "Project Details", f"Could not update {file_name}:\n{e}")
                    return

            self._load_project_change_order_log()

    def _calculate_project_change_order_total(self) -> float:
        """Calculate the sum of all Change Order amounts."""
        table = getattr(self, "_project_change_order_table", None)
        if table is None:
            return 0.0
        
        total = 0.0
        # Find the "Amount" column (usually column 2)
        amount_col = -1
        for col in range(table.columnCount()):
            header_item = table.horizontalHeaderItem(col)
            header_text = header_item.text() if header_item else ""
            if header_text.lower() == "amount":
                amount_col = col
                break
        
        if amount_col < 0:
            return 0.0
        
        # Sum all amounts in the column
        for row in range(table.rowCount()):
            item = table.item(row, amount_col)
            if item:
                text = item.text().strip()
                if text:
                    amount = self._parse_financials_number(text)
                    if amount > 0:
                        total += amount
        
        return total

    def _update_project_change_order_total_display(self) -> None:
        """Update the Total Change Orders label and adjusted Contract Amount."""
        if not hasattr(self, "_project_change_order_total_label"):
            return
        
        total = self._calculate_project_change_order_total()
        self._project_change_order_total_label.setText(
            f"Total Change Orders: {self._format_currency(total)}"
        )
        
        # Update Contract Amount display with adjustment
        if hasattr(self, "lbl_active_bid_total") and self.current_category == "projects":
            parent_path = self._selected_parent_for_project_views()
            if parent_path:
                contract_amount = self._get_total_amount_override(parent_path)
                if contract_amount is not None:
                    adjusted_amount = contract_amount + total
                    tooltip = f"Contract Amount: {self._format_currency(contract_amount)}\n"
                    tooltip += f"Total Change Orders: {self._format_currency(total)}\n"
                    tooltip += f"Adjusted Total: {self._format_currency(adjusted_amount)}"
                    self.lbl_active_bid_total.setToolTip(tooltip)

    def _selected_parent_for_project_views(self) -> Optional[Path]:
        if self.current_category != "projects":
            return None
        if self._current_editing_path and self._current_editing_path.exists():
            return self._current_editing_path
        selected = self.selected_path()
        if selected and selected.exists():
            return selected
        return None

    def _open_active_workbook_folder(self) -> None:
        parent_path = self._selected_parent_for_project_views()
        if not parent_path:
            QMessageBox.information(self, "Project Details", "Select a project first.")
            return
        active_workbook = self._get_active_workbook_path(parent_path)
        if not active_workbook:
            active_workbook = self._prompt_select_active_workbook(parent_path)
        if not active_workbook:
            return
        open_in_file_manager(active_workbook)

    def _open_project_detail_view(self, view_key: str) -> None:
        parent_path = self._selected_parent_for_project_views()
        if not parent_path:
            QMessageBox.information(self, "Project Details", "Select a project first.")
            return

        active_workbook = self._get_active_workbook_path(parent_path)
        if not active_workbook:
            active_workbook = self._prompt_select_active_workbook(parent_path)
        if not active_workbook:
            return

        if view_key == "scheduling":
            self.view_schedule(workbook_path=active_workbook)
            return

        target_csv = None
        for filename in self._project_view_file_candidates(view_key):
            candidate = active_workbook / filename
            if candidate.exists() and candidate.is_file():
                target_csv = candidate
                break

        if target_csv is None:
            QMessageBox.information(
                self,
                "Project Details",
                f"No matching CSV file was found in the active workbook for {view_key.replace('_', ' ').title()}.",
            )
            return

        QDesktopServices.openUrl(QUrl.fromLocalFile(str(target_csv)))

    def _on_project_details_tab_changed(self, tab_index: int) -> None:
        if getattr(self, "_project_detail_tab_changing", False):
            return
        if tab_index < 0:
            return
        if not hasattr(self, "_project_detail_tab_keys"):
            return
        if tab_index >= len(self._project_detail_tab_keys):
            return

        prev_idx = getattr(self, "_project_detail_prev_tab_index", 0)
        if prev_idx != tab_index and prev_idx < len(self._project_detail_tab_keys):
            prev_key = self._project_detail_tab_keys[prev_idx]
            if prev_key in {"financials", "purchase_orders", "work_orders"}:
                dirty = getattr(self, "_project_view_dirty", {}).get(prev_key, False)
                if dirty:
                    name = prev_key.replace("_", " ").title()
                    reply = QMessageBox.question(
                        self,
                        "Unsaved Changes",
                        f"You have unsaved changes in {name}.\nSave before leaving?",
                        QMessageBox.StandardButton.Save
                        | QMessageBox.StandardButton.Discard
                        | QMessageBox.StandardButton.Cancel,
                    )
                    if reply == QMessageBox.StandardButton.Save:
                        self._save_project_detail_table(prev_key)
                    elif reply == QMessageBox.StandardButton.Cancel:
                        self._project_detail_tab_changing = True
                        try:
                            self.project_details_views.setCurrentIndex(prev_idx)
                        finally:
                            self._project_detail_tab_changing = False
                        return
                    else:
                        # Discard
                        if hasattr(self, "_project_view_dirty"):
                            self._project_view_dirty[prev_key] = False

        self._project_detail_prev_tab_index = tab_index
        view_key = self._project_detail_tab_keys[tab_index]
        if view_key in {"financials", "purchase_orders", "work_orders"}:
            self._load_project_detail_table(view_key)

    def _refresh_project_detail_view_tabs(self) -> None:
        if not hasattr(self, "project_details_views"):
            return

        tab_count = self.project_details_views.count()
        in_projects = self.current_category == "projects"
        for idx in range(1, tab_count):
            self.project_details_views.setTabEnabled(idx, in_projects)
        if not in_projects and self.project_details_views.currentIndex() != 0:
            self.project_details_views.setCurrentIndex(0)

        labels = getattr(self, "_project_view_status_labels", {})
        if not labels:
            return

        if not in_projects:
            for lbl in labels.values():
                lbl.setText("These tabs are available when viewing Projects.")
            for key in ("financials", "purchase_orders", "work_orders"):
                self._clear_project_view_table(key)
            self._refresh_project_change_order_markup_ui()
            return

        parent_path = self._selected_parent_for_project_views()
        if not parent_path:
            for lbl in labels.values():
                lbl.setText("Select a project to load this view.")
            for key in ("financials", "purchase_orders", "work_orders"):
                self._clear_project_view_table(key)
            self._refresh_project_change_order_markup_ui()
            return

        active_workbook = self._get_active_workbook_path(parent_path)
        if not active_workbook:
            for lbl in labels.values():
                lbl.setText("No active workbook is set. Choose one from the Main tab Workbooks section.")
            for key in ("financials", "purchase_orders", "work_orders"):
                self._clear_project_view_table(key)
            self._refresh_project_change_order_markup_ui()
            return

        active_name = active_workbook.name
        for view_key, lbl in labels.items():
            if view_key == "financials":
                info = self._read_parent_info_cached(parent_path)
                locked_name = str(info.get("locked_financials_csv", "")).strip() or "Locked_Financials.csv"
                locked_path = parent_path / locked_name
                if locked_path.exists() and locked_path.is_file():
                    lbl.setText(f"Locked at promotion: {locked_name}. Change orders are tracked below.")
                else:
                    candidates = self._project_view_file_candidates(view_key)
                    found = next((name for name in candidates if (active_workbook / name).exists()), None)
                    if found:
                        lbl.setText(f"Active workbook: {active_name}. Found {found}.")
                    else:
                        lbl.setText(f"Active workbook: {active_name}. No matching file found ({', '.join(candidates)}).")
                continue

            if view_key == "scheduling":
                has_schedule = any((active_workbook / name).exists() for name in self._project_view_file_candidates(view_key))
                if has_schedule:
                    lbl.setText(f"Active workbook: {active_name}. Schedule file is available.")
                else:
                    lbl.setText(f"Active workbook: {active_name}. Schedule.csv was not found.")
                continue

            candidates = self._project_view_file_candidates(view_key)
            found = next((name for name in candidates if (active_workbook / name).exists()), None)
            if found:
                lbl.setText(f"Active workbook: {active_name}. Found {found}.")
            else:
                lbl.setText(f"Active workbook: {active_name}. No matching file found ({', '.join(candidates)}).")

        self._refresh_project_change_order_markup_ui()

        current_idx = self.project_details_views.currentIndex()
        if 0 <= current_idx < len(getattr(self, "_project_detail_tab_keys", [])):
            key = self._project_detail_tab_keys[current_idx]
            if key in {"financials", "purchase_orders", "work_orders"}:
                self._load_project_detail_table(key)

    def _clear_details_panel(self):
        self._cancel_deferred_details_load()
        for lbl in [self.lbl_name, self.lbl_modified, self.lbl_type,
                    self.lbl_created, self.lbl_promoted, self.lbl_gc,
                    self.lbl_address, self.lbl_project_info, self.lbl_active_bid_total]:
            lbl.setText("-")
        self.lbl_status.setCurrentIndex(-1)
        self.lbl_due.clear()
        self.lbl_estimator.clearEditText()
        self.lbl_project_manager.clearEditText()
        self.lbl_proposal_type.setCurrentIndex(-1)
        self.gc_combo.setCurrentIndex(-1)
        for _gc_extra in getattr(self, "gc_extra_combos", []):
            _gc_extra.setCurrentIndex(-1)
        self.poc_combo.setCurrentIndex(-1)
        for _poc_extra in getattr(self, "poc_combos", [])[1:]:
            _poc_extra.setCurrentIndex(-1)
        for _email_edit in getattr(self, "poc_email_edits", []):
            _email_edit.clear()
        for _phone_edit in getattr(self, "poc_phone_edits", []):
            _phone_edit.clear()
        for _invite_edit in getattr(self, "invite_doc_edits", []):
            _invite_edit.clear()
        self.edit_address.clear()
        self.edit_project_info.clear()
        self.subfolder_list.clear()
        self.other_folders_tree.clear()
        if hasattr(self, "project_tasks_list"):
            self.project_tasks_list.clear()
        if hasattr(self, "project_notes_list"):
            self.project_notes_list.clear()
        if hasattr(self, "gc_tab_widget"):
            self._sync_gc_tabs()
        self._current_editing_path = None
        self._refresh_project_detail_view_tabs()
        self._set_kpi_open_tasks_count(None)
        self._update_kpi_strip()
        self._has_unsaved_changes = False

    def _cancel_deferred_details_load(self):
        self._details_deferred_token += 1

    def _start_deferred_details_load(self, path: Path):
        token = self._details_deferred_token
        QTimer.singleShot(0, lambda detail_path=path, t=token: self._load_deferred_details(detail_path, t))

    def _load_deferred_details(self, path: Path, token: int):
        if token != self._details_deferred_token:
            return
        if self._current_editing_path != path:
            return
        self._update_other_folders_buttons(path)
        self._update_subfolder_list(path)

    def update_details(self):
        self._cancel_deferred_details_load()
        item = self.selected_item()
        if not item:
            self._clear_details_panel()
            return

        p = self.selected_path()
        if not p or not p.exists():
            return

        # Reset browsing path when selecting a new bid/project
        self.current_browsing_path = None

        self.lbl_name.setText(item.text())

        # Size scan is expensive on large jobs; keep optional for performance.
        if self._enable_detail_size_scan:
            QTimer.singleShot(50, lambda path=p: self._compute_size(path))

        mtime = datetime.fromtimestamp(p.stat().st_mtime).strftime("%Y-%m-%d %H:%M")
        self.lbl_modified.setText(mtime)

        info = self._read_parent_info_cached(p)
        self.lbl_type.setText(info.get("type", "bid" if self.current_category == "bids" else "project").capitalize())
        self.lbl_status.setCurrentText(self._normalize_status_for_current_category(str(info.get("status", ""))))
        due_str = info.get("due_date", "")
        if due_str:
            try:
                due_date = QDate.fromString(due_str, "yyyy-MM-dd")
                if due_date.isValid():
                    self.lbl_due.setDate(due_date)
                else:
                    self.lbl_due.clear()
            except Exception:
                self.lbl_due.clear()
        else:
            self.lbl_due.clear()
        
        # Populate and set estimator dropdown
        self.lbl_estimator.clear()
        self.lbl_estimator.addItems(self.estimators_list)
        estimator_val = info.get("estimator", "")
        if estimator_val and self.lbl_estimator.findText(estimator_val) < 0:
            self.lbl_estimator.addItem(estimator_val)
        self.lbl_estimator.setCurrentText(estimator_val)
        
        # Populate and set project manager dropdown
        self.lbl_project_manager.clear()
        self.lbl_project_manager.addItems(self.project_managers_list)
        pm_val = info.get("project_manager", "")
        if pm_val and self.lbl_project_manager.findText(pm_val) < 0:
            self.lbl_project_manager.addItem(pm_val)
        self.lbl_project_manager.setCurrentText(pm_val)
        
        self.lbl_created.setText(info.get("created_at", "-"))
        self.lbl_promoted.setText(info.get("promoted_at", "-"))
        
        # Set GC dropdowns and Point Of Contact
        raw_gcs = info.get("gcs", [])
        parsed_gcs: List[str] = []
        if isinstance(raw_gcs, list):
            parsed_gcs = [str(x).strip() for x in raw_gcs if str(x).strip()]
        if not parsed_gcs:
            gc_fallback = str(info.get("gc", "")).strip()
            if gc_fallback:
                parsed_gcs = [gc_fallback]

        gc_val = parsed_gcs[0] if parsed_gcs else ""
        self.gc_combo.setCurrentText(gc_val)
        for idx, _gc_extra in enumerate(getattr(self, "gc_extra_combos", []), start=1):
            _gc_extra.setCurrentText(parsed_gcs[idx] if idx < len(parsed_gcs) else "")
        for idx in range(len(getattr(self, "gc_combos", [self.gc_combo]))):
            self._on_gc_combo_selected(idx)

        # Set Point Of Contact dropdowns
        raw_pocs = info.get("pocs", [])
        parsed_pocs: List[str] = []
        if isinstance(raw_pocs, list):
            parsed_pocs = [str(x).strip() for x in raw_pocs]
        if not parsed_pocs:
            poc_legacy = str(info.get("point_of_contact", "")).strip()
            parsed_pocs = [poc_legacy] if poc_legacy else []
        for idx, _poc in enumerate(getattr(self, "poc_combos", [self.poc_combo])):
            _poc.setCurrentText(parsed_pocs[idx] if idx < len(parsed_pocs) else "")

        raw_invite_docs = info.get("invite_docs", [])
        parsed_invite_docs: List[str] = []
        if isinstance(raw_invite_docs, list):
            parsed_invite_docs = [str(x).strip() for x in raw_invite_docs]
        for idx, _invite in enumerate(getattr(self, "invite_doc_edits", [])):
            _invite.setText(parsed_invite_docs[idx] if idx < len(parsed_invite_docs) else "")
        for idx in range(len(getattr(self, "gc_combos", [self.gc_combo]))):
            self._update_gc_contact_details(idx)
        
        # Set proposal type dropdown
        proposal_val = info.get("proposal_type", "")
        if proposal_val in ["Proposal", "Budget"]:
            self.lbl_proposal_type.setCurrentText(proposal_val)
        else:
            self.lbl_proposal_type.setCurrentIndex(-1)
        
        self.lbl_address.setText(info.get("address", "-"))
        self.edit_address.setPlainText(info.get("address", ""))
        self.lbl_project_info.setText(info.get("project_info", "-"))
        self.edit_project_info.setPlainText(info.get("project_info", ""))

        # Prefer live workbook metrics (cached by signature) so totals persist
        # across Save Details and list refresh without waiting for manual refresh.
        manual_amount = self._get_total_amount_override(p, info=info)
        if manual_amount is not None:
            self.lbl_active_bid_total.setText(self._format_currency(manual_amount) if manual_amount > 0 else "-")
            self._set_bid_total_source_badge(True)
            _, opening_text = self._get_active_metrics_text(p, info=info, force=False)
            self.lbl_opening_count.setText(opening_text if opening_text else "-")
        else:
            total_text, opening_text = self._get_active_metrics_text(p, info=info, force=False)
            self.lbl_active_bid_total.setText(total_text if total_text else "-")
            self._set_bid_total_source_badge(False)
            self.lbl_opening_count.setText(opening_text if opening_text else "-")
        self._update_kpi_strip()
        self._gc_visible_count = None  # auto-detect from loaded data
        self._sync_gc_tabs()

        # Track current editing path immediately so deferred loading can validate selection.
        self._current_editing_path = p
        self._refresh_project_detail_view_tabs()
        self._refresh_project_tasks_panel()
        self._refresh_project_notes_panel()

        # Defer expensive folder/workbook filesystem scans to keep selection responsive.
        self._start_deferred_details_load(p)

        # Reset unsaved changes flag after loading
        self._has_unsaved_changes = False

    def _compute_size(self, path: Path):
        # Size computation kept for internal use but not displayed
        size = dir_size(path)

    def create_folders_from_template(self):
        """Copy subfolders from template to the selected bid/project."""
        p = self.selected_path()
        if not p:
            QMessageBox.information(self, "Create Folders", "Select a Bid/Project first.")
            return
        
        # Template path
        template_path = Path(__file__).parent / "data" / "Template"
        
        if not template_path.exists():
            QMessageBox.warning(
                self, 
                "Create Folders", 
                f"Template folder not found:\n{template_path}"
            )
            return
        
        try:
            # Find all subdirectories in template
            template_folders = []
            for item in template_path.iterdir():
                if item.is_dir() and not item.name.startswith('.'):
                    template_folders.append(item)
            
            if not template_folders:
                QMessageBox.information(
                    self,
                    "Create Folders",
                    "No folders found in template."
                )
                return
            
            # Copy each folder if it doesn't exist
            created_folders = []
            skipped_folders = []
            
            for folder in template_folders:
                dest = p / folder.name
                if dest.exists():
                    skipped_folders.append(folder.name)
                else:
                    shutil.copytree(folder, dest)
                    created_folders.append(folder.name)
            
            # Show results
            msg = ""
            if created_folders:
                msg += f"Created folders:\n" + "\n".join(f"  • {name}" for name in created_folders)
            if skipped_folders:
                if msg:
                    msg += "\n\n"
                msg += f"Skipped (already exist):\n" + "\n".join(f"  • {name}" for name in skipped_folders)
            
            if not msg:
                msg = "No folders were created."
            
            # Refresh the other folders buttons
            self._update_other_folders_buttons(p)
            
            QMessageBox.information(
                self,
                "Create Folders",
                msg
            )
            
        except Exception as e:
            QMessageBox.critical(
                self, 
                "Create Folders", 
                f"Failed to create folders:\n{e}"
            )

    def _update_other_folders_buttons(self, path: Path):
        """Populate the folders tree with all subfolders except 4.Workbooks."""
        self.other_folders_tree.clear()
        
        if not path.exists():
            return
        
        try:
            self.other_folders_tree.setSortingEnabled(False)
            parent_info = self._read_parent_info_cached(path)
            folder_icon = self.style().standardIcon(QStyle.StandardPixmap.SP_DirIcon)
            file_icon = self.style().standardIcon(QStyle.StandardPixmap.SP_FileIcon)
            pin_icon = self.style().standardIcon(QStyle.StandardPixmap.SP_DialogApplyButton)

            for field_key, label in self._other_current_field_defs():
                pinned_item = self._make_other_current_item(path, parent_info, field_key, label, pin_icon)
                self.other_folders_tree.addTopLevelItem(pinned_item)

            subfolders = [
                p for p in sorted(path.iterdir(), key=lambda fp: fp.name.lower())
                if p.is_dir() and not p.name.startswith('.') and p.name != "4.Workbooks"
            ]

            for folder_path in subfolders:
                item = self._make_other_folder_item(folder_path, folder_icon)
                self._ensure_other_folder_lazy_marker(item)
                self.other_folders_tree.addTopLevelItem(item)

            if not subfolders:
                empty = QTreeWidgetItem(["No other folders", "", ""])
                empty.setFlags(empty.flags() & ~Qt.ItemFlag.ItemIsEnabled)
                self.other_folders_tree.addTopLevelItem(empty)
                
        except Exception:
            pass
        finally:
            self.other_folders_tree.setSortingEnabled(False)

    def _other_current_field_defs(self) -> List[Tuple[str, str]]:
        """Return pinned current-file fields shown above the folders list."""
        return [
            ("current_planset", "Current Planset"),
            ("current_schedule", "Current Schedule"),
            ("current_proposal", "Current Proposal"),
        ]

    def _resolve_other_current_path(self, parent_path: Path, info: Dict, field_key: str) -> Optional[Path]:
        """Resolve a stored current-file relative path to an absolute path when valid."""
        raw_rel = str(info.get(field_key) or "").strip()
        if not raw_rel:
            return None
        try:
            target = (parent_path / raw_rel).resolve()
            if target.exists() and (target.is_file() or target.is_dir()):
                return target
        except Exception:
            return None
        return None

    def _make_other_current_item(
        self,
        parent_path: Path,
        info: Dict,
        field_key: str,
        label: str,
        pin_icon: QIcon,
    ) -> QTreeWidgetItem:
        """Build one pinned Current row above the folder tree."""
        target = self._resolve_other_current_path(parent_path, info, field_key)
        target_name = target.name if target else "(not set)"
        modified_text = "-"
        item_kind = "pinned"

        if target:
            try:
                modified_text = datetime.fromtimestamp(target.stat().st_mtime).strftime("%Y-%m-%d %H:%M")
            except Exception:
                modified_text = "-"
            item_kind = "folder" if target.is_dir() else "file"

        type_text = f"Pinned {label.replace('Current ', '')}"
        item = QTreeWidgetItem([f"{label}: {target_name}", type_text, modified_text])
        item.setIcon(0, pin_icon)
        item.setChildIndicatorPolicy(QTreeWidgetItem.ChildIndicatorPolicy.DontShowIndicator)
        if target:
            item.setData(0, Qt.ItemDataRole.UserRole, str(target))
            item.setToolTip(0, str(target))
        else:
            item.setToolTip(0, f"Right-click a file and choose Set as {label}")
        item.setData(0, Qt.ItemDataRole.UserRole + 1, item_kind)
        item.setData(0, Qt.ItemDataRole.UserRole + 2, field_key)
        return item

    def _set_other_current_reference(self, parent_path: Path, item_path: Path, field_key: str, label: str) -> bool:
        """Persist one current-file assignment for the selected bid/project."""
        try:
            rel_path = str(item_path.resolve().relative_to(parent_path.resolve()))
        except Exception:
            QMessageBox.warning(self, "Folders", f"Could not set {label}; the selected item is outside this bid.")
            return False

        try:
            info = self._read_parent_info_cached(parent_path)
            info[field_key] = rel_path
            write_info(parent_path, info)
            self._update_other_folders_buttons(parent_path)
            self.statusBar().showMessage(f"Set {label}: {item_path.name}", 4000)
            return True
        except Exception as e:
            QMessageBox.warning(self, "Folders", f"Could not set {label}:\n{e}")
            return False

    def _clear_other_current_reference(self, parent_path: Path, field_key: str, label: str) -> bool:
        """Clear one current-file assignment from info.json."""
        try:
            info = self._read_parent_info_cached(parent_path)
            if field_key in info:
                del info[field_key]
                write_info(parent_path, info)
            self._update_other_folders_buttons(parent_path)
            self.statusBar().showMessage(f"Cleared {label}", 4000)
            return True
        except Exception as e:
            QMessageBox.warning(self, "Folders", f"Could not clear {label}:\n{e}")
            return False

    def _make_other_folder_item(self, folder_path: Path, folder_icon: QIcon) -> QTreeWidgetItem:
        """Build one explorer-like tree item row for a folder path."""
        modified_text = "-"
        try:
            modified_text = datetime.fromtimestamp(folder_path.stat().st_mtime).strftime("%Y-%m-%d %H:%M")
        except Exception:
            modified_text = "-"

        item = QTreeWidgetItem([folder_path.name, "File folder", modified_text])
        item.setIcon(0, folder_icon)
        item.setChildIndicatorPolicy(QTreeWidgetItem.ChildIndicatorPolicy.ShowIndicator)
        item.setData(0, Qt.ItemDataRole.UserRole, str(folder_path))
        item.setData(0, Qt.ItemDataRole.UserRole + 1, "folder")
        item.setToolTip(0, str(folder_path))
        return item

    def _thumbnail_icon_for_file(self, file_path: Path, fallback_icon: QIcon) -> QIcon:
        """Return a cached thumbnail icon for image files, or the fallback icon."""
        supported_exts = {".png", ".jpg", ".jpeg", ".bmp", ".gif", ".webp", ".tif", ".tiff", ".pdf"}
        if file_path.suffix.lower() not in supported_exts:
            return fallback_icon

        try:
            stat_info = file_path.stat()
            cache_key = f"icon::{file_path.resolve()}::{stat_info.st_mtime_ns}::{stat_info.st_size}"
        except Exception:
            return fallback_icon

        cache = getattr(self, "_other_folder_thumb_cache", None)
        if not isinstance(cache, dict):
            cache = {}
            self._other_folder_thumb_cache = cache

        cached_icon = cache.get(cache_key)
        if isinstance(cached_icon, QIcon):
            return cached_icon

        pix = self._preview_pixmap_for_file(file_path, 30)
        if pix is None or pix.isNull():
            return fallback_icon

        icon = QIcon(pix)
        cache[cache_key] = icon

        # Keep cache from growing unbounded during long sessions.
        if len(cache) > 800:
            cache.clear()
        return icon

    def _preview_pixmap_for_file(self, file_path: Path, size: int) -> Optional[QPixmap]:
        """Build a preview pixmap for supported file types (images and PDFs)."""
        ext = file_path.suffix.lower()
        image_exts = {".png", ".jpg", ".jpeg", ".bmp", ".gif", ".webp", ".tif", ".tiff"}

        if ext in image_exts:
            pix = QPixmap(str(file_path))
            if pix.isNull():
                return None
            return pix.scaled(size, size, Qt.AspectRatioMode.KeepAspectRatio, Qt.TransformationMode.SmoothTransformation)

        if ext == ".pdf":
            return self._preview_pixmap_for_pdf(file_path, size)

        return None

    def _preview_pixmap_for_pdf(self, file_path: Path, size: int) -> Optional[QPixmap]:
        """Render the first page of a PDF for thumbnail/preview usage."""
        try:
            stat_info = file_path.stat()
            cache_key = f"pdf::{file_path.resolve()}::{size}::{stat_info.st_mtime_ns}::{stat_info.st_size}"
        except Exception:
            return None

        cache = getattr(self, "_other_folder_thumb_cache", None)
        if not isinstance(cache, dict):
            cache = {}
            self._other_folder_thumb_cache = cache

        cached_pix = cache.get(cache_key)
        if isinstance(cached_pix, QPixmap):
            return cached_pix

        pix: Optional[QPixmap] = None

        if HAS_PDFPLUMBER and pdfplumber is not None:
            try:
                with pdfplumber.open(str(file_path)) as pdf:
                    if pdf.pages:
                        page_image = pdf.pages[0].to_image(resolution=72)
                        pil_image = getattr(page_image, "original", None)
                        if pil_image is not None:
                            buf = io.BytesIO()
                            pil_image.convert("RGB").save(buf, format="PNG")
                            pix_candidate = QPixmap()
                            if pix_candidate.loadFromData(buf.getvalue()):
                                pix = pix_candidate
            except Exception:
                pix = None

        if pix is None and HAS_OCR and convert_from_path is not None:
            try:
                images = convert_from_path(
                    str(file_path),
                    first_page=1,
                    last_page=1,
                    poppler_path=get_poppler_path(),  # type: ignore[arg-type]
                )
                if images:
                    buf = io.BytesIO()
                    images[0].convert("RGB").save(buf, format="PNG")
                    pix_candidate = QPixmap()
                    if pix_candidate.loadFromData(buf.getvalue()):
                        pix = pix_candidate
            except Exception:
                pix = None

        if pix is None or pix.isNull():
            return None

        scaled = pix.scaled(size, size, Qt.AspectRatioMode.KeepAspectRatio, Qt.TransformationMode.SmoothTransformation)
        cache[cache_key] = scaled
        return scaled

    def _preview_tooltip_for_file(self, file_path: Path) -> str:
        """Build HTML tooltip preview for supported files; fallback to full path text."""
        pix = self._preview_pixmap_for_file(file_path, 180)
        if pix is None or pix.isNull():
            return str(file_path)

        preview_dir = Path(tempfile.gettempdir()) / "goro_folder_previews"
        try:
            preview_dir.mkdir(parents=True, exist_ok=True)
            stat_info = file_path.stat()
            preview_name = f"{abs(hash((str(file_path.resolve()), stat_info.st_mtime_ns, stat_info.st_size)))}.png"
            preview_path = preview_dir / preview_name
            if not preview_path.exists():
                pix.save(str(preview_path), "PNG")
            return (
                f"<div><b>{file_path.name}</b><br>"
                f"<img src='{preview_path.as_uri()}' width='{pix.width()}' height='{pix.height()}'><br>"
                f"<span>{file_path}</span></div>"
            )
        except Exception:
            return str(file_path)

    def _make_other_file_item(self, file_path: Path, file_icon: QIcon) -> QTreeWidgetItem:
        """Build one explorer-like tree item row for a file path."""
        modified_text = "-"
        try:
            modified_text = datetime.fromtimestamp(file_path.stat().st_mtime).strftime("%Y-%m-%d %H:%M")
        except Exception:
            modified_text = "-"

        item = QTreeWidgetItem([file_path.name, "File", modified_text])
        item.setIcon(0, file_icon)
        item.setChildIndicatorPolicy(QTreeWidgetItem.ChildIndicatorPolicy.DontShowIndicator)
        item.setData(0, Qt.ItemDataRole.UserRole, str(file_path))
        item.setData(0, Qt.ItemDataRole.UserRole + 1, "file")
        item.setData(0, Qt.ItemDataRole.UserRole + 4, False)
        item.setToolTip(0, str(file_path))
        item.setToolTip(1, str(file_path))
        item.setToolTip(2, str(file_path))
        return item

    def _on_other_folder_item_hovered(self, item: QTreeWidgetItem, _column: int):
        """Lazily generate larger hover previews for files in the folder tree."""
        if item is None:
            return
        item_kind = item.data(0, Qt.ItemDataRole.UserRole + 1)
        if item_kind != "file":
            return

        cached_tooltip = item.data(0, Qt.ItemDataRole.UserRole + 3)
        if isinstance(cached_tooltip, str) and cached_tooltip:
            return

        raw = item.data(0, Qt.ItemDataRole.UserRole)
        if not raw:
            return

        file_path = Path(str(raw))
        tooltip = self._preview_tooltip_for_file(file_path)
        for col in range(3):
            item.setToolTip(col, tooltip)
        item.setData(0, Qt.ItemDataRole.UserRole + 3, tooltip)

        thumb_done = bool(item.data(0, Qt.ItemDataRole.UserRole + 4))
        if not thumb_done:
            fallback_icon = self.style().standardIcon(QStyle.StandardPixmap.SP_FileIcon)
            item.setIcon(0, self._thumbnail_icon_for_file(file_path, fallback_icon))
            item.setData(0, Qt.ItemDataRole.UserRole + 4, True)

    def _has_other_folder_lazy_marker(self, folder_item: QTreeWidgetItem) -> bool:
        """Return True when a folder node still has the lazy placeholder child."""
        if folder_item.childCount() != 1:
            return False
        child = folder_item.child(0)
        return bool(child and child.data(0, Qt.ItemDataRole.UserRole + 6))

    def _ensure_other_folder_lazy_marker(self, folder_item: QTreeWidgetItem):
        """Add one placeholder child so folder contents load only when expanded."""
        if self._has_other_folder_lazy_marker(folder_item):
            return
        placeholder = QTreeWidgetItem(["Loading...", "", ""])
        placeholder.setData(0, Qt.ItemDataRole.UserRole + 6, True)
        placeholder.setFlags(placeholder.flags() & ~Qt.ItemFlag.ItemIsEnabled)
        folder_item.addChild(placeholder)

    def _populate_other_folder_children(
        self,
        parent_item: QTreeWidgetItem,
        parent_path: Path,
        folder_icon: QIcon,
        file_icon: QIcon,
    ):
        """Populate one level of children for a folder item (lazy load)."""
        if self._has_other_folder_lazy_marker(parent_item):
            parent_item.removeChild(parent_item.child(0))

        try:
            child_entries = [
                p for p in sorted(parent_path.iterdir(), key=lambda fp: (not fp.is_dir(), fp.name.lower()))
                if not p.name.startswith('.')
            ]
        except Exception:
            return

        for child_path in child_entries:
            if child_path.is_dir():
                child_item = self._make_other_folder_item(child_path, folder_icon)
                self._ensure_other_folder_lazy_marker(child_item)
                parent_item.addChild(child_item)
            elif child_path.is_file():
                child_item = self._make_other_file_item(child_path, file_icon)
                parent_item.addChild(child_item)

    def _on_other_folder_expanded(self, item: QTreeWidgetItem):
        """Lazy-load folder contents when a tree node is expanded."""
        if item is None:
            return
        item_kind = item.data(0, Qt.ItemDataRole.UserRole + 1)
        if item_kind != "folder":
            return
        if not self._has_other_folder_lazy_marker(item):
            return

        raw = item.data(0, Qt.ItemDataRole.UserRole)
        if not raw:
            return
        folder_path = Path(str(raw))
        if not folder_path.exists() or not folder_path.is_dir():
            return

        folder_icon = self.style().standardIcon(QStyle.StandardPixmap.SP_DirIcon)
        file_icon = self.style().standardIcon(QStyle.StandardPixmap.SP_FileIcon)
        self._populate_other_folder_children(item, folder_path, folder_icon, file_icon)

    def _resolve_other_folder_drop_target(self, item: Optional[QTreeWidgetItem]) -> Optional[Path]:
        """Resolve the folder tree drop target path, falling back to selected bid path."""
        if item is not None:
            raw = item.data(0, Qt.ItemDataRole.UserRole)
            item_kind = item.data(0, Qt.ItemDataRole.UserRole + 1)
            if raw:
                target = Path(str(raw))
                if target.exists() and target.is_dir():
                    return target
                if item_kind == "file" and target.exists() and target.is_file():
                    parent = target.parent
                    if parent.exists() and parent.is_dir():
                        return parent

        selected = self.selected_path()
        if selected and selected.exists() and selected.is_dir():
            return selected
        return None

    def _is_subpath(self, child: Path, parent: Path) -> bool:
        """Return True when child is located inside parent."""
        try:
            child.resolve().relative_to(parent.resolve())
            return True
        except Exception:
            return False

    def _next_drop_destination(self, destination_dir: Path, source_path: Path) -> Path:
        """Build a collision-free destination path for dropped files/folders."""
        candidate = destination_dir / source_path.name
        if not candidate.exists():
            return candidate

        if source_path.is_dir():
            return destination_dir / available_copy_name(destination_dir, source_path.name)

        stem = source_path.stem
        suffix = source_path.suffix
        first = destination_dir / f"{stem} - Copy{suffix}"
        if not first.exists():
            return first

        n = 2
        while True:
            candidate = destination_dir / f"{stem} - Copy ({n}){suffix}"
            if not candidate.exists():
                return candidate
            n += 1

    def _handle_other_folder_drop(self, destination: Path, source_paths: List[Path]) -> bool:
        """Copy dropped files/folders into a folder tree target."""
        copied = 0
        skipped: List[str] = []
        errors: List[str] = []

        for src in source_paths:
            try:
                if src.resolve() == destination.resolve() or self._is_subpath(destination, src):
                    skipped.append(src.name)
                    continue

                target = self._next_drop_destination(destination, src)
                if src.is_dir():
                    shutil.copytree(src, target)
                elif src.is_file():
                    shutil.copy2(src, target)
                else:
                    skipped.append(src.name)
                    continue
                copied += 1
            except Exception as e:
                errors.append(f"{src.name}: {e}")

        current = self.selected_path()
        if current:
            self._update_other_folders_buttons(current)

        if copied:
            self.statusBar().showMessage(f"Copied {copied} item(s) to {destination.name}", 4000)

        if errors:
            preview = "\n".join(errors[:5])
            QMessageBox.warning(self, "Folder Drop", f"Some items could not be copied:\n{preview}")
        elif skipped and not copied:
            QMessageBox.information(self, "Folder Drop", "No items were copied.")

        return copied > 0

    def _move_other_folder_drop(self, source_path: Path, destination: Path) -> bool:
        """Move a folder to a new destination when dragged within the folders tree."""
        try:
            source_resolved = source_path.resolve()
            destination_resolved = destination.resolve()
        except Exception:
            return False

        if not source_path.exists() or not source_path.is_dir() or not destination.exists() or not destination.is_dir():
            return False

        if source_resolved == destination_resolved:
            return False

        if self._is_subpath(destination_resolved, source_resolved):
            QMessageBox.information(self, "Move Folder", "Cannot move a folder into itself.")
            return False

        if source_resolved.parent == destination_resolved:
            # No effective move when dropped back in the same parent.
            return False

        try:
            target_path = destination / source_path.name
            if target_path.exists():
                target_path = destination / available_copy_name(destination, source_path.name)
            shutil.move(str(source_path), str(target_path))

            current = self.selected_path()
            if current:
                self._update_other_folders_buttons(current)
            self.statusBar().showMessage(f"Moved folder to {destination.name}", 4000)
            return True
        except Exception as e:
            QMessageBox.warning(self, "Move Folder", f"Could not move folder:\n{e}")
            return False

    def _open_other_folder_item(self, item: QTreeWidgetItem, _column: int):
        """Open a folder or file from the expandable folders tree."""
        raw = item.data(0, Qt.ItemDataRole.UserRole)
        if not raw:
            return
        item_path = Path(str(raw))
        if item_path.exists():
            open_in_file_manager(item_path)

    def _other_folders_context_menu(self, pos):
        parent_path = self.selected_path()
        if not parent_path or not parent_path.exists() or not parent_path.is_dir():
            return

        item = self.other_folders_tree.itemAt(pos)
        if not item:
            return
        raw = item.data(0, Qt.ItemDataRole.UserRole)
        pin_field_key = str(item.data(0, Qt.ItemDataRole.UserRole + 2) or "").strip()

        item_path = Path(str(raw)) if raw else None
        item_exists = bool(item_path and item_path.exists())

        menu = QMenu(self)
        act_open = menu.addAction("Open") if item_exists else None

        set_actions: List[Tuple[str, str, QAction]] = []
        if item_exists and item_path is not None:
            if act_open is not None:
                menu.addSeparator()
            for field_key, label in self._other_current_field_defs():
                act = menu.addAction(f"Set as {label}")
                if act is None:
                    continue
                set_actions.append((field_key, label, cast(QAction, act)))

        act_clear = None
        if pin_field_key:
            field_labels = dict(self._other_current_field_defs())
            label = field_labels.get(pin_field_key, pin_field_key)
            menu.addSeparator()
            act_clear = menu.addAction(f"Clear {label}")

        if menu.isEmpty():
            return

        chosen = menu.exec(self.other_folders_tree.mapToGlobal(pos))
        if chosen is None:
            return

        if act_open is not None and chosen is act_open and item_path is not None:
            open_in_file_manager(item_path)
            return

        for field_key, label, action in set_actions:
            if chosen is action and item_path is not None:
                self._set_other_current_reference(parent_path, item_path, field_key, label)
                return

        if act_clear is not None and chosen is act_clear and pin_field_key:
            field_labels = dict(self._other_current_field_defs())
            label = field_labels.get(pin_field_key, pin_field_key)
            self._clear_other_current_reference(parent_path, pin_field_key, label)

    def _update_subfolder_list(self, path: Path):
        """Populate the subfolder list with workbooks from 4.Workbooks folder."""
        self.subfolder_list.clear()
        
        if not path.exists():
            return
        
        try:
            # Read parent info.json to know which workbook is active
            parent_info = self._read_parent_info_cached(path)
            active_rel = parent_info.get("active_workbook")
            
            # Look for 4.Workbooks folder
            workbooks_folder = path / "4.Workbooks"
            
            if workbooks_folder.exists() and workbooks_folder.is_dir():
                # Collect all workbooks
                workbooks = []
                for p in sorted(workbooks_folder.iterdir()):
                    if p.is_dir() and not p.name.startswith('.'):
                        workbooks.append(p)
                
                # Sort: active workbook first, then others alphabetically
                def sort_key(p):
                    try:
                        rel = str(p.relative_to(path))
                    except Exception:
                        rel = None
                    is_active = rel and active_rel and rel == active_rel
                    # Return tuple: (not is_active, name) - False sorts before True, so active comes first
                    return (not is_active, p.name)
                
                workbooks.sort(key=sort_key)
                
                # Add workbooks in sorted order
                for p in workbooks:
                    item = QListWidgetItem()
                    item.setData(Qt.ItemDataRole.UserRole, str(p))
                    item.setData(Qt.ItemDataRole.UserRole + 1, "workbook")

                    # Determine whether this workbook is active
                    try:
                        rel = str(p.relative_to(path))
                    except Exception:
                        rel = None

                    is_active = bool(rel and active_rel and rel == active_rel)

                    # Per-workbook metrics for card display
                    created_text = "-"
                    try:
                        created_text = datetime.fromtimestamp(p.stat().st_ctime).strftime("%Y-%m-%d")
                    except Exception:
                        created_text = "-"

                    try:
                        total_val = self._compute_financials_bid_total(p)
                        total_text = self._format_currency(total_val)
                    except Exception:
                        total_text = "-"

                    try:
                        opening_count = self._get_opening_count_from_schedule(p)
                    except Exception:
                        opening_count = 0

                    try:
                        milestone_count = len(list_milestones(p))
                    except Exception:
                        milestone_count = 0

                    card = self._make_workbook_card_widget(
                        workbook_name=p.name,
                        total_text=total_text,
                        opening_count=opening_count,
                        created_text=created_text,
                        milestone_count=milestone_count,
                        is_active=is_active,
                        workbook_path=p,
                    )
                    hint = card.sizeHint()
                    if hint.height() < 122:
                        hint.setHeight(122)
                    item.setSizeHint(hint)
                    
                    self.subfolder_list.addItem(item)
                    self.subfolder_list.setItemWidget(item, card)
        except Exception:
            pass

    def _open_subfolder(self, item: QListWidgetItem):
        """Open schedule popup for the selected workbook."""
        item_path = Path(item.data(Qt.ItemDataRole.UserRole))
        item_type = item.data(Qt.ItemDataRole.UserRole + 1)
        
        if item_type == "workbook":
            # Open schedule popup for this workbook
            self.view_schedule(workbook_path=item_path)

    def _subfolder_context_menu(self, pos):
        item = self.subfolder_list.itemAt(pos)
        if not item:
            return
        item_type = item.data(Qt.ItemDataRole.UserRole + 1)
        if item_type != "workbook":
            return

        item_path = Path(item.data(Qt.ItemDataRole.UserRole))
        p = self.selected_path()
        if not p:
            return
        
        # Check if this is the active workbook
        info = self._read_parent_info_cached(p)
        rel = None
        try:
            rel = str(item_path.relative_to(p))
        except Exception:
            rel = None
        
        active = info.get("active_workbook") == rel if rel else False

        menu = QMenu(self)
        act_set = act_clear = None
        if active:
            act_clear = menu.addAction("Clear Active Workbook")
        else:
            act_set = menu.addAction("Set as Active Workbook")
        menu.addSeparator()
        act_copy = menu.addAction("Copy Workbook")
        act_cfr = menu.addAction("Copy for Record (Read-Only)")
        act_delete = menu.addAction("Delete Workbook")
        menu.addSeparator()
        act_create_ms = menu.addAction("Create Milestone")
        act_manage_ms = menu.addAction("Manage Milestones")
        menu.addSeparator()
        act_open = menu.addAction("Open Folder")

        chosen = menu.exec(self.subfolder_list.mapToGlobal(pos))
        if not chosen:
            return

        try:
            if chosen is act_open:
                open_in_file_manager(item_path)
            elif act_set is not None and chosen is act_set:
                # Store relative path in info.json
                if rel:
                    info["active_workbook"] = rel
                    write_info(p, info)
                    self._invalidate_active_metrics_cache(p)
                    self._update_subfolder_list(p)
                    if hasattr(self, "lbl_active_bid_total"):
                        self.lbl_active_bid_total.setText("-")
                    if hasattr(self, "lbl_opening_count"):
                        self.lbl_opening_count.setText("-")
            elif act_clear is not None and chosen is act_clear:
                if "active_workbook" in info:
                    del info["active_workbook"]
                    write_info(p, info)
                    self._invalidate_active_metrics_cache(p)
                    self._update_subfolder_list(p)
                    if hasattr(self, "lbl_active_bid_total"):
                        self.lbl_active_bid_total.setText("-")
                    if hasattr(self, "lbl_opening_count"):
                        self.lbl_opening_count.setText("-")
            elif chosen is act_copy:
                self._copy_workbook(item_path, p)
            elif chosen is act_cfr:
                self._copy_for_record(item_path, p)
            elif chosen is act_delete:
                self._delete_workbook(item_path, p)
            elif chosen is act_create_ms:
                self._create_milestone_for_workbook(item_path)
            elif chosen is act_manage_ms:
                self._manage_milestones_for_workbook(item_path)
        except Exception:
            pass
        self._refresh_project_detail_view_tabs()

    def _collect_workbook_import_bid_candidates(self, current_path: Path) -> List[Tuple[str, Path]]:
        candidates: List[Tuple[str, Path]] = []
        seen_paths: set[str] = set()

        try:
            current_resolved = str(current_path.resolve())
        except Exception:
            current_resolved = str(current_path)

        def add_candidate(path: Path, group_label: str, display_name: Optional[str] = None) -> None:
            if not path.exists() or not path.is_dir():
                return

            try:
                resolved = str(path.resolve())
            except Exception:
                resolved = str(path)

            if resolved == current_resolved or resolved in seen_paths:
                return

            seen_paths.add(resolved)
            name = (display_name or path.name).strip() or path.name
            candidates.append((f"{name} [{group_label}]", path))

        for p in list_bids(self.paths.bids):
            add_candidate(p, "Bids")

        if self.paths.submitted.exists():
            for p in sorted(self.paths.submitted.iterdir()):
                if p.is_dir() and not p.name.startswith('.'):
                    add_candidate(p, "Submitted")

        if self.paths.awarded.exists():
            for p in sorted(self.paths.awarded.iterdir()):
                if not (p.is_dir() or p.is_symlink()) or p.name.startswith('.'):
                    continue
                try:
                    target = p.resolve() if p.is_symlink() else p
                except Exception:
                    continue
                add_candidate(target, "Awarded", display_name=p.name)

        return sorted(candidates, key=lambda entry: entry[0].lower())

    def import_workbook_from_bid(self):
        """Import a workbook from another bid/project into the selected bid/project."""
        current_path = self.selected_path()
        if not current_path:
            QMessageBox.information(self, "Import Workbook", "Select a Bid/Project first.")
            return

        candidates = self._collect_workbook_import_bid_candidates(current_path)
        if not candidates:
            QMessageBox.information(self, "Import Workbook", "No other bids/projects were found.")
            return

        dlg = QDialog(self)
        dlg.setWindowTitle("Import Workbook")
        dlg.setMinimumWidth(min(760, clamped_size(760, 500)[0]))
        dlg.setMinimumHeight(min(500, clamped_size(760, 500)[1]))

        layout = QVBoxLayout(dlg)
        search_label = QLabel("Search bids/projects (partial match):")
        layout.addWidget(search_label)

        search_edit = QLineEdit()
        search_edit.setPlaceholderText("Type to filter bids/projects…")
        layout.addWidget(search_edit)

        lists_row = QHBoxLayout()
        bids_col = QVBoxLayout()
        bids_col.addWidget(QLabel("Matching bids/projects:"))
        bids_list = QListWidget()
        bids_col.addWidget(bids_list)

        workbooks_col = QVBoxLayout()
        workbooks_col.addWidget(QLabel("Workbooks in selected bid/project:"))
        workbooks_list = QListWidget()
        workbooks_col.addWidget(workbooks_list)

        lists_row.addLayout(bids_col, 1)
        lists_row.addLayout(workbooks_col, 1)
        layout.addLayout(lists_row)

        buttons = QDialogButtonBox(
            QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel
        )
        import_btn = buttons.button(QDialogButtonBox.StandardButton.Ok)
        import_btn.setText("Import")
        import_btn.setEnabled(False)
        buttons.accepted.connect(dlg.accept)
        buttons.rejected.connect(dlg.reject)
        layout.addWidget(buttons)

        def set_import_enabled() -> None:
            import_btn.setEnabled(workbooks_list.currentItem() is not None)

        def load_workbooks_for_selected_bid() -> None:
            workbooks_list.clear()
            selected_bid = bids_list.currentItem()
            if not selected_bid:
                set_import_enabled()
                return

            bid_path = Path(str(selected_bid.data(Qt.ItemDataRole.UserRole)))
            workbooks_folder = bid_path / "4.Workbooks"
            if workbooks_folder.exists() and workbooks_folder.is_dir():
                for p in sorted(workbooks_folder.iterdir()):
                    if p.is_dir() and not p.name.startswith('.'):
                        item = QListWidgetItem(p.name)
                        item.setData(Qt.ItemDataRole.UserRole, str(p))
                        workbooks_list.addItem(item)

            if workbooks_list.count() > 0:
                workbooks_list.setCurrentRow(0)
            set_import_enabled()

        def populate_bids() -> None:
            query = search_edit.text().strip().lower()
            bids_list.clear()

            for display_text, bid_path in candidates:
                if query and query not in display_text.lower() and query not in bid_path.name.lower():
                    continue
                item = QListWidgetItem(display_text)
                item.setData(Qt.ItemDataRole.UserRole, str(bid_path))
                bids_list.addItem(item)

            if bids_list.count() > 0:
                bids_list.setCurrentRow(0)
            else:
                workbooks_list.clear()
                set_import_enabled()

        search_edit.textChanged.connect(lambda _text: populate_bids())
        bids_list.currentItemChanged.connect(lambda _cur, _prev: load_workbooks_for_selected_bid())
        workbooks_list.currentItemChanged.connect(lambda _cur, _prev: set_import_enabled())
        workbooks_list.itemDoubleClicked.connect(lambda _item: dlg.accept() if import_btn.isEnabled() else None)

        populate_bids()
        if dlg.exec() != QDialog.DialogCode.Accepted:
            return

        selected_bid_item = bids_list.currentItem()
        selected_workbook_item = workbooks_list.currentItem()
        if not selected_bid_item or not selected_workbook_item:
            QMessageBox.warning(self, "Import Workbook", "Select a bid/project and workbook to import.")
            return

        source_bid_label = selected_bid_item.text()
        source_workbook_path = Path(str(selected_workbook_item.data(Qt.ItemDataRole.UserRole)))
        if not source_workbook_path.exists() or not source_workbook_path.is_dir():
            QMessageBox.warning(self, "Import Workbook", "Selected workbook folder was not found.")
            return

        dest_workbooks_folder = current_path / "4.Workbooks"
        dest_workbooks_folder.mkdir(parents=True, exist_ok=True)

        target_name = source_workbook_path.name
        target_path = dest_workbooks_folder / target_name

        if target_path.exists():
            suggested_name = available_copy_name(dest_workbooks_folder, target_name)
            new_name, ok = QInputDialog.getText(
                self,
                "Import Workbook",
                f"A workbook named '{target_name}' already exists.\nEnter a new name:",
                text=suggested_name,
            )
            if not ok or not new_name.strip():
                return

            target_name = new_name.strip()
            reason = invalid_name_reason(target_name)
            if reason:
                QMessageBox.warning(self, "Invalid Name", reason)
                return

            target_path = dest_workbooks_folder / target_name
            if target_path.exists():
                QMessageBox.warning(
                    self,
                    "Import Workbook",
                    f"A workbook named '{target_name}' already exists."
                )
                return

        try:
            shutil.copytree(source_workbook_path, target_path)
            self._update_subfolder_list(current_path)
            QMessageBox.information(
                self,
                "Import Workbook",
                f"Imported workbook '{target_path.name}' from {source_bid_label}."
            )
        except Exception as e:
            QMessageBox.critical(self, "Import Workbook", f"Failed to import workbook:\n{e}")

    def create_new_workbook(self):
        """Create a new workbook from template for the selected bid/project."""
        p = self.selected_path()
        if not p:
            QMessageBox.information(self, "New Workbook", "Select a Bid/Project first.")
            return
        
        # Template path
        template_path = APP_ROOT / "data" / "WB_Template"
        
        if not template_path.exists():
            QMessageBox.warning(
                self, 
                "New Workbook", 
                f"Template folder not found:\n{template_path}"
            )
            return
        
        try:
            # Get workbook name from user
            name, ok = QInputDialog.getText(
                self, 
                "New Workbook", 
                "Enter name for the new workbook:",
                text="Workbook"
            )
            
            if not ok or not name.strip():
                return
            
            name = name.strip()
            
            # Validate the name
            reason = invalid_name_reason(name)
            if reason:
                QMessageBox.warning(self, "Invalid Name", reason)
                return
            
            # Create 4.Workbooks subfolder if it doesn't exist
            workbooks_folder = p / "4.Workbooks"
            workbooks_folder.mkdir(exist_ok=True)
            
            # Create destination path
            dest_path = workbooks_folder / name
            
            # Check if destination already exists
            if dest_path.exists():
                QMessageBox.warning(
                    self, 
                    "New Workbook", 
                    f"A workbook named '{name}' already exists."
                )
                return
            
            # Copy the template
            shutil.copytree(template_path, dest_path)
            
            # Refresh the subfolder list
            self._update_subfolder_list(p)
            
            QMessageBox.information(
                self,
                "New Workbook",
                f"Workbook '{name}' created successfully."
            )
            
        except Exception as e:
            QMessageBox.critical(
                self, 
                "New Workbook", 
                f"Failed to create workbook:\n{e}"
            )

    def _copy_workbook(self, src_path: Path, parent_path: Path):
        """Copy a workbook folder with a new name."""
        try:
            # Get new name from user
            original_name = src_path.name
            new_name, ok = QInputDialog.getText(
                self, 
                "Copy Workbook", 
                f"Enter name for copy of '{original_name}':",
                text=f"{original_name}_copy"
            )
            
            if not ok or not new_name.strip():
                return
            
            new_name = new_name.strip()
            
            # Validate the name
            reason = invalid_name_reason(new_name)
            if reason:
                QMessageBox.warning(self, "Invalid Name", reason)
                return
            
            # Create destination path in the same folder as the source workbook
            dest_folder = src_path.parent
            dest_path = dest_folder / new_name
            
            # Check if destination already exists
            if dest_path.exists():
                QMessageBox.warning(
                    self, 
                    "Copy Workbook", 
                    f"A folder named '{new_name}' already exists."
                )
                return
            
            # Copy the directory
            shutil.copytree(src_path, dest_path)
            
            # Refresh the subfolder list
            self._update_subfolder_list(parent_path)
            
            QMessageBox.information(
                self, 
                "Copy Workbook", 
                f"Workbook copied successfully to '{new_name}'."
            )
            
        except Exception as e:
            QMessageBox.critical(
                self, 
                "Copy Workbook", 
                f"Failed to copy workbook:\n{e}"
            )

    def _copy_for_record(self, src_path: Path, parent_path: Path):
        """Create a read-only copy for record with CFR and date suffix."""
        try:
            # Get current date in YYYY-MM-DD format
            today = date.today().strftime("%Y-%m-%d")
            
            # Generate name: OriginalName_CFR_Date
            original_name = src_path.name
            cfr_name = f"{original_name}_CFR_{today}"
            
            # Create destination path in the same folder as the source workbook
            dest_folder = src_path.parent
            dest_path = dest_folder / cfr_name
            
            # Check if destination already exists
            if dest_path.exists():
                QMessageBox.warning(
                    self, 
                    "Copy for Record", 
                    f"A CFR copy already exists for today:\n{cfr_name}"
                )
                return
            
            # Copy the directory
            shutil.copytree(src_path, dest_path)
            
            # Make all files read-only
            for root, dirs, files in os.walk(dest_path):
                for file in files:
                    file_path = Path(root) / file
                    try:
                        # Set read-only permission
                        file_path.chmod(0o444)  # r--r--r-- permissions
                    except Exception:
                        pass  # Continue even if some files can't be made read-only
            
            # Refresh the subfolder list
            self._update_subfolder_list(parent_path)
            
            QMessageBox.information(
                self, 
                "Copy for Record", 
                f"Read-only copy created:\n{cfr_name}"
            )
            
        except Exception as e:
            QMessageBox.critical(
                self, 
                "Copy for Record", 
                f"Failed to create copy for record:\n{e}"
            )

    def _delete_workbook(self, workbook_path: Path, parent_path: Path):
        """Delete a workbook folder with confirmation."""
        try:
            workbook_name = workbook_path.name
            
            # Show confirmation dialog
            reply = QMessageBox.question(
                self,
                "Delete Workbook",
                f"Are you sure you want to delete the workbook:\n\n'{workbook_name}'?\n\nThis action cannot be undone.",
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                QMessageBox.StandardButton.No  # Default to No
            )
            
            if reply != QMessageBox.StandardButton.Yes:
                return
            
            # Error handler for read-only and locked files
            def handle_remove_readonly(func, path, exc):
                """Handle read-only files and other permission issues."""
                import stat
                try:
                    # Remove read-only attribute
                    os.chmod(path, stat.S_IWUSR | stat.S_IWRITE | stat.S_IREAD | stat.S_IEXEC)
                    # Try the operation again
                    func(path)
                except Exception:
                    # If still failing, try direct Windows attribute change
                    if get_system() == "Windows":
                        try:
                            import subprocess
                            subprocess.run(['attrib', '-R', path], capture_output=True)
                            func(path)
                        except Exception:
                            pass
            
            # Delete the directory
            deleted = False
            error_msg = None
            
            # Try send2trash first (safest)
            if HAS_SEND2TRASH:
                try:
                    send2trash(workbook_path)
                    deleted = True
                except Exception as e:
                    error_msg = str(e)
            
            # If send2trash failed or not available, try shutil.rmtree
            if not deleted:
                try:
                    shutil.rmtree(workbook_path, onerror=handle_remove_readonly)
                    deleted = True
                except Exception as e:
                    error_msg = str(e)
            
            # If still not deleted, show helpful error message
            if not deleted:
                QMessageBox.critical(
                    self,
                    "Delete Workbook",
                    f"Could not delete workbook '{workbook_name}'.\n\n"
                    f"Possible reasons:\n"
                    f"• Files are open in Excel or another program\n"
                    f"• OneDrive is syncing the folder\n"
                    f"• Files are in use by another process\n\n"
                    f"Try closing all files and programs, then try again.\n\n"
                    f"Error: {error_msg}"
                )
                return
            
            # Refresh the subfolder list
            self._update_subfolder_list(parent_path)
            
            QMessageBox.information(
                self, 
                "Delete Workbook", 
                f"Workbook '{workbook_name}' has been deleted."
            )
            
        except Exception as e:
            QMessageBox.critical(
                self, 
                "Delete Workbook", 
                f"Failed to delete workbook:\n{e}"
            )

    class FrozenColumnsManager(QObject):
        """Maintains a frozen-column overlay for a QTableWidget."""

        def __init__(self, table: QTableWidget):
            super().__init__(table)
            self.table = table
            self._updating = False
            self._col_widths: Dict[int, int] = {}  # cached widths (Qt returns 0 for hidden cols)
            self._last_margin: int = 0               # track last setViewportMargins to avoid cascade

            self.overlay = QTableView(table)
            self.overlay.setObjectName("frozenColumnsOverlay")
            self.overlay.setModel(table.model())
            self.overlay.setSelectionModel(table.selectionModel())
            self.overlay.setFocusPolicy(Qt.FocusPolicy.StrongFocus)
            self.overlay.setFrameShape(QFrame.Shape.NoFrame)
            self.overlay.setHorizontalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAlwaysOff)
            self.overlay.setVerticalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAlwaysOff)
            self.overlay.setSelectionBehavior(table.selectionBehavior())
            self.overlay.setSelectionMode(table.selectionMode())
            self.overlay.setEditTriggers(table.editTriggers())
            self.overlay.setShowGrid(table.showGrid())
            self.overlay.setWordWrap(table.wordWrap())
            self.overlay.setAlternatingRowColors(table.alternatingRowColors())
            self.overlay.setStyleSheet(table.styleSheet())
            # Keep frozen pane fully opaque so underlying scrolling cells never bleed through.
            self.overlay.setAttribute(Qt.WidgetAttribute.WA_OpaquePaintEvent, True)
            self.overlay.viewport().setAutoFillBackground(True)
            self.overlay.viewport().setAttribute(Qt.WidgetAttribute.WA_OpaquePaintEvent, True)
            self.overlay.verticalHeader().hide()

            overlay_header = VerticalHeaderView(Qt.Orientation.Horizontal, self.overlay)
            self.overlay.setHorizontalHeader(overlay_header)
            overlay_header.setSectionsClickable(True)
            overlay_header.setSectionsMovable(False)
            overlay_header.setSectionResizeMode(QHeaderView.ResizeMode.Interactive)
            overlay_header.setResizeContentsPrecision(100)

            table.horizontalHeader().sectionResized.connect(self._sync_column_width_from_main)
            overlay_header.sectionResized.connect(self._sync_column_width_from_overlay)
            table.verticalHeader().sectionResized.connect(self._sync_row_height)
            table.horizontalHeader().sectionMoved.connect(self._on_main_section_moved)
            table.verticalScrollBar().valueChanged.connect(self._sync_overlay_scroll)
            self.overlay.verticalScrollBar().valueChanged.connect(self._sync_main_scroll)
            table.model().rowsInserted.connect(lambda *_args: QTimer.singleShot(0, self.refresh))
            table.model().rowsRemoved.connect(lambda *_args: QTimer.singleShot(0, self.refresh))
            table.model().columnsInserted.connect(lambda *_args: QTimer.singleShot(0, self.refresh))
            table.model().columnsRemoved.connect(lambda *_args: QTimer.singleShot(0, self.refresh))
            table.viewport().installEventFilter(self)
            table.horizontalHeader().installEventFilter(self)
            table.installEventFilter(self)

            table._frozen_overlay_view = self.overlay  # type: ignore[attr-defined]
            self.capture_base_state()
            # Seed width cache from initial visible state
            for _col in range(table.columnCount()):
                if not table.isColumnHidden(_col):
                    _w = table.columnWidth(_col)
                    if _w > 0:
                        self._col_widths[_col] = _w
            self.overlay.hide()

        def eventFilter(self, obj, event):
            # Only react to Resize/Show — NOT LayoutRequest, because
            # setViewportMargins itself fires LayoutRequest causing an infinite loop.
            if event.type() in (QEvent.Type.Resize, QEvent.Type.Show):
                QTimer.singleShot(0, self.refresh)
            return super().eventFilter(obj, event)

        def _normalize_pinned_columns(self) -> List[int]:
            pinned = self.table.property("_pinned_columns")
            if not isinstance(pinned, list):
                return []

            normalized: List[int] = []
            seen = set()
            base_hidden = self.base_hidden_map()
            for col in pinned:
                if not isinstance(col, int):
                    continue
                if col < 0 or col >= self.table.columnCount():
                    continue
                if col in seen:
                    continue
                if base_hidden.get(col, False):
                    continue
                seen.add(col)
                normalized.append(col)
            return normalized

        def base_order(self) -> List[int]:
            base = self.table.property("_pinned_base_order")
            if isinstance(base, list):
                return [col for col in base if isinstance(col, int)]
            return []

        def base_hidden_map(self) -> Dict[int, bool]:
            hidden_map = self.table.property("_pinned_base_hidden")
            if isinstance(hidden_map, dict):
                return {int(k): bool(v) for k, v in hidden_map.items()}
            return {}

        def capture_base_state(self) -> None:
            if self._normalize_pinned_columns():
                return
            header = self.table.horizontalHeader()
            order = [header.logicalIndex(i) for i in range(header.count())]
            hidden = {col: self.table.isColumnHidden(col) for col in range(self.table.columnCount())}
            self.table.setProperty("_pinned_base_order", order)
            self.table.setProperty("_pinned_base_hidden", hidden)

        def is_pinned(self, col: int) -> bool:
            return col in self._normalize_pinned_columns()

        def effective_column_hidden(self, col: int) -> bool:
            return self.table.isColumnHidden(col) and not self.is_pinned(col)

        def visible_columns_for_navigation(self) -> List[int]:
            pinned = self._normalize_pinned_columns()
            base_hidden = self.base_hidden_map()
            visible_pinned = [col for col in pinned if not base_hidden.get(col, False)]

            header = self.table.horizontalHeader()
            visual_order = [header.logicalIndex(i) for i in range(header.count())]
            visible_unpinned = [
                col for col in visual_order
                if col not in visible_pinned and not self.table.isColumnHidden(col)
            ]
            return visible_pinned + visible_unpinned

        def view_for_column(self, col: int):
            if self.is_pinned(col) and not self.overlay.isHidden():
                return self.overlay
            return self.table

        def _restore_main_visual_order(self) -> None:
            base_order = self.base_order()
            if not base_order:
                return
            header = self.table.horizontalHeader()
            for target_visual, logical_col in enumerate(base_order):
                current_visual = header.visualIndex(logical_col)
                if current_visual >= 0 and current_visual != target_visual:
                    header.moveSection(current_visual, target_visual)

        def _apply_overlay_visual_order(self, pinned: List[int]) -> None:
            header = self.overlay.horizontalHeader()
            for target_visual, logical_col in enumerate(pinned):
                current_visual = header.visualIndex(logical_col)
                if current_visual >= 0 and current_visual != target_visual:
                    header.moveSection(current_visual, target_visual)

        def _sync_column_width_from_main(self, logical_index: int, _old_size: int, new_size: int) -> None:
            if self._updating:
                return
            if new_size > 0:
                self._col_widths[logical_index] = new_size
            self._updating = True
            try:
                self.overlay.setColumnWidth(logical_index, new_size if new_size > 0 else self._col_widths.get(logical_index, 80))
                self._update_overlay_geometry()
            finally:
                self._updating = False

        def _sync_column_width_from_overlay(self, logical_index: int, _old_size: int, new_size: int) -> None:
            if self._updating:
                return
            if not self.is_pinned(logical_index):
                return
            self._updating = True
            try:
                self.table.setColumnWidth(logical_index, new_size)
                self._update_overlay_geometry()
            finally:
                self._updating = False

        def _sync_row_height(self, logical_index: int, _old_size: int, new_size: int) -> None:
            if self._updating:
                return
            self.overlay.setRowHeight(logical_index, new_size)

        def _sync_overlay_scroll(self, value: int) -> None:
            if self._updating:
                return
            self._updating = True
            try:
                self.overlay.verticalScrollBar().setValue(value)
            finally:
                self._updating = False

        def _sync_main_scroll(self, value: int) -> None:
            if self._updating:
                return
            self._updating = True
            try:
                self.table.verticalScrollBar().setValue(value)
            finally:
                self._updating = False

        def _on_main_section_moved(self, _logical: int, _old_visual: int, _new_visual: int) -> None:
            if self._updating:
                return
            if self._normalize_pinned_columns():
                return
            self.capture_base_state()

        def _copy_table_appearance(self) -> None:
            base_style = self.table.styleSheet()
            self.overlay.setStyleSheet(
                f"{base_style}\n"
                "QTableView#frozenColumnsOverlay {"
                "background-color: palette(base);"
                "border-right: 1px solid rgba(120, 140, 170, 110);"
                "}"
                "QTableView#frozenColumnsOverlay::item {"
                "background-color: palette(base);"
                "}"
            )
            self.overlay.setFont(self.table.font())
            self.overlay.setPalette(self.table.palette())
            self.overlay.setSelectionBehavior(self.table.selectionBehavior())
            self.overlay.setSelectionMode(self.table.selectionMode())
            self.overlay.setEditTriggers(self.table.editTriggers())

        def _set_margin(self, width: int) -> None:
            """Set left viewport margin only when it actually changes to prevent
            setViewportMargins → LayoutRequest → refresh() → setViewportMargins
            infinite cascade."""
            if self._last_margin != width:
                self._last_margin = width
                self.table.setViewportMargins(width, 0, 0, 0)

        def _update_overlay_geometry(self) -> None:
            pinned = self._normalize_pinned_columns()
            if not pinned:
                self.overlay.hide()
                self._set_margin(0)
                return

            left = self.table.frameWidth() + self.table.verticalHeader().width()
            top = self.table.frameWidth()
            header_height = self.table.horizontalHeader().height()
            # Use cached widths — Qt returns 0 for hidden column widths
            overlay_width = sum(self._col_widths.get(col, self.table.columnWidth(col)) for col in pinned)

            if overlay_width <= 0:
                self.overlay.hide()
                self._set_margin(0)
                return

            # Push the main table's viewport right so it doesn't draw under the overlay.
            # Guard against cascade: only call setViewportMargins when value changes.
            self._set_margin(overlay_width + 1)

            overlay_height = header_height + self.table.viewport().height()
            self.overlay.setGeometry(left, top, overlay_width, overlay_height)
            self.overlay.raise_()
            self.overlay.show()

        def refresh(self) -> None:
            if self._updating:
                return

            pinned = self._normalize_pinned_columns()
            self.table.setProperty("_pinned_columns", pinned)

            # Fast path: nothing is frozen — just keep the overlay hidden and margin at 0.
            if not pinned:
                if self.overlay.isVisible():
                    self.overlay.hide()
                self._set_margin(0)
                return

            if not self.base_order():
                self.capture_base_state()

            self._updating = True
            try:
                self._copy_table_appearance()
                self._restore_main_visual_order()

                base_hidden = self.base_hidden_map()
                # Snapshot visible column widths BEFORE hiding (Qt returns 0 for hidden cols)
                for col in range(self.table.columnCount()):
                    if not self.table.isColumnHidden(col):
                        w = self.table.columnWidth(col)
                        if w > 0:
                            self._col_widths[col] = w
                for col in range(self.table.columnCount()):
                    original_hidden = base_hidden.get(col, self.table.isColumnHidden(col))
                    self.table.setColumnHidden(col, original_hidden or col in pinned)
                    self.overlay.setColumnHidden(col, col not in pinned)
                    self.overlay.setColumnWidth(col, self._col_widths.get(col, 80))
                    delegate = self.table.itemDelegateForColumn(col)
                    if delegate is not None:
                        self.overlay.setItemDelegateForColumn(col, delegate)

                for row in range(self.table.rowCount()):
                    self.overlay.setRowHeight(row, self.table.rowHeight(row))
                    self.overlay.setRowHidden(row, self.table.isRowHidden(row))

                self._apply_overlay_visual_order(pinned)
                self._sync_overlay_scroll(self.table.verticalScrollBar().value())
                self._update_overlay_geometry()
            finally:
                self._updating = False

    class TablePasteEventFilter(QObject):
        """Event filter to handle paste and delete operations in QTableWidget."""
        def __init__(self, table, change_callback=None, ensure_row_callback=None, enable_excel_shortcuts=False, undo_callback=None, redo_callback=None, duplicate_row_callback=None, post_edit_callback=None):
            super().__init__(table)
            self.table = table
            self.change_callback = change_callback
            self.ensure_row_callback = ensure_row_callback
            self.enable_excel_shortcuts = enable_excel_shortcuts
            self.undo_callback = undo_callback
            self.redo_callback = redo_callback
            self.duplicate_row_callback = duplicate_row_callback
            self.post_edit_callback = post_edit_callback
        
        def eventFilter(self, obj, event):
            if event.type() == QEvent.Type.KeyPress:
                focus_widget = QApplication.focusWidget()
                if focus_widget is None:
                    return super().eventFilter(obj, event)
                if focus_widget is not self.table and not self.table.isAncestorOf(focus_widget):
                    return super().eventFilter(obj, event)

                mods = event.modifiers()
                ctrl = bool(mods & Qt.KeyboardModifier.ControlModifier)
                shift = bool(mods & Qt.KeyboardModifier.ShiftModifier)
                alt = bool(mods & Qt.KeyboardModifier.AltModifier)

                if event.matches(QKeySequence.StandardKey.Undo) and self.undo_callback:
                    self.undo_callback()
                    return True
                is_ctrl_shift_z = (
                    event.key() == Qt.Key.Key_Z
                    and (event.modifiers() & Qt.KeyboardModifier.ControlModifier)
                    and (event.modifiers() & Qt.KeyboardModifier.ShiftModifier)
                )
                if (event.matches(QKeySequence.StandardKey.Redo) or is_ctrl_shift_z) and self.redo_callback:
                    self.redo_callback()
                    return True
                if self.enable_excel_shortcuts and event.matches(QKeySequence.StandardKey.Copy):
                    self.handle_copy()
                    return True
                if event.matches(QKeySequence.StandardKey.Paste):
                    self.handle_paste()
                    return True
                elif event.matches(QKeySequence.StandardKey.Delete):
                    self.handle_delete()
                    return True
                elif self.enable_excel_shortcuts and event.key() in (Qt.Key.Key_F2,):
                    self._start_edit_current_cell()
                    return True
                elif self.enable_excel_shortcuts and event.key() in (Qt.Key.Key_Tab, Qt.Key.Key_Backtab) and not ctrl and not alt:
                    move_left = shift or event.key() == Qt.Key.Key_Backtab
                    self.handle_tab_navigation(move_left=move_left)
                    return True
                elif self.enable_excel_shortcuts and event.key() in (Qt.Key.Key_Return, Qt.Key.Key_Enter) and not ctrl and not alt:
                    self.handle_enter_navigation(move_up=shift)
                    return True
                elif self.enable_excel_shortcuts and ctrl and not alt and event.key() in (Qt.Key.Key_Up, Qt.Key.Key_Down, Qt.Key.Key_Left, Qt.Key.Key_Right):
                    self.handle_ctrl_arrow_navigation(event.key(), extend_selection=shift)
                    return True
                elif self.enable_excel_shortcuts and event.key() in (Qt.Key.Key_Home, Qt.Key.Key_End) and not alt:
                    self.handle_home_end_navigation(event.key(), ctrl=ctrl, extend_selection=shift)
                    return True
                elif self.enable_excel_shortcuts and ctrl and not alt and event.key() == Qt.Key.Key_Semicolon:
                    self.insert_current_date()
                    return True
                elif self.enable_excel_shortcuts and event.key() == Qt.Key.Key_Space and ctrl and not shift and not alt:
                    self._select_current_column()
                    return True
                elif self.enable_excel_shortcuts and event.key() == Qt.Key.Key_Space and shift and not ctrl and not alt:
                    self._select_current_row()
                    return True
                elif self.enable_excel_shortcuts and event.key() == Qt.Key.Key_D and \
                        (event.modifiers() & Qt.KeyboardModifier.ControlModifier) and \
                        (event.modifiers() & Qt.KeyboardModifier.ShiftModifier):
                    if self.duplicate_row_callback:
                        self.duplicate_row_callback()
                    else:
                        self.handle_fill_down()
                    return True
                elif self.enable_excel_shortcuts and event.key() == Qt.Key.Key_D and \
                        (event.modifiers() & Qt.KeyboardModifier.ControlModifier):
                    self.handle_fill_down()
                    return True
            return super().eventFilter(obj, event)

        def _is_checkbox_col(self, col: int) -> bool:
            header_item = self.table.horizontalHeaderItem(col)
            return bool(header_item and header_item.text().strip() in ("", "", ""))

        def _frozen_manager(self):
            return getattr(self.table, "_frozen_columns_manager", None)

        def _is_effectively_hidden_col(self, col: int) -> bool:
            manager = self._frozen_manager()
            if manager is not None and hasattr(manager, "effective_column_hidden"):
                return bool(manager.effective_column_hidden(col))
            return self.table.isColumnHidden(col)

        def _current_cell_or_default(self) -> tuple[int, int]:
            current = self.table.currentIndex()
            if current.isValid():
                return current.row(), current.column()
            selected = self.table.selectedRanges()
            if selected:
                return selected[0].topRow(), selected[0].leftColumn()
            return 0, 0

        def _visible_rows(self) -> List[int]:
            return [r for r in range(self.table.rowCount()) if not self.table.isRowHidden(r)]

        def _visible_cols(self) -> List[int]:
            manager = self._frozen_manager()
            if manager is not None and hasattr(manager, "visible_columns_for_navigation"):
                return list(manager.visible_columns_for_navigation())
            return [c for c in range(self.table.columnCount()) if not self.table.isColumnHidden(c)]

        def _visible_data_cols(self) -> List[int]:
            cols = self._visible_cols()
            data_cols = [c for c in cols if not self._is_checkbox_col(c)]
            return data_cols if data_cols else cols

        def _cell_text(self, row: int, col: int) -> str:
            if self.table.isRowHidden(row) or self._is_effectively_hidden_col(col):
                return ""
            item = self.table.item(row, col)
            return item.text().strip() if item else ""

        def _move_to_cell(self, row: int, col: int, keep_anchor: bool = False, anchor_row: int = -1, anchor_col: int = -1, begin_edit: bool = False) -> None:
            if row < 0 or col < 0:
                return
            if row >= self.table.rowCount() or col >= self.table.columnCount():
                return
            if self.table.isRowHidden(row) or self._is_effectively_hidden_col(col):
                return

            self.table.setCurrentCell(row, col)
            manager = self._frozen_manager()
            view = manager.view_for_column(col) if manager is not None and hasattr(manager, "view_for_column") else self.table
            view.scrollTo(self.table.model().index(row, col), QAbstractItemView.ScrollHint.PositionAtCenter)

            if keep_anchor and anchor_row >= 0 and anchor_col >= 0:
                self.table.clearSelection()
                top_row = min(anchor_row, row)
                bottom_row = max(anchor_row, row)
                left_col = min(anchor_col, col)
                right_col = max(anchor_col, col)
                self.table.setRangeSelected(QTableWidgetSelectionRange(top_row, left_col, bottom_row, right_col), True)
            else:
                self.table.clearSelection()
                self.table.setRangeSelected(QTableWidgetSelectionRange(row, col, row, col), True)

            if begin_edit:
                self._start_edit_current_cell()

        def _start_edit_current_cell(self) -> None:
            row, col = self._current_cell_or_default()
            if row < 0 or col < 0:
                return
            if self._is_checkbox_col(col):
                return
            if self.table.isRowHidden(row) or self._is_effectively_hidden_col(col):
                return

            item = self.table.item(row, col)
            if item is None:
                item = QTableWidgetItem("")
                self.table.setItem(row, col, item)
            if not (item.flags() & Qt.ItemFlag.ItemIsEditable):
                return

            manager = self._frozen_manager()
            view = manager.view_for_column(col) if manager is not None and hasattr(manager, "view_for_column") else self.table
            index = self.table.model().index(row, col)
            view.setFocus(Qt.FocusReason.OtherFocusReason)
            view.setCurrentIndex(index)
            QTimer.singleShot(0, lambda v=view, idx=index: v.edit(idx))

        def _ctrl_row_target(self, start_row: int, col: int, direction: int) -> int:
            row_count = self.table.rowCount()
            if row_count <= 0:
                return start_row

            row = max(0, min(start_row, row_count - 1))
            if self.table.isRowHidden(row):
                r = row + direction
                while 0 <= r < row_count and self.table.isRowHidden(r):
                    r += direction
                if 0 <= r < row_count:
                    row = r
                else:
                    return start_row

            current_text = self._cell_text(row, col)
            r = row + direction

            if not current_text:
                while 0 <= r < row_count:
                    if self._cell_text(r, col):
                        return r
                    r += direction
                return row

            last_non_blank = row
            while 0 <= r < row_count:
                if not self._cell_text(r, col):
                    break
                last_non_blank = r
                r += direction
            return last_non_blank

        def _ctrl_col_target(self, row: int, start_col: int, direction: int) -> int:
            col_count = self.table.columnCount()
            if col_count <= 0:
                return start_col

            col = max(0, min(start_col, col_count - 1))
            if self._is_effectively_hidden_col(col):
                c = col + direction
                while 0 <= c < col_count and self._is_effectively_hidden_col(c):
                    c += direction
                if 0 <= c < col_count:
                    col = c
                else:
                    return start_col

            current_text = self._cell_text(row, col)
            c = col + direction

            if not current_text:
                while 0 <= c < col_count:
                    if self._is_effectively_hidden_col(c):
                        c += direction
                        continue
                    if self._cell_text(row, c):
                        return c
                    c += direction
                return col

            last_non_blank = col
            while 0 <= c < col_count:
                if self._is_effectively_hidden_col(c):
                    c += direction
                    continue
                if not self._cell_text(row, c):
                    break
                last_non_blank = c
                c += direction
            return last_non_blank

        def _last_non_blank_col_in_row(self, row: int) -> int:
            data_cols = self._visible_data_cols()
            if not data_cols:
                return 0
            for col in reversed(data_cols):
                if self._cell_text(row, col):
                    return col
            return data_cols[-1]

        def _last_used_cell(self) -> tuple[int, int]:
            visible_rows = self._visible_rows()
            data_cols = self._visible_data_cols()
            if not visible_rows or not data_cols:
                return (0, 0)

            last_row = visible_rows[0]
            last_col = data_cols[0]
            found_any = False

            for row in visible_rows:
                for col in data_cols:
                    if self._cell_text(row, col):
                        last_row = row
                        last_col = col
                        found_any = True

            if found_any:
                return (last_row, last_col)
            return (visible_rows[0], data_cols[0])

        def handle_home_end_navigation(self, key, ctrl: bool = False, extend_selection: bool = False):
            row_count = self.table.rowCount()
            col_count = self.table.columnCount()
            if row_count <= 0 or col_count <= 0:
                return

            visible_rows = self._visible_rows()
            data_cols = self._visible_data_cols()
            if not visible_rows or not data_cols:
                return

            row, col = self._current_cell_or_default()
            if row not in visible_rows:
                row = visible_rows[0]
            if col not in data_cols:
                col = data_cols[0]

            anchor_row, anchor_col = row, col

            if key == Qt.Key.Key_Home:
                if ctrl:
                    target_row = visible_rows[0]
                    target_col = data_cols[0]
                else:
                    target_row = row
                    target_col = data_cols[0]
            else:
                if ctrl:
                    target_row, target_col = self._last_used_cell()
                else:
                    target_row = row
                    target_col = self._last_non_blank_col_in_row(row)

            self._move_to_cell(
                target_row,
                target_col,
                keep_anchor=extend_selection,
                anchor_row=anchor_row,
                anchor_col=anchor_col,
                begin_edit=False,
            )

        def handle_ctrl_arrow_navigation(self, key, extend_selection: bool = False):
            row_count = self.table.rowCount()
            col_count = self.table.columnCount()
            if row_count <= 0 or col_count <= 0:
                return

            row, col = self._current_cell_or_default()
            anchor_row, anchor_col = row, col

            if key == Qt.Key.Key_Up:
                target_row = self._ctrl_row_target(row, col, -1)
                target_col = col
            elif key == Qt.Key.Key_Down:
                target_row = self._ctrl_row_target(row, col, 1)
                target_col = col
            elif key == Qt.Key.Key_Left:
                target_row = row
                target_col = self._ctrl_col_target(row, col, -1)
            else:
                target_row = row
                target_col = self._ctrl_col_target(row, col, 1)

            self._move_to_cell(target_row, target_col, keep_anchor=extend_selection, anchor_row=anchor_row, anchor_col=anchor_col, begin_edit=False)

        def handle_tab_navigation(self, move_left: bool = False):
            row_count = self.table.rowCount()
            col_count = self.table.columnCount()
            if row_count <= 0 or col_count <= 0:
                return

            visible_rows = self._visible_rows()
            visible_cols = self._visible_cols()
            if not visible_rows or not visible_cols:
                return

            row, col = self._current_cell_or_default()
            if row not in visible_rows:
                row = visible_rows[0]
            if col not in visible_cols:
                col = visible_cols[0]

            row_pos = visible_rows.index(row)
            col_pos = visible_cols.index(col)

            if move_left:
                col_pos -= 1
                if col_pos < 0:
                    col_pos = len(visible_cols) - 1
                    row_pos = max(0, row_pos - 1)
            else:
                col_pos += 1
                if col_pos >= len(visible_cols):
                    col_pos = 0
                    row_pos = min(len(visible_rows) - 1, row_pos + 1)

            target_row = visible_rows[row_pos]
            target_col = visible_cols[col_pos]
            self._move_to_cell(target_row, target_col, begin_edit=not self._is_checkbox_col(target_col))

        def _select_current_row(self):
            row, col = self._current_cell_or_default()
            if row < 0:
                return
            left_col = 0
            right_col = max(0, self.table.columnCount() - 1)
            self.table.clearSelection()
            self.table.setCurrentCell(row, max(0, col))
            self.table.setRangeSelected(QTableWidgetSelectionRange(row, left_col, row, right_col), True)

        def _select_current_column(self):
            row, col = self._current_cell_or_default()
            if col < 0:
                return
            top_row = 0
            bottom_row = max(0, self.table.rowCount() - 1)
            self.table.clearSelection()
            self.table.setCurrentCell(max(0, row), col)
            self.table.setRangeSelected(QTableWidgetSelectionRange(top_row, col, bottom_row, col), True)

        def insert_current_date(self):
            row, col = self._current_cell_or_default()
            if row < 0 or col < 0:
                return
            if self._is_checkbox_col(col):
                return
            if self.table.isRowHidden(row) or self.table.isColumnHidden(col):
                return

            item = self.table.item(row, col)
            if item is None:
                item = QTableWidgetItem("")
                self.table.setItem(row, col, item)
            if not (item.flags() & Qt.ItemFlag.ItemIsEditable):
                return

            date_text = date.today().strftime("%m/%d/%Y")
            self.table.blockSignals(True)
            item.setText(date_text)
            self.table.blockSignals(False)

            if self.change_callback:
                self.change_callback()
            if self.ensure_row_callback:
                self.ensure_row_callback()
            if hasattr(self.table, "_trigger_unit_costs"):
                self.table._trigger_unit_costs()
            if self.post_edit_callback:
                self.post_edit_callback()

        def handle_copy(self):
            """Copy selected cells as tab-delimited text, including multi-range selections."""
            selected_ranges = self.table.selectedRanges()
            if selected_ranges:
                blocks = []
                for sel_range in selected_ranges:
                    lines = []
                    for row in range(sel_range.topRow(), sel_range.bottomRow() + 1):
                        values = []
                        for col in range(sel_range.leftColumn(), sel_range.rightColumn() + 1):
                            item = self.table.item(row, col)
                            values.append(item.text() if item else "")
                        lines.append("\t".join(values))
                    blocks.append("\n".join(lines))

                QApplication.clipboard().setText("\n\n".join(blocks))  # type: ignore[union-attr]
                return

            selected_indexes = [idx for idx in self.table.selectedIndexes() if idx.isValid()]
            if selected_indexes:
                rows = [idx.row() for idx in selected_indexes]
                cols = [idx.column() for idx in selected_indexes]
                min_row, max_row = min(rows), max(rows)
                min_col, max_col = min(cols), max(cols)

                selected_coords = {(idx.row(), idx.column()) for idx in selected_indexes}
                lines = []
                for row in range(min_row, max_row + 1):
                    values = []
                    for col in range(min_col, max_col + 1):
                        if (row, col) in selected_coords:
                            item = self.table.item(row, col)
                            values.append(item.text() if item else "")
                        else:
                            values.append("")
                    lines.append("\t".join(values))

                QApplication.clipboard().setText("\n".join(lines))  # type: ignore[union-attr]
                return

            return

        def _ctrl_down_target_row(self, start_row: int, col: int) -> int:
            """Return target row for Ctrl+Down behavior in a column."""
            row_count = self.table.rowCount()
            if row_count == 0:
                return start_row

            if self.table.isRowHidden(start_row):
                for row in range(start_row + 1, row_count):
                    if not self.table.isRowHidden(row):
                        start_row = row
                        break
                else:
                    return start_row

            def cell_text(row_idx: int) -> str:
                if self.table.isRowHidden(row_idx):
                    return ""
                item = self.table.item(row_idx, col)
                return item.text().strip() if item else ""

            current_text = cell_text(start_row)

            # If current cell is blank: jump to next non-blank, else to last row.
            if not current_text:
                for row in range(start_row + 1, row_count):
                    if cell_text(row):
                        return row
                return start_row

            # Current cell has data: move through contiguous non-blank block to its edge.
            row = start_row
            while row + 1 < row_count and cell_text(row + 1):
                row += 1
            return row

        def handle_select_down(self):
            """Extend selection downward, similar to Excel Ctrl+Shift+Down."""
            current = self.table.currentIndex()
            if not current.isValid():
                selected = self.table.selectedRanges()
                if not selected:
                    return
                sel_range = selected[0]
                start_row = sel_range.topRow()
                current_col = sel_range.leftColumn()
                left_col = sel_range.leftColumn()
                right_col = sel_range.rightColumn()
            else:
                start_row = current.row()
                current_col = current.column()
                selected = self.table.selectedRanges()
                if selected:
                    first_range = selected[0]
                    in_first_range = (
                        first_range.topRow() <= current.row() <= first_range.bottomRow()
                        and first_range.leftColumn() <= current.column() <= first_range.rightColumn()
                    )
                    if in_first_range:
                        left_col = first_range.leftColumn()
                        right_col = first_range.rightColumn()
                    else:
                        left_col = current_col
                        right_col = current_col
                else:
                    left_col = current_col
                    right_col = current_col

            end_row = self._ctrl_down_target_row(start_row, current_col)

            self.table.clearSelection()
            top_row = min(start_row, end_row)
            bottom_row = max(start_row, end_row)

            if not self.table.isRowHidden(top_row) and not self.table.isRowHidden(bottom_row):
                self.table.setRangeSelected(QTableWidgetSelectionRange(top_row, left_col, bottom_row, right_col), True)
            else:
                for row in range(top_row, bottom_row + 1):
                    if self.table.isRowHidden(row):
                        continue
                    self.table.setRangeSelected(QTableWidgetSelectionRange(row, left_col, row, right_col), True)
            # Keep the range selected (do not collapse selection by moving current cell).

        def handle_enter_navigation(self, move_up: bool = False):
            """Move current cell vertically, similar to Excel Enter / Shift+Enter."""
            row_count = self.table.rowCount()
            col_count = self.table.columnCount()
            if row_count <= 0 or col_count <= 0:
                return

            current = self.table.currentIndex()
            if current.isValid():
                row = current.row()
                col = current.column()
            else:
                selected = self.table.selectedRanges()
                if not selected:
                    row, col = 0, 0
                else:
                    row = selected[0].topRow()
                    col = selected[0].leftColumn()

            delta = -1 if move_up else 1

            if self.table.isRowHidden(row):
                visible_row = None
                for r in range(row, row_count):
                    if not self.table.isRowHidden(r):
                        visible_row = r
                        break
                if visible_row is None:
                    for r in range(row - 1, -1, -1):
                        if not self.table.isRowHidden(r):
                            visible_row = r
                            break
                if visible_row is None:
                    return
                row = visible_row

            target_row = row
            search_row = row + delta
            while 0 <= search_row < row_count:
                if not self.table.isRowHidden(search_row):
                    target_row = search_row
                    break
                search_row += delta

            self._move_to_cell(target_row, col, begin_edit=not self._is_checkbox_col(col))

        def handle_fill_down(self):
            """Fill selected cells downward from the top value in each selected column (Excel Ctrl+D)."""
            selected_ranges = self.table.selectedRanges()
            if not selected_ranges:
                current = self.table.currentIndex()
                if not current.isValid():
                    return
                selected_ranges = [
                    QTableWidgetSelectionRange(
                        current.row(),
                        current.column(),
                        current.row(),
                        current.column(),
                    )
                ]

            current_index = self.table.currentIndex()

            def is_checkbox_col(col: int) -> bool:
                header_item = self.table.horizontalHeaderItem(col)
                return bool(header_item and header_item.text().strip() in ("", "", ""))

            def find_source_row_for_fill(top_row: int, bottom_row: int, col: int):
                # Prefer first non-empty visible value inside selection.
                for row in range(top_row, bottom_row + 1):
                    if self.table.isRowHidden(row):
                        continue
                    item = self.table.item(row, col)
                    if item and item.text().strip():
                        return row

                # Fallback to nearest visible row above selection.
                for row in range(top_row - 1, -1, -1):
                    if not self.table.isRowHidden(row):
                        return row

                # Final fallback: first visible row inside selection.
                for row in range(top_row, bottom_row + 1):
                    if not self.table.isRowHidden(row):
                        return row
                return None

            selected_non_checkbox_cols = set()
            for sel_range in selected_ranges:
                for col in range(sel_range.leftColumn(), sel_range.rightColumn() + 1):
                    if not is_checkbox_col(col):
                        selected_non_checkbox_cols.add(col)

            self.table.blockSignals(True)
            changed = False
            for sel_range in selected_ranges:
                candidate_cols = [
                    col
                    for col in range(sel_range.leftColumn(), sel_range.rightColumn() + 1)
                    if not is_checkbox_col(col)
                ]

                # If selection is only in checkbox column(s), apply fill-down to
                # the active data column across the selected rows.
                if not candidate_cols and current_index.isValid() and not is_checkbox_col(current_index.column()):
                    candidate_cols = [current_index.column()]

                for col in candidate_cols:

                    top_row = sel_range.topRow()
                    bottom_row = sel_range.bottomRow()

                    # Excel behavior: for a single-row selection, copy from the nearest
                    # visible row above into the selected cell(s).
                    if top_row == bottom_row:
                        target_row = top_row
                        source_row = None
                        for row in range(target_row - 1, -1, -1):
                            if not self.table.isRowHidden(row):
                                source_row = row
                                break
                        if source_row is None:
                            continue

                        source_item = self.table.item(source_row, col)
                        source_value = source_item.text() if source_item else ""

                        target_item = self.table.item(target_row, col)
                        if target_item is None:
                            target_item = QTableWidgetItem(source_value)
                            self.table.setItem(target_row, col, target_item)
                        else:
                            target_item.setText(source_value)
                        changed = True
                        continue

                    source_row = find_source_row_for_fill(top_row, bottom_row, col)

                    if source_row is None:
                        continue

                    source_item = self.table.item(source_row, col)
                    source_value = source_item.text() if source_item else ""

                    for row in range(top_row, bottom_row + 1):
                        if row == source_row:
                            continue
                        if self.table.isRowHidden(row):
                            continue
                        item = self.table.item(row, col)
                        if item is None:
                            item = QTableWidgetItem(source_value)
                            self.table.setItem(row, col, item)
                        else:
                            item.setText(source_value)
                        changed = True

            self.table.blockSignals(False)

            if changed:
                if self.change_callback:
                    self.change_callback()
                if self.ensure_row_callback:
                    self.ensure_row_callback()
                if hasattr(self.table, "_trigger_unit_costs"):
                    self.table._trigger_unit_costs()
                if self.post_edit_callback:
                    self.post_edit_callback()
                resized_cols = set()
                for sel_range in selected_ranges:
                    for col in range(sel_range.leftColumn(), sel_range.rightColumn() + 1):
                        if col not in resized_cols:
                            self.table.resizeColumnToContents(col)
                            resized_cols.add(col)
        
        def handle_paste(self):
            """Handle paste from clipboard, adding rows as needed."""
            clipboard = QApplication.clipboard()
            assert clipboard is not None
            text = clipboard.text()
            
            if not text:
                return
            
            # Parse clipboard data (tab-delimited rows)
            lines = text.split('\n')
            # Remove empty last line if present
            if lines and not lines[-1].strip():
                lines = lines[:-1]
            
            if not lines:
                return
            
            # Get current selection
            selected = self.table.selectedRanges()
            if not selected:
                # If nothing selected, paste at top-left
                start_row = 0
                start_col = 0
            else:
                # Paste at top-left of selection
                start_row = selected[0].topRow()
                start_col = selected[0].leftColumn()
            
            # Parse and normalize clipboard rows so blank lines stay full-width
            # instead of collapsing to a single first-column cell.
            selection_width = 1
            if selected:
                selection_width = max(1, selected[0].rightColumn() - selected[0].leftColumn() + 1)

            raw_rows = [line.rstrip('\r').split('\t') for line in lines]
            expected_width = max((len(row) for row in raw_rows), default=1)
            if selection_width > 1:
                expected_width = max(expected_width, selection_width)

            paste_data = []
            for row in raw_rows:
                normalized_row = list(row)
                if len(normalized_row) < expected_width:
                    normalized_row.extend([""] * (expected_width - len(normalized_row)))
                paste_data.append(normalized_row)

            max_pasted_width = max((len(row) for row in paste_data), default=0)

            # Build visible target rows so paste skips hidden/filter rows.
            target_rows = []
            search_row = start_row
            row_count = self.table.rowCount()
            while search_row < row_count and len(target_rows) < len(paste_data):
                if not self.table.isRowHidden(search_row):
                    target_rows.append(search_row)
                search_row += 1

            remaining_rows = len(paste_data) - len(target_rows)
            if remaining_rows > 0 and not self.table.property("_no_auto_row_add"):
                # Add rows at the bottom and use any visible new rows as targets.
                old_count = self.table.rowCount()
                self.table.blockSignals(True)
                self.table.setRowCount(old_count + remaining_rows + 1)  # +1 for the empty row at the end
                self.table.blockSignals(False)
                for row in range(old_count, self.table.rowCount()):
                    if not self.table.isRowHidden(row):
                        target_rows.append(row)
                        if len(target_rows) >= len(paste_data):
                            break

            if not target_rows:
                return
            
            # Paste the data
            self.table.blockSignals(True)
            for row_offset, row_data in enumerate(paste_data):
                if row_offset >= len(target_rows):
                    break
                target_row = target_rows[row_offset]
                for col_offset, cell_value in enumerate(row_data):
                    target_col = start_col + col_offset
                    if target_col < self.table.columnCount():
                        item = self.table.item(target_row, target_col)
                        if item is None:
                            item = QTableWidgetItem(cell_value)
                            self.table.setItem(target_row, target_col, item)
                        else:
                            item.setText(cell_value)
            self.table.blockSignals(False)
            
            # Notify that changes were made
            if self.change_callback:
                self.change_callback()
            if self.ensure_row_callback:
                self.ensure_row_callback()
            if hasattr(self.table, "_trigger_unit_costs"):
                self.table._trigger_unit_costs()
            if self.post_edit_callback:
                self.post_edit_callback()
            if max_pasted_width > 0:
                end_col = min(self.table.columnCount() - 1, start_col + max_pasted_width - 1)
                for col in range(start_col, end_col + 1):
                    self.table.resizeColumnToContents(col)
        
        def handle_delete(self):
            """Clear the contents of selected cells."""
            selected = self.table.selectedRanges()
            if not selected:
                return
            
            # Clear all selected cells
            self.table.blockSignals(True)
            for sel_range in selected:
                for row in range(sel_range.topRow(), sel_range.bottomRow() + 1):
                    if self.table.isRowHidden(row):
                        continue
                    for col in range(sel_range.leftColumn(), sel_range.rightColumn() + 1):
                        item = self.table.item(row, col)
                        if item is not None:
                            item.setText("")
            self.table.blockSignals(False)
            
            # Notify that changes were made
            if self.change_callback:
                self.change_callback()
            if self.ensure_row_callback:
                self.ensure_row_callback()
            if hasattr(self.table, "_trigger_unit_costs"):
                self.table._trigger_unit_costs()
            if self.post_edit_callback:
                self.post_edit_callback()

    def _evaluate_calculator_expression(self, expression: str):
        """Safely evaluate a basic arithmetic expression for the cell calculator."""
        if not expression:
            return None

        expr = expression.strip().replace(",", "")
        if not expr:
            return None

        try:
            node = ast.parse(expr, mode="eval")
        except Exception:
            return None

        def _eval(n):
            if isinstance(n, ast.Expression):
                return _eval(n.body)
            if isinstance(n, ast.Constant) and isinstance(n.value, (int, float)):
                return n.value
            if isinstance(n, ast.UnaryOp) and isinstance(n.op, (ast.UAdd, ast.USub)):
                value = _eval(n.operand)
                return +value if isinstance(n.op, ast.UAdd) else -value
            if isinstance(n, ast.BinOp):
                left = _eval(n.left)
                right = _eval(n.right)
                if isinstance(n.op, ast.Add):
                    return left + right
                if isinstance(n.op, ast.Sub):
                    return left - right
                if isinstance(n.op, ast.Mult):
                    return left * right
                if isinstance(n.op, ast.Div):
                    return left / right
                if isinstance(n.op, ast.FloorDiv):
                    return left // right
                if isinstance(n.op, ast.Mod):
                    return left % right
                if isinstance(n.op, ast.Pow):
                    return left ** right
            raise ValueError("Unsupported expression")

        try:
            return _eval(node)
        except Exception:
            return None

    def _duplicate_rows_with_dialog(
        self,
        table: QTableWidget,
        source_row: int,
        table_headers: list,
        duplicate_rows_fn,
        mark_changed_fn,
    ) -> None:
        """Show a dialog asking how many copies and what suffix style, then duplicate."""
        # Find the mark / opening-number column in the table headers
        mark_col_idx: int | None = None
        mark_keywords = {"opening number", "opening #", "opening", "mark", "door #", "frame #"}
        for idx in range(table.columnCount()):
            hdr_item = table.horizontalHeaderItem(idx)
            if hdr_item and hdr_item.text().strip().lower() in mark_keywords:
                mark_col_idx = idx
                break

        source_mark = ""
        if mark_col_idx is not None:
            src_item = table.item(source_row, mark_col_idx)
            source_mark = src_item.text().strip() if src_item else ""

        # --- Build dialog ---
        dlg = QDialog(table.window())
        dlg.setWindowTitle("Duplicate Row")
        layout = QVBoxLayout(dlg)

        layout.addWidget(QLabel(f"Duplicating row {source_row + 1}"
                                + (f"  (Mark: {source_mark})" if source_mark else "")))

        # Number of copies
        count_layout = QHBoxLayout()
        count_layout.addWidget(QLabel("Number of copies:"))
        count_spin = QSpinBox()
        count_spin.setRange(1, 999)
        count_spin.setValue(1)
        count_layout.addWidget(count_spin)
        layout.addLayout(count_layout)

        # Suffix style
        suffix_group = QGroupBox("Mark suffix")
        suffix_layout = QVBoxLayout(suffix_group)
        btn_group = QButtonGroup(dlg)
        rb_none = QRadioButton("No suffix  (same mark for every copy)")
        rb_letter = QRadioButton("Lettered   (a, b, c …)")
        rb_number = QRadioButton("Numbered  (.1, .2, .3 …)")
        rb_none.setChecked(True)
        for rb in (rb_none, rb_letter, rb_number):
            btn_group.addButton(rb)
            suffix_layout.addWidget(rb)
        layout.addWidget(suffix_group)

        buttons = QDialogButtonBox(
            QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel
        )
        buttons.accepted.connect(dlg.accept)
        buttons.rejected.connect(dlg.reject)
        layout.addWidget(buttons)

        if dlg.exec() != QDialog.DialogCode.Accepted:
            return

        num_copies = count_spin.value()
        if rb_letter.isChecked():
            suffix_mode = "letter"
        elif rb_number.isChecked():
            suffix_mode = "number"
        else:
            suffix_mode = "none"

        # --- Perform duplication ---
        table.blockSignals(True)
        try:
            for i in range(num_copies):
                insert_at = source_row + 1 + i
                table.insertRow(insert_at)
                for c in range(table.columnCount()):
                    src_item = table.item(source_row, c)
                    if src_item is None:
                        continue
                    try:
                        new_item = src_item.clone()
                    except Exception:
                        new_item = QTableWidgetItem(src_item.text())
                        new_item.setFlags(src_item.flags())
                        if src_item.flags() & Qt.ItemFlag.ItemIsUserCheckable:
                            new_item.setCheckState(src_item.checkState())
                    table.setItem(insert_at, c, new_item)

                # Apply suffix to the mark column
                if mark_col_idx is not None and source_mark and suffix_mode != "none":
                    if suffix_mode == "letter":
                        suffix = chr(ord("a") + i) if i < 26 else chr(ord("a") + (i // 26) - 1) + chr(ord("a") + (i % 26))
                    else:
                        suffix = f".{i + 1}"
                    mark_item = table.item(insert_at, mark_col_idx)
                    if mark_item is None:
                        mark_item = QTableWidgetItem()
                        table.setItem(insert_at, mark_col_idx, mark_item)
                    mark_item.setText(f"{source_mark}{suffix}")
        finally:
            table.blockSignals(False)

        mark_changed_fn()

    def _open_cell_calculator(self, table: QTableWidget, row: int, col: int, change_callback=None):
        """Open calculator dialog and write evaluated result into the target cell."""
        existing_item = table.item(row, col)
        existing_text = existing_item.text().strip() if existing_item else ""

        dlg = QDialog(table)
        dlg.setWindowTitle("Calculator")
        layout = QVBoxLayout(dlg)

        layout.addWidget(QLabel("Enter math expression:"))
        expr_edit = QLineEdit(existing_text)
        layout.addWidget(expr_edit)

        result_label = QLabel("Result: -")
        layout.addWidget(result_label)

        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
        ok_button = buttons.button(QDialogButtonBox.StandardButton.Ok)
        assert ok_button is not None
        ok_button.setText("Apply")
        ok_button.setEnabled(False)
        layout.addWidget(buttons)

        calc_state = {"valid": False, "result": None}

        def update_result_label():
            result = self._evaluate_calculator_expression(expr_edit.text())
            if result is None:
                calc_state["valid"] = False
                calc_state["result"] = None
                result_label.setText("Result: invalid expression")
                ok_button.setEnabled(False)
                return

            calc_state["valid"] = True
            calc_state["result"] = result
            if isinstance(result, float) and result.is_integer():
                shown = str(int(result))
            else:
                shown = str(result)
            result_label.setText(f"Result: {shown}")
            ok_button.setEnabled(True)

        expr_edit.textChanged.connect(update_result_label)
        buttons.accepted.connect(dlg.accept)
        buttons.rejected.connect(dlg.reject)
        update_result_label()

        if dlg.exec() != QDialog.DialogCode.Accepted or not calc_state["valid"]:
            return

        result = calc_state["result"]
        if isinstance(result, float) and result.is_integer():
            new_value = str(int(result))
        else:
            new_value = str(result)

        item = table.item(row, col)
        if item is None:
            item = QTableWidgetItem(new_value)
            table.setItem(row, col, item)
        else:
            item.setText(new_value)

        if change_callback:
            change_callback()

    def email_vendor_quote(
        self,
        table_headers: List[str],
        table_data: List[dict],
        table_name: str,
        workbook_path: Optional[Path] = None,
        source_frame_table: Optional[QTableWidget] = None,
        source_frame_headers: Optional[List[str]] = None,
        source_door_table: Optional[QTableWidget] = None,
        source_door_headers: Optional[List[str]] = None,
    ) -> None:
        """
        Generate a PDF of the table filtered by vendor and email it via Outlook.
        
        Args:
            table_headers: List of column headers
            table_data: List of row dictionaries
            table_name: Name of the table (e.g., "Wood Doors", "Aluminum Frames")
            workbook_path: Optional path to workbook for finding vendors_contacts.csv
        """
        try:
            # Get vendor list from table
            vendors = get_vendor_list_from_table(table_data, vendor_column="Vendor")
            
            if not vendors:
                QMessageBox.warning(self, "No Vendors", "No vendors found in the table. Add vendors to rows before emailing quotes.")
                return
            
            # Show vendor selection dialog
            vendor_dlg = VendorQuoteDialog(vendors, self)
            if vendor_dlg.exec() != QDialog.DialogCode.Accepted:
                return
            
            selected_vendor = vendor_dlg.get_selected_vendor()
            
            # Filter table data by vendor
            filtered_data = filter_table_by_vendor(table_data, selected_vendor, vendor_column="Vendor")
            
            if not filtered_data:
                QMessageBox.warning(self, "No Data", f"No rows found for vendor: {selected_vendor}")
                return
            
            # Determine vendors_contacts.csv path
            if workbook_path:
                # Use provided workbook path to find the root
                root_path = workbook_path
                while root_path.parent != root_path:  # Not at filesystem root
                    if (root_path.parent / "vendors_contacts.csv").exists():
                        vendors_contacts_csv = root_path.parent / "vendors_contacts.csv"
                        break
                    root_path = root_path.parent
                else:
                    # Fallback to self.paths if provided path doesn't work
                    vendors_contacts_csv = self.paths.root / "vendors_contacts.csv" if self.paths else Path("data/vendors_contacts.csv")
            else:
                # Use self.paths as primary source
                vendors_contacts_csv = self.paths.root / "vendors_contacts.csv" if self.paths else Path("data/vendors_contacts.csv")
            
            vendor_contacts = load_vendor_contacts(vendors_contacts_csv)
            vendor_email = vendor_contacts.get(selected_vendor, "")
            
            if not vendor_email:
                # Show what vendor names are available
                available_vendors = ", ".join(vendor_contacts.keys()) if vendor_contacts else "None"
                QMessageBox.warning(self, "Vendor Not Found", 
                    f"No email found for vendor: '{selected_vendor}'\n\n"
                    f"Available vendors:\n{available_vendors}\n\n"
                    f"Please check the vendor name in your table matches exactly "
                    f"(including spaces and capitalization) with vendors_contacts.csv")
                return
            
            # Get bid/project name
            bid_path = getattr(self, "_current_editing_path", None)
            bid_name = bid_path.name if bid_path and isinstance(bid_path, Path) else ""
            
            # Generate PDF with filtered data
            pdf_path = self._generate_vendor_quote_pdf(table_name, selected_vendor, table_headers, filtered_data, bid_name)
            
            if not pdf_path:
                QMessageBox.warning(self, "PDF Error", "Failed to generate PDF. Please try again.")
                return
            
            # Optional: include elevations when emailing quotes.
            attachment_pdf_path = pdf_path
            is_frame_quote = source_frame_table is not None and source_frame_headers is not None and "frame" in table_name.lower()
            is_door_quote = source_door_table is not None and source_door_headers is not None and "door" in table_name.lower()
            if is_door_quote:
                include_reply = QMessageBox.question(
                    self,
                    "Include Door Elevations",
                    "Include door elevations in this quote PDF?",
                    QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                    QMessageBox.StandardButton.Yes,
                )
                if include_reply == QMessageBox.StandardButton.Yes:
                    temp_dir = Path(tempfile.gettempdir()) / "GORO_Quotes"
                    temp_dir.mkdir(parents=True, exist_ok=True)
                    ts = datetime.now().strftime("%Y%m%d_%H%M%S")
                    door_pdf_path = temp_dir / sanitize_name(f"Door_Elevations_{table_name}_{selected_vendor}_{ts}.pdf")

                    generated_door_pdf = self.export_door_elevations_pdf(
                        None,
                        None,
                        workbook_path,
                        source_door_table=source_door_table,
                        source_door_headers=source_door_headers,
                        source_door_tab_name=table_name,
                        out_path=door_pdf_path,
                        prompt_for_path=False,
                        show_messages=False,
                    )

                    if generated_door_pdf and generated_door_pdf.exists():
                        if HAS_PYPDF2 and PdfMerger is not None:
                            merged_pdf_path = temp_dir / sanitize_name(f"Quote_With_Door_Elevations_{table_name}_{selected_vendor}_{ts}.pdf")
                            try:
                                merger = PdfMerger()
                                merger.append(str(pdf_path))
                                merger.append(str(generated_door_pdf))
                                merger.write(str(merged_pdf_path))
                                merger.close()
                                attachment_pdf_path = merged_pdf_path
                            except Exception as merge_e:
                                QMessageBox.warning(
                                    self,
                                    "Door Elevations",
                                    f"Could not merge door elevations into quote PDF. Sending quote-only PDF.\n\n{merge_e}",
                                )
                        else:
                            QMessageBox.warning(
                                self,
                                "Door Elevations",
                                "PDF merge support is not available. Sending quote-only PDF.",
                            )
                    else:
                        QMessageBox.warning(
                            self,
                            "Door Elevations",
                            "Could not generate door elevations PDF. Sending quote-only PDF.",
                        )
            if is_frame_quote:
                include_reply = QMessageBox.question(
                    self,
                    "Include Frame Elevations",
                    "Include frame elevations in this quote PDF?",
                    QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                    QMessageBox.StandardButton.Yes,
                )
                if include_reply == QMessageBox.StandardButton.Yes:
                    temp_dir = Path(tempfile.gettempdir()) / "GORO_Quotes"
                    temp_dir.mkdir(parents=True, exist_ok=True)
                    ts = datetime.now().strftime("%Y%m%d_%H%M%S")
                    frame_pdf_path = temp_dir / sanitize_name(f"Frame_Elevations_{table_name}_{selected_vendor}_{ts}.pdf")

                    generated_frame_pdf = self.export_frame_elevations_pdf(
                        None,
                        None,
                        workbook_path,
                        source_frame_table=source_frame_table,
                        source_frame_headers=source_frame_headers,
                        source_frame_tab_name=table_name,
                        out_path=frame_pdf_path,
                        prompt_for_path=False,
                        show_messages=False,
                    )

                    if generated_frame_pdf and generated_frame_pdf.exists():
                        if HAS_PYPDF2 and PdfMerger is not None:
                            merged_pdf_path = temp_dir / sanitize_name(f"Quote_With_Frame_Elevations_{table_name}_{selected_vendor}_{ts}.pdf")
                            try:
                                merger = PdfMerger()
                                merger.append(str(pdf_path))
                                merger.append(str(generated_frame_pdf))
                                merger.write(str(merged_pdf_path))
                                merger.close()
                                attachment_pdf_path = merged_pdf_path
                            except Exception as merge_e:
                                QMessageBox.warning(
                                    self,
                                    "Frame Elevations",
                                    f"Could not merge frame elevations into quote PDF. Sending quote-only PDF.\n\n{merge_e}",
                                )
                        else:
                            QMessageBox.warning(
                                self,
                                "Frame Elevations",
                                "PDF merge support is not available. Sending quote-only PDF.",
                            )
                    else:
                        QMessageBox.warning(
                            self,
                            "Frame Elevations",
                            "Could not generate frame elevations PDF. Sending quote-only PDF.",
                        )

            # Get email template from settings
            settings = QSettings(ORG_NAME, APP_NAME)
            email_body = settings.value("quote_email_template", 
                "Hello,\n\nPlease provide a quote for the items listed in the attached PDF.\n\nThank you,\nBid Team", type=str)
            
            # Launch Outlook with bid name in subject
            bid_prefix = f"{bid_name} - " if bid_name else ""
            email_subject = f"Quote Request - {bid_prefix}{table_name} - {selected_vendor}"
            success = launch_outlook_with_pdf(
                recipient_email=vendor_email,
                subject=email_subject,
                body=email_body,
                pdf_path=attachment_pdf_path
            )
            
            if success:
                QMessageBox.information(self, "Success", 
                    f"Email opened in Outlook for {selected_vendor}\n\n"
                    f"Email: {vendor_email}\n"
                    f"PDF: {attachment_pdf_path.name}")
                
                # Log the quote email as a communication
                if bid_path and isinstance(bid_path, Path) and bid_path.exists():
                    self._log_vendor_quote_as_communication(
                        bid_path=bid_path,
                        table_name=table_name,
                        vendor_name=selected_vendor,
                        vendor_email=vendor_email,
                        pdf_path=attachment_pdf_path,
                        email_subject=email_subject,
                        email_body=email_body,
                    )
            else:
                QMessageBox.warning(self, "Error", 
                    f"Could not launch Outlook. PDF saved to:\n{attachment_pdf_path}")
        
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to email quote:\n{str(e)}")

    def _log_vendor_quote_as_communication(
        self,
        bid_path: Path,
        table_name: str,
        vendor_name: str,
        vendor_email: str,
        pdf_path: Path,
        email_subject: str,
        email_body: str,
    ) -> None:
        """
        Log a vendor quote email as a communication in the bid notes.
        Copy the PDF to the bid files section.
        
        Args:
            bid_path: Path to the bid/project folder
            table_name: Name of the quote table (e.g., "Wood Doors")
            vendor_name: Name of the vendor
            vendor_email: Email address of the vendor  
            pdf_path: Path to the generated PDF
            email_subject: Email subject line
            email_body: Email body text
        """
        try:
            # Create a Documents subfolder if it doesn't exist
            bid_docs_folder = bid_path / "Documents"
            bid_docs_folder.mkdir(parents=True, exist_ok=True)

            # Copy PDF to bid files folder
            pdf_filename = f"Quote_{table_name}_{vendor_name}_{datetime.now().strftime('%Y%m%d_%H%M%S')}.pdf"
            pdf_filename_safe = sanitize_name(pdf_filename)
            pdf_dest = bid_docs_folder / pdf_filename_safe
            
            if pdf_path.exists():
                shutil.copy2(str(pdf_path), str(pdf_dest))

            # Create communication log entry
            note_scope, record_rel = self._get_record_scope_and_rel_for_notes(bid_path)
            if not record_rel:
                return
            
            content_lines = [
                f"Quote Request Email Sent",
                f"Table: {table_name}",
                f"Vendor: {vendor_name}",
                f"Email: {vendor_email}",
                "",
                f"Subject: {email_subject}",
                "",
                "Message:",
                email_body,
            ]

            notes = self._load_notes()
            notes.append({
                "id": str(uuid.uuid4()),
                "type": "Communication",
                "subject": email_subject,
                "content": "\n".join(content_lines),
                "direction": "To",
                "contact": vendor_name,
                "pinned": False,
                "file_path": str(pdf_dest) if pdf_dest.exists() else "",
                "scope": note_scope,
                "record_rel_path": record_rel,
                "bid_rel_path": record_rel if note_scope == "bid" else "",
                "created_at": now_iso(),
            })
            self._save_notes(notes)
            
            # Refresh the files tree to show the new PDF
            if hasattr(self, "other_folders_tree"):
                self._refresh_folder_tree_for_bid(bid_path)
        
        except Exception as e:
            print(f"Error logging vendor quote: {e}")

    def _refresh_folder_tree_for_bid(self, bid_path: Path) -> None:
        """Refresh the folder tree to show files added to the bid."""
        if not hasattr(self, "other_folders_tree"):
            return
        try:
            self._update_other_folders_buttons(bid_path)
        except Exception as e:
            print(f"Error refreshing folder tree: {e}")

    def _create_table_with_email_button(self, table_widget: QTableWidget, headers: List[str], 
                                        table_name: str, workbook_path: Optional[Path] = None) -> QWidget:
        """
        Wrap a table with an "Email Quote" button above it.
        
        Args:
            table_widget: The QTableWidget to wrap
            headers: Column headers for the table
            table_name: Name of the table (e.g., "Wood Doors")
            workbook_path: Optional path to the workbook for finding vendor contacts
        
        Returns:
            A QWidget containing the button and table
        """
        container = QWidget()
        layout = QVBoxLayout(container)
        layout.setContentsMargins(0, 0, 0, 0)
        layout.setSpacing(5)
        
        # Create button
        btn_email = QPushButton("ðŸ“§ Email Quote")
        btn_email.setMaximumWidth(150)
        
        def on_email_clicked():
            # Extract table data from widget
            table_data = []
            for row in range(table_widget.rowCount()):
                row_dict = {}
                for col, header in enumerate(headers):
                    item = table_widget.item(row, col)
                    value = item.text() if item else ""
                    row_dict[header] = value
                table_data.append(row_dict)
            
            # Open email dialog, passing workbook path
            self.email_vendor_quote(headers, table_data, table_name, workbook_path)
        
        btn_email.clicked.connect(on_email_clicked)
        
        # Layout with button and table
        layout.addWidget(btn_email)
        layout.addWidget(table_widget, 1)
        
        return container

