                    ("Active Width", ["active width"]),
                    ("Inactive Width", ["inactive width"]),
                    ("Height", ["height", "door height"]),
                    ("Fire Rating", ["fire rating"]),
                    ("Core", ["core"]),
                    ("Finish", ["finish"]),
