    def import_from_pdf(self, tab_widget, tables_data, mark_changed_callback, workbook_path):
        """Import table data from PDF using hybrid text extraction/OCR approach."""
        # Determine default directory (1.Bid Docs in the bid root)
        default_dir = ""
        if workbook_path:
            # workbook_path is like: Bid_2025-001/4.Workbooks/Schedule_Workbook
            # We need to go up to the bid root to find 1.Bid Docs
            bid_root = workbook_path.parent.parent  # Go up two levels
            bid_docs = bid_root / "1.Bid Docs"
            if bid_docs.exists() and bid_docs.is_dir():
                default_dir = str(bid_docs)
            else:
                # Backward compatibility for older folder naming
                legacy_bid_docs = bid_root / "1.Bid Docs Folder"
                if legacy_bid_docs.exists() and legacy_bid_docs.is_dir():
                    default_dir = str(legacy_bid_docs)
                else:
                    # Try to create preferred folder if it doesn't exist
                    try:
                        bid_docs.mkdir(exist_ok=True)
                        default_dir = str(bid_docs)
                    except:
                        default_dir = str(bid_root)
        
        # Select PDF file
        pdf_path, _ = QFileDialog.getOpenFileName(
            self,
            "Select PDF File",
            default_dir,
            "PDF Files (*.pdf)"
        )
        
        if not pdf_path:
            return
        
        # Import into the currently active tab/table.
        current_widget = tab_widget.currentWidget()
        if isinstance(current_widget, QTabWidget):
            current_widget = current_widget.currentWidget()

        target_entry = None
        if current_widget is not None:
            for widget, csv_path, headers, quoted_col_idx in tables_data:
                if widget is current_widget:
                    target_entry = (widget, csv_path, headers, quoted_col_idx)
                    break

        if target_entry is None and current_widget is not None:
            active_table = self._extract_table_widget(current_widget)
            if active_table is None and isinstance(current_widget, QWidget):
                table_children = current_widget.findChildren(QTableWidget)
                if table_children:
                    active_table = next((t for t in table_children if t.isVisible()), table_children[0])

            if active_table is not None:
                for widget, csv_path, headers, quoted_col_idx in tables_data:
                    table_widget = self._extract_table_widget(widget)
                    if table_widget is active_table:
                        target_entry = (widget, csv_path, headers, quoted_col_idx)
                        break

        if target_entry is None:
            QMessageBox.warning(self, "Import from PDF", "Could not determine the active table tab.")
            return

        target_widget, csv_path, headers, quoted_col_idx = target_entry
        current_table = self._extract_table_widget(target_widget)
        if current_table is None:
            QMessageBox.warning(self, "Import from PDF", "Current tab does not support PDF table import.")
            return
        
        # Try to extract tables with pdfplumber first
        extracted_data = None
        page_num = 1  # Default page number
        if HAS_PDFPLUMBER:
            try:
                with pdfplumber.open(pdf_path) as pdf:
                    # Ask user which page
                    if len(pdf.pages) > 1:
                        page_num = self._select_pdf_page_visual(pdf_path, len(pdf.pages))
                        if page_num is None:
                            return
                    else:
                        page_num = 1
                    
                    page = pdf.pages[page_num - 1]
                    tables = page.extract_tables()
                    
                    if tables:
                        # Flag to track if user wants manual OCR selection
                        use_ocr_manual = False
                        table_idx: int | None = None
                        
                        # Let user pick which table if multiple
                        if len(tables) > 1:
                            # Show visual selection
                            table_bboxes = []
                            for table_obj in page.find_tables():
                                bbox = table_obj.bbox  # (x0, top, x1, bottom)
                                table_bboxes.append(bbox)
                            
                            # Convert page to image for visual selection
                            visual_selection_worked = False
                            if HAS_OCR:  # pdf2image is part of HAS_OCR
                                try:
                                    # Use lower DPI for faster rendering (100 instead of 150)
                                    images = convert_from_path(
                                        pdf_path,
                                        first_page=page_num,
                                        last_page=page_num,
                                        dpi=100,
                                        poppler_path=get_poppler_path(),  # type: ignore[arg-type]
                                    )
                                    if images:
                                        image = images[0]
                                        
                                        # Convert PIL image to QPixmap (optimized)
                                        pixmap = self._pil_to_qpixmap(image)
                                        
                                        # Don't scale down too aggressively - keep at least 1200px width for visibility
                                        max_width, max_height = clamped_size(1400, 1000, margin=80)
                                        if pixmap.width() > max_width or pixmap.height() > max_height:
                                            pixmap = pixmap.scaled(max_width, max_height, Qt.AspectRatioMode.KeepAspectRatio, Qt.TransformationMode.SmoothTransformation)
                                        
                                        # Show selection dialog
                                        dlg = QDialog(self)
                                        dlg.setWindowTitle("Select Table")
                                        dlg.resize(*clamped_size(1400, 1000))
                                        layout = QVBoxLayout(dlg)
                                        label = QLabel(f"Click on the table you want to import ({len(tables)} tables found):")
                                        layout.addWidget(label)
                                        
                                        # Add zoom controls
                                        zoom_layout = QHBoxLayout()
                                        zoom_label = QLabel("Zoom:")
                                        btn_zoom_out = QPushButton("-")
                                        btn_zoom_out.setMaximumWidth(40)
                                        zoom_level_label = QLabel("100%")
                                        zoom_level_label.setMinimumWidth(50)
                                        zoom_level_label.setAlignment(Qt.AlignmentFlag.AlignCenter)
                                        btn_zoom_in = QPushButton("+")
                                        btn_zoom_in.setMaximumWidth(40)
                                        btn_zoom_fit = QPushButton("Fit")
                                        btn_zoom_fit.setMaximumWidth(60)
                                        
                                        zoom_layout.addWidget(zoom_label)
                                        zoom_layout.addWidget(btn_zoom_out)
                                        zoom_layout.addWidget(zoom_level_label)
                                        zoom_layout.addWidget(btn_zoom_in)
                                        zoom_layout.addWidget(btn_zoom_fit)
                                        zoom_layout.addStretch()
                                        layout.addLayout(zoom_layout)
                                        
                                        selector = TableSelectionWidget(pixmap, table_bboxes, page.width, page.height)
                                        scroll = QScrollArea()
                                        scroll.setWidget(selector)
                                        scroll.setWidgetResizable(False)
                                        selector.set_scroll_area(scroll)  # Set reference for dynamic alignment
                                        layout.addWidget(scroll)
                                        
                                        # Zoom control functions
                                        current_zoom = [1.0]
                                        
                                        def update_zoom(zoom):
                                            current_zoom[0] = zoom
                                            selector.set_zoom(zoom)
                                            zoom_level_label.setText(f"{int(zoom * 100)}%")
                                        
                                        # Initialize with proper alignment
                                        update_zoom(1.0)
                                        
                                        def zoom_in():
                                            new_zoom = min(current_zoom[0] + 0.25, 3.0)
                                            update_zoom(new_zoom)
                                        
                                        def zoom_out():
                                            new_zoom = max(current_zoom[0] - 0.25, 0.25)
                                            update_zoom(new_zoom)
                                        
                                        def zoom_fit():
                                            update_zoom(1.0)
                                        
                                        btn_zoom_in.clicked.connect(zoom_in)
                                        btn_zoom_out.clicked.connect(zoom_out)
                                        btn_zoom_fit.clicked.connect(zoom_fit)
                                        
                                        # Add buttons including "Use OCR Instead"
                                        btn_box = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
                                        btn_ocr = QPushButton("Use OCR Instead")
                                        btn_ocr.setToolTip("Skip table detection and manually select a region")
                                        btn_box.addButton(btn_ocr, QDialogButtonBox.ButtonRole.ActionRole)
                                        
                                        use_ocr_instead = [False]  # Use list to capture in lambda
                                        def on_ocr_clicked():
                                            use_ocr_instead[0] = True
                                            dlg.accept()
                                        
                                        btn_ocr.clicked.connect(on_ocr_clicked)
                                        btn_box.accepted.connect(dlg.accept)
                                        btn_box.rejected.connect(dlg.reject)
                                        layout.addWidget(btn_box)
                                        
                                        if dlg.exec() == QDialog.DialogCode.Accepted:
                                            if use_ocr_instead[0]:
                                                # User wants to use OCR instead
                                                visual_selection_worked = "use_ocr"
                                            else:
                                                table_idx = selector.get_selected_index()
                                                if table_idx is None:
                                                    QMessageBox.warning(self, "No Selection", "Please click on a table to select it.")
                                                    return
                                                table_idx += 1  # Convert to 1-based
                                                visual_selection_worked = True
                                        else:
                                            return
                                except Exception as e:
                                    error_msg = str(e)
                                    extra_info = ""
                                    if "poppler" in error_msg.lower() or "Unable to get page count" in error_msg:
                                        extra_info = "\n\nGORO normally includes Poppler automatically. If this is the installed app, reinstall GORO. For development, install Poppler or add its bin folder to PATH."
                                    
                                    QMessageBox.information(
                                        self,
                                        "Visual Selection Unavailable",
                                        f"Could not show visual table selection:\n{error_msg}\n\n"
                                        "Falling back to numbered selection.\n\n"
                                        "To enable visual selection, make sure the PDF/OCR libraries are available:\n"
                                        f"pip install pdf2image pytesseract Pillow{extra_info}"
                                    )
                            
                            # Check if user wants OCR instead
                            if visual_selection_worked == "use_ocr":
                                # Skip table extraction, go to OCR
                                use_ocr_manual = True
                            # Fallback to text-based selection if visual didn't work
                            elif not visual_selection_worked:
                                table_idx, ok = QInputDialog.getInt(
                                    self,
                                    "Select Table",
                                    f"Found {len(tables)} tables on page {page_num}. Which one?\n(Enter 0 to use OCR region selection instead)",
                                    1, 0, len(tables)
                                )
                                if not ok:
                                    return
                                if table_idx == 0:
                                    # User wants OCR instead
                                    use_ocr_manual = True
                        else:
                            # Single table found - ask if user wants to use it or OCR instead
                            if HAS_OCR:
                                msg_box = QMessageBox(self)
                                msg_box.setWindowTitle("Table Detected")
                                msg_box.setText(f"One table detected on page {page_num}.")
                                msg_box.setInformativeText("Would you like to use the detected table or manually select a region?")
                                btn_use_table = msg_box.addButton("Use Detected Table", QMessageBox.ButtonRole.AcceptRole)
                                btn_use_ocr = msg_box.addButton("Select Region (OCR)", QMessageBox.ButtonRole.RejectRole)
                                msg_box.setDefaultButton(btn_use_table)
                                
                                msg_box.exec()
                                
                                if msg_box.clickedButton() == btn_use_ocr:
                                    use_ocr_manual = True
                                else:
                                    table_idx = 1
                            else:
                                table_idx = 1
                        
                        # Extract table data unless user requested manual OCR
                        if not use_ocr_manual and table_idx is not None:
                            extracted_data = tables[table_idx - 1]
                            QMessageBox.information(
                                self,
                                "Table Found",
                                f"Successfully extracted table with {len(extracted_data)} rows."
                            )
            except Exception as e:
                QMessageBox.warning(
                    self,
                    "Text Extraction Failed",
                    f"Could not extract tables from PDF:\n{e}\n\nWill try OCR instead."
                )
        
        # If text extraction failed, try OCR
        if extracted_data is None and HAS_OCR and page_num is not None:
            extracted_data = self._ocr_pdf_region(pdf_path, page_num)
            if extracted_data is None:
                return
        
        if extracted_data is None:
            QMessageBox.warning(
                self,
                "Import Failed",
                "Could not extract data from PDF. Please install required libraries:\n"
                "pip install pdfplumber pdf2image pytesseract"
            )
            return

        # Normalize extracted table shape to avoid collapsed single-column imports
        extracted_data = self._normalize_pdf_table_data(extracted_data, len(headers))
        
        # Show column mapping dialog
        mapped_data = self._map_pdf_columns(extracted_data, headers)
        if mapped_data is None:
            return
        
        # Check for duplicate mark numbers
        mapped_data = self._check_duplicate_marks(current_table, mapped_data, headers)
        if mapped_data is None:
            return
        
        # Import the data into the table
        self._import_mapped_data(current_table, mapped_data, headers)
        mark_changed_callback()
        
        QMessageBox.information(
            self,
            "Import Complete",
            f"Successfully imported {len(mapped_data)} rows."
        )

    def import_from_spreadsheet(self, tab_widget, tables_data, mark_changed_callback, workbook_path):
        """Import table data from CSV/Excel files into the active Schedule table."""
        default_dir = ""
        if workbook_path:
            bid_root = workbook_path.parent.parent
            bid_docs = bid_root / "1.Bid Docs"
            if bid_docs.exists() and bid_docs.is_dir():
                default_dir = str(bid_docs)
            else:
                legacy_bid_docs = bid_root / "1.Bid Docs Folder"
                if legacy_bid_docs.exists() and legacy_bid_docs.is_dir():
                    default_dir = str(legacy_bid_docs)
                else:
                    try:
                        bid_docs.mkdir(exist_ok=True)
                        default_dir = str(bid_docs)
                    except Exception:
                        default_dir = str(bid_root)

        file_path, _ = QFileDialog.getOpenFileName(
            self,
            "Select Spreadsheet File",
            default_dir,
            "Spreadsheet Files (*.csv *.xlsx *.xls *.xlsm);;CSV Files (*.csv);;Excel Files (*.xlsx *.xls *.xlsm)"
        )
        if not file_path:
            return

        current_widget = tab_widget.currentWidget()
        if isinstance(current_widget, QTabWidget):
            current_widget = current_widget.currentWidget()

        target_entry = None
        if current_widget is not None:
            for widget, csv_path, headers, quoted_col_idx in tables_data:
                if widget is current_widget:
                    target_entry = (widget, csv_path, headers, quoted_col_idx)
                    break

        if target_entry is None and current_widget is not None:
            active_table = self._extract_table_widget(current_widget)
            if active_table is None and isinstance(current_widget, QWidget):
                table_children = current_widget.findChildren(QTableWidget)
                if table_children:
                    active_table = next((t for t in table_children if t.isVisible()), table_children[0])

            if active_table is not None:
                for widget, csv_path, headers, quoted_col_idx in tables_data:
                    table_widget = self._extract_table_widget(widget)
                    if table_widget is active_table:
                        target_entry = (widget, csv_path, headers, quoted_col_idx)
                        break

        if target_entry is None:
            QMessageBox.warning(self, "Import Spreadsheet", "Could not determine the active table tab.")
            return

        target_widget, csv_path, headers, quoted_col_idx = target_entry
        current_table = self._extract_table_widget(target_widget)
        if current_table is None:
            QMessageBox.warning(self, "Import Spreadsheet", "Current tab does not support spreadsheet import.")
            return

        extracted_data = self._read_spreadsheet_import_data(file_path)
        if not extracted_data:
            return

        extracted_data = self._normalize_pdf_table_data(extracted_data, len(headers))

        mapped_data = self._map_pdf_columns(extracted_data, headers, source_label="Spreadsheet")
        if mapped_data is None:
            return

        mapped_data = self._check_duplicate_marks(current_table, mapped_data, headers)
        if mapped_data is None:
            return

        self._import_mapped_data(current_table, mapped_data, headers)
        mark_changed_callback()

        QMessageBox.information(
            self,
            "Import Complete",
            f"Successfully imported {len(mapped_data)} rows."
        )

    def _read_spreadsheet_import_data(self, file_path: str):
        """Read rows from CSV or Excel for Schedule import."""
        path = Path(file_path)
        suffix = path.suffix.lower()

        try:
            if suffix == ".csv":
                for encoding in ("utf-8-sig", "utf-8", "cp1252"):
                    try:
                        with open(path, "r", newline="", encoding=encoding) as f:
                            rows = [list(row) for row in csv.reader(f)]
                        break
                    except UnicodeDecodeError:
                        continue
                else:
                    QMessageBox.warning(self, "Import Spreadsheet", "Could not read CSV encoding.")
                    return None

            elif suffix in (".xlsx", ".xlsm"):
                try:
                    from openpyxl import load_workbook
                except Exception:
                    QMessageBox.warning(
                        self,
                        "Import Spreadsheet",
                        "Excel import requires openpyxl. Install with:\npip install openpyxl"
                    )
                    return None

                wb = load_workbook(filename=str(path), read_only=True, data_only=True)
                ws = wb.active
                rows = []
                for row in ws.iter_rows(values_only=True):
                    rows.append(["" if cell is None else str(cell) for cell in row])
                wb.close()

            elif suffix == ".xls":
                try:
                    import xlrd
                except Exception:
                    QMessageBox.warning(
                        self,
                        "Import Spreadsheet",
                        "Legacy .xls import requires xlrd. Install with:\npip install xlrd\n\n"
                        "Or save the file as .xlsx/.csv and import again."
                    )
                    return None

                book = xlrd.open_workbook(str(path))
                sheet = book.sheet_by_index(0)
                rows = []
                for row_idx in range(sheet.nrows):
                    row_values = []
                    for col_idx in range(sheet.ncols):
                        cell_val = sheet.cell_value(row_idx, col_idx)
                        row_values.append("" if cell_val is None else str(cell_val))
                    rows.append(row_values)

            else:
                QMessageBox.warning(self, "Import Spreadsheet", "Unsupported file type. Use CSV or Excel files.")
                return None

            if not rows:
                QMessageBox.warning(self, "Import Spreadsheet", "No data was found in the selected file.")
                return None

            if len(rows) < 2:
                QMessageBox.warning(self, "Import Spreadsheet", "File must include at least a header row and one data row.")
                return None

            # Expand rows where cells contain embedded newlines (multi-line cells in Excel/CSV)
            # e.g. a cell "08-211B\n8000\n8003" becomes three separate rows.
            expanded = []
            for row in rows:
                # Normalize line endings inside each cell, then split
                split_cells = [
                    cell.replace('\r\n', '\n').replace('\r', '\n').split('\n')
                    for cell in row
                ]
                n_sub = max((len(parts) for parts in split_cells), default=1)
                if n_sub <= 1:
                    expanded.append(row)
                else:
                    for i in range(n_sub):
                        new_row = [
                            parts[i].strip() if i < len(parts) else ''
                            for parts in split_cells
                        ]
                        # Skip entirely blank sub-rows (trailing newlines in a cell)
                        if any(v for v in new_row):
                            expanded.append(new_row)
            rows = expanded

            return rows
        except Exception as e:
            QMessageBox.warning(self, "Import Spreadsheet", f"Could not read spreadsheet:\n{e}")
            return None

    def _normalize_pdf_table_data(self, pdf_data, expected_cols: int | None = None):
        """Normalize extracted PDF rows so collapsed one-cell rows can be split into columns."""
        if not pdf_data:
            return pdf_data

        normalized = []
        for row in pdf_data:
            if isinstance(row, (list, tuple)):
                normalized.append(["" if cell is None else str(cell) for cell in row])
            elif row is None:
                normalized.append([""])
            else:
                normalized.append([str(row)])

        # Detect tables where extraction collapsed each row into a single cell
        row_lengths = [len(r) for r in normalized if r is not None]
        if not row_lengths:
            return normalized

        mostly_single_column = max(row_lengths, default=0) <= 1
        if not mostly_single_column:
            return normalized

        split_rows = []
        max_split_cols = 0
        for row in normalized:
            text = row[0].strip() if row and row[0] else ""
            if not text:
                split = [""]
            else:
                # Common collapsed formats: tab-separated, 2+ spaces, or pipe-separated
                split = [part.strip() for part in re.split(r"\t+|\s{2,}|\s*\|\s*", text) if part.strip()]
                if not split:
                    split = [text]
            max_split_cols = max(max_split_cols, len(split))
            split_rows.append(split)

        # Only replace if we actually recovered multiple columns
        if max_split_cols <= 1:
            return normalized

        # If expected columns are known, prefer only reasonable splits
        if expected_cols and expected_cols > 1 and max_split_cols > (expected_cols * 3):
            return normalized

        return split_rows
    
    def _select_pdf_page_visual(self, pdf_path, num_pages):
        """Show visual page previews and let user select which page to import from."""
        if not HAS_OCR:
            # Fallback to text input if pdf2image not available
            page_num, ok = QInputDialog.getInt(
                self,
                "Select Page",
                f"PDF has {num_pages} pages. Which page contains the table?",
                1, 1, num_pages
            )
            return page_num if ok else None
        
        # First, ask user if they know the page number or want to see previews
        dlg = QDialog(self)
        dlg.setWindowTitle("Select Page")
        dlg.resize(400, 200)
        
        layout = QVBoxLayout(dlg)
        label = QLabel(f"This PDF has {num_pages} pages.\n\nHow would you like to select the page?")
        label.setWordWrap(True)
        layout.addWidget(label)
        
        # Option buttons
        btn_input = QPushButton("Enter Page Number")
        btn_input.setToolTip("Quickly enter the page number if you know it")
        btn_preview = QPushButton("Show Visual Thumbnails")
        btn_preview.setToolTip("Generate previews of all pages (may take time for large PDFs)")
        btn_cancel = QPushButton("Cancel")
        
        layout.addWidget(btn_input)
        layout.addWidget(btn_preview)
        layout.addWidget(btn_cancel)
        
        result: list[str | None] = [None]  # Use list to capture in lambda
        
        def on_input():
            result[0] = "input"
            dlg.accept()
        
        def on_preview():
            result[0] = "preview"
            dlg.accept()
        
        btn_input.clicked.connect(on_input)
        btn_preview.clicked.connect(on_preview)
        btn_cancel.clicked.connect(dlg.reject)
        
        if dlg.exec() != QDialog.DialogCode.Accepted:
            return None
        
        # Handle user choice
        if result[0] == "input":
            page_num, ok = QInputDialog.getInt(
                self,
                "Enter Page Number",
                f"Enter the page number (1-{num_pages}):",
                1, 1, num_pages
            )
            return page_num if ok else None
        
        # Show visual previews (with background processing)
        return self._select_pdf_page_thumbnails(pdf_path, num_pages)
    
    def _select_pdf_page_thumbnails(self, pdf_path, num_pages):
        """Show visual page previews and let user select which page to import from."""
        # Show progress dialog (non-modal to allow processing)
        progress_dlg = QDialog(self)
        progress_dlg.setWindowTitle("Loading Preview")
        progress_dlg.resize(400, 150)
        progress_dlg.setModal(True)
        
        progress_layout = QVBoxLayout(progress_dlg)
        progress_label = QLabel(f"Generating thumbnails for {num_pages} pages...\nPlease wait, this may take a moment.")
        progress_label.setWordWrap(True)
        progress_layout.addWidget(progress_label)
        
        progress_status = QLabel("Starting...")
        progress_layout.addWidget(progress_status)
        
        # Store result
        result_data = {'images': None, 'error': None}
        
        # Create worker thread for PDF conversion
        worker = PDFConversionWorker(pdf_path, 30)  # DPI=30 for fast thumbnails
        
        def on_progress(msg):
            progress_status.setText(msg)
            QApplication.processEvents()  # Keep UI responsive
        
        def on_finished(images):
            result_data['images'] = images
            progress_dlg.close()
        
        def on_error(error):
            result_data['error'] = error
            progress_dlg.close()
        
        worker.progress.connect(on_progress)
        worker.finished.connect(on_finished)
        worker.error.connect(on_error)
        
        # Start worker
        worker.start()
        
        # Show dialog and wait (this blocks but allows events to process)
        progress_dlg.exec()
        
        # Ensure thread is finished
        if worker.isRunning():
            worker.wait()
        
        # Check for errors
        if result_data['error']:
            QMessageBox.information(
                self,
                "Visual Preview Unavailable",
                f"Could not show page previews:\n{result_data['error']}\n\nFalling back to numbered selection."
            )
            page_num, ok = QInputDialog.getInt(
                self,
                "Select Page",
                f"PDF has {num_pages} pages. Which page contains the table?",
                1, 1, num_pages
            )
            return page_num if ok else None
        
        if not result_data['images']:
            # Fallback to text input
            page_num, ok = QInputDialog.getInt(
                self,
                "Select Page",
                f"PDF has {num_pages} pages. Which page contains the table?",
                1, 1, num_pages
            )
            return page_num if ok else None
        
        # Create dialog
        dlg = QDialog(self)
        dlg.setWindowTitle("Select Page")
        dlg.resize(*clamped_size(1000, 700))
        
        layout = QVBoxLayout(dlg)
        label = QLabel(f"Select the page containing the table you want to import ({num_pages} pages):")
        layout.addWidget(label)
        
        # Create scroll area for page previews
        scroll = QScrollArea()
        scroll.setWidgetResizable(True)
        scroll_widget = QWidget()
        grid_layout = QGridLayout(scroll_widget)
        grid_layout.setSpacing(10)
        
        # Store page widgets
        page_widgets = []
        selected_page = [None]  # Use list to allow modification in nested function
        
        def on_page_clicked(page_num):
            # Deselect all
            for pw in page_widgets:
                pw.set_selected(False)
            # Select clicked
            page_widgets[page_num - 1].set_selected(True)
            selected_page[0] = page_num
        
        # Create preview for each page (4 columns per row)
        cols_per_row = 4
        for i, image in enumerate(result_data['images']):
            page_num = i + 1
            row = i // cols_per_row
            col = i % cols_per_row
            
            # Convert PIL image to QPixmap (optimized conversion)
            pixmap = self._pil_to_qpixmap(image)
            
            # Create page widget container
            page_container = QWidget()
            page_layout = QVBoxLayout(page_container)
            page_layout.setContentsMargins(0, 0, 0, 0)
            page_layout.setSpacing(5)
            
            # Create preview widget
            preview = PagePreviewWidget(page_num, pixmap)
            preview.mousePressEvent = lambda ev, pn=page_num: on_page_clicked(pn)
            page_widgets.append(preview)
            
            # Add page number label
            page_label = QLabel(f"Page {page_num}")
            page_label.setAlignment(Qt.AlignmentFlag.AlignCenter)
            page_label.setStyleSheet("color: #cccccc; font-weight: bold;")
            
            page_layout.addWidget(preview)
            page_layout.addWidget(page_label)
            
            grid_layout.addWidget(page_container, row, col)
        
        scroll.setWidget(scroll_widget)
        layout.addWidget(scroll)
        
        # Buttons
        btn_box = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
        btn_box.accepted.connect(dlg.accept)
        btn_box.rejected.connect(dlg.reject)
        layout.addWidget(btn_box)
        
        if dlg.exec() == QDialog.DialogCode.Accepted:
            if selected_page[0] is None:
                QMessageBox.warning(self, "No Selection", "Please click on a page to select it.")
                return None
            return selected_page[0]
        else:
            return None
    
    def _pil_to_qpixmap(self, pil_image):
        """Efficiently convert PIL image to QPixmap."""
        # Convert to RGB if needed
        if pil_image.mode != 'RGB':
            pil_image = pil_image.convert('RGB')
        
        # Use tobytes for efficient conversion
        img_data = pil_image.tobytes('raw', 'RGB')
        qimage = QImage(
            img_data,
            pil_image.width,
            pil_image.height,
            pil_image.width * 3,
            QImage.Format.Format_RGB888
        )
        return QPixmap.fromImage(qimage)
    
    def _ocr_pdf_region(self, pdf_path: str, page_num: int = 1):
        """Use OCR to extract table from user-selected region of PDF."""
        try:
            configure_tesseract(self.settings)

            # Convert specified page to image
            images = convert_from_path(
                pdf_path,
                first_page=page_num,
                last_page=page_num,
                dpi=150,
                poppler_path=get_poppler_path(),  # type: ignore[arg-type]
            )
            if not images:
                QMessageBox.warning(self, "OCR Error", "Could not convert PDF to image.")
                return None
            
            image = images[0]
            
            # Show image and let user select region
            dlg = QDialog(self)
            dlg.setWindowTitle(f"Select Table Region - Page {page_num}")
            dlg.resize(*clamped_size(900, 700))
            
            layout = QVBoxLayout(dlg)
            label = QLabel(f"Draw a rectangle around the table you want to import from page {page_num}:")
            layout.addWidget(label)
            
            # Convert PIL image to QPixmap (optimized)
            original_pixmap = self._pil_to_qpixmap(image)
            pixmap = original_pixmap

            # Scale pixmap if too large (keep track of scale for coordinate mapping)
            _img_w, _img_h = clamped_size(850, 600, margin=120)
            if pixmap.width() > _img_w or pixmap.height() > _img_h:
                pixmap = pixmap.scaled(_img_w, _img_h, Qt.AspectRatioMode.KeepAspectRatio, Qt.TransformationMode.SmoothTransformation)
            
            # Create selection widget
            selector = ImageRegionSelection(pixmap)
            layout.addWidget(selector)
            
            btn_row = QHBoxLayout()
            btn_ok = QPushButton("Extract")
            btn_cancel = QPushButton("Cancel")
            btn_ok.clicked.connect(dlg.accept)
            btn_cancel.clicked.connect(dlg.reject)
            btn_row.addWidget(btn_ok)
            btn_row.addWidget(btn_cancel)
            layout.addLayout(btn_row)
            
            if dlg.exec() != QDialog.DialogCode.Accepted:
                return None
            
            rect = selector.get_selection()
            if rect is None:
                QMessageBox.warning(self, "No Selection", "Please select a region first.")
                return None
            
            # Map selection coordinates from displayed pixmap back to original image coordinates
            scale_x = image.width / max(1, pixmap.width())
            scale_y = image.height / max(1, pixmap.height())

            left = max(0, int(rect.x() * scale_x))
            top = max(0, int(rect.y() * scale_y))
            right = min(image.width, int((rect.x() + rect.width()) * scale_x))
            bottom = min(image.height, int((rect.y() + rect.height()) * scale_y))

            if right <= left or bottom <= top:
                QMessageBox.warning(self, "Selection Error", "Invalid selection area. Please try again.")
                return None

            # Crop image to corrected selection
            cropped = image.crop((left, top, right, bottom))
            
            # Perform OCR with better error handling
            try:
                text = pytesseract.image_to_string(cropped)
            except pytesseract.TesseractNotFoundError:
                QMessageBox.critical(
                    self, 
                    "Tesseract Not Found",
                    "GORO could not locate Tesseract OCR.\n\n"
                    "The Windows installer normally includes it automatically. If you are running the installed app, reinstall GORO.\n\n"
                    "You can also set a custom Tesseract executable path in Settings.\n\n"
                    "Development fallback:\n"
                    "Windows: https://github.com/UB-Mannheim/tesseract/wiki\n"
                    "Mac: brew install tesseract\n"
                    "Linux: sudo apt install tesseract-ocr"
                )
                return None
            
            # Parse text into rows and columns
            lines = [line.strip() for line in text.split('\n') if line.strip()]
            table_data = []
            for line in lines:
                # Split by tabs or runs of 2+ spaces for more reliable column detection
                cells = [cell.strip() for cell in re.split(r"\t+|\s{2,}", line) if cell.strip()]
                if cells:
                    table_data.append(cells)
            
            if not table_data:
                QMessageBox.warning(self, "OCR Error", "Could not extract table data from selected region.")
                return None
            
            return table_data
            
        except Exception as e:
            error_msg = str(e)
            if "tesseract" in error_msg.lower() or "not installed" in error_msg.lower():
                QMessageBox.critical(
                    self, 
                    "Tesseract Not Found",
                    "GORO could not locate Tesseract OCR.\n\n"
                    "The Windows installer normally includes it automatically. If you are running the installed app, reinstall GORO.\n\n"
                    "You can also set a custom Tesseract executable path in Settings.\n\n"
                    "Development fallback:\n"
                    "Windows: https://github.com/UB-Mannheim/tesseract/wiki\n"
                    "Mac: brew install tesseract\n"
                    "Linux: sudo apt install tesseract-ocr"
                )
            else:
                QMessageBox.critical(self, "OCR Error", f"OCR failed:\n{error_msg}")
            return None
    
    def _map_pdf_columns(self, pdf_data, csv_headers, source_label: str = "PDF"):
        """Show dialog to map imported columns to Schedule columns."""
        if not pdf_data:
            return None
        
        # Assume first row is headers
        pdf_headers = pdf_data[0] if pdf_data else []
        pdf_rows = pdf_data[1:] if len(pdf_data) > 1 else []
        
        if not pdf_rows:
            QMessageBox.warning(self, "No Data", f"No data rows found in {source_label} table.")
            return None
        
        # Create mapping dialog
        dlg = QDialog(self)
        dlg.setWindowTitle("Map Columns")
        dlg.resize(*clamped_size(700, 600))
        
        layout = QVBoxLayout(dlg)
        label = QLabel(f"Map {source_label} columns to Schedule columns:")
        layout.addWidget(label)
        
        # Create scroll area for mapping interface
        scroll = QScrollArea()
        scroll.setWidgetResizable(True)
        scroll_widget = QWidget()
        mapping_layout = QFormLayout(scroll_widget)
        
        column_combos = []
        
        for i, pdf_col in enumerate(pdf_headers):
            combo = QComboBox()
            combo.addItem("(Skip)")
            for csv_header in csv_headers:
                combo.addItem(csv_header)
            
            # Create label for PDF column
            pdf_col_str = str(pdf_col).strip() if pdf_col else ""
            if not pdf_col_str:
                # If header is blank, find first non-blank cell in this column as hint
                example_cell = ""
                for row in pdf_rows:
                    if i < len(row):
                        cell_value = str(row[i]).strip() if row[i] else ""
                        if cell_value:
                            example_cell = cell_value
                            break
                
                if example_cell:
                    pdf_col_label = f"{source_label}: (blank header) - Example: {example_cell[:50]}"
                else:
                    pdf_col_label = f"{source_label}: (blank header - empty column)"
            else:
                pdf_col_label = f"{source_label}: {pdf_col_str}"
            
            # Try to auto-match if names are similar
            matched = False
            pdf_col_lower = pdf_col_str.lower()
            for j, csv_header in enumerate(csv_headers):
                if pdf_col_lower and pdf_col_lower in csv_header.lower():
                    combo.setCurrentIndex(j + 1)  # +1 because of "(Skip)" option
                    matched = True
                    break

            # Fallback: positional mapping for blank/unclear headers
            if not matched and i < len(csv_headers):
                combo.setCurrentIndex(i + 1)
            
            mapping_layout.addRow(pdf_col_label, combo)
            column_combos.append(combo)
        
        scroll.setWidget(scroll_widget)
        layout.addWidget(scroll)
        
        btn_row = QHBoxLayout()
        btn_ok = QPushButton("Import")
        btn_cancel = QPushButton("Cancel")
        btn_ok.clicked.connect(dlg.accept)
        btn_cancel.clicked.connect(dlg.reject)
        btn_row.addWidget(btn_ok)
        btn_row.addWidget(btn_cancel)
        layout.addLayout(btn_row)
        
        if dlg.exec() != QDialog.DialogCode.Accepted:
            return None
        
        # Build mapped data
        mapped_rows = []
        for pdf_row in pdf_rows:
            csv_row = [""] * len(csv_headers)
            for pdf_col_idx, combo in enumerate(column_combos):
                selected_idx = combo.currentIndex()
                csv_col_idx = selected_idx - 1  # -1 because index 0 is "(Skip)"
                if csv_col_idx >= 0 and pdf_col_idx < len(pdf_row):
                    new_value = str(pdf_row[pdf_col_idx]).strip() if pdf_row[pdf_col_idx] else ""
                    if not new_value:
                        continue

                    # Allow multiple source columns to map into one destination column.
                    if csv_row[csv_col_idx]:
                        csv_row[csv_col_idx] = f"{csv_row[csv_col_idx]}. {new_value}"
                    else:
                        csv_row[csv_col_idx] = new_value
            mapped_rows.append(csv_row)
        
        return mapped_rows
    
    def _check_duplicate_marks(self, table, mapped_data, headers):
        """Check for duplicate opening numbers and prompt user how to handle them."""
        if not mapped_data or not headers:
            return mapped_data

        table_col_offset = 0
        if table.columnCount() == len(headers) + 1:
            table_col_offset = 1
        
        # Find the opening number column index (look for "opening" in header names)
        opening_col_idx = None
        for i, header in enumerate(headers):
            if "opening" in header.lower():
                opening_col_idx = i
                break
        
        if opening_col_idx is None:
            # No opening column found, proceed without checking
            return mapped_data
        
        # Get all existing opening numbers from the table
        existing_openings = set()
        for row_idx in range(table.rowCount()):
            table_col_idx = opening_col_idx + table_col_offset
            if table_col_idx >= table.columnCount():
                continue
            item = table.item(row_idx, table_col_idx)
            if item and item.text().strip():
                existing_openings.add(item.text().strip())
        
        # Find duplicates in mapped_data
        duplicates = []
        for row_idx, row_data in enumerate(mapped_data):
            if opening_col_idx < len(row_data):
                opening_value = row_data[opening_col_idx].strip()
                if opening_value and opening_value in existing_openings:
                    duplicates.append((row_idx, opening_value))
        
        if not duplicates:
            # No duplicates, proceed
            return mapped_data
        
        # Show dialog to handle duplicates
        dlg = QDialog(self)
        dlg.setWindowTitle("Duplicate Opening Numbers Found")
        dlg.resize(500, 300)
        
        layout = QVBoxLayout(dlg)
        
        dup_list = ", ".join([opening for _, opening in duplicates[:5]])
        if len(duplicates) > 5:
            dup_list += f", ... ({len(duplicates)} total)"
        
        label = QLabel(
            f"Found {len(duplicates)} row(s) with existing opening numbers:\n"
            f"{dup_list}\n\n"
            f"How would you like to handle these duplicates?"
        )
        label.setWordWrap(True)
        layout.addWidget(label)
        
        # Radio buttons for options
        btn_group = QButtonGroup(dlg)
        
        rb_replace = QRadioButton("Replace existing rows with new data")
        rb_suffix = QRadioButton("Keep both - add custom suffix to new opening numbers")
        rb_skip = QRadioButton("Skip duplicate rows (don't import them)")
        rb_cancel = QRadioButton("Cancel import")
        
        rb_suffix.setChecked(True)  # Default option
        
        btn_group.addButton(rb_replace)
        btn_group.addButton(rb_suffix)
        btn_group.addButton(rb_skip)
        btn_group.addButton(rb_cancel)
        
        layout.addWidget(rb_replace)
        layout.addWidget(rb_suffix)
        
        # Add suffix input field next to suffix option
        suffix_layout = QHBoxLayout()
        suffix_layout.addSpacing(30)  # Indent
        suffix_label = QLabel("Suffix:")
        suffix_input = QLineEdit("-alt")
        suffix_input.setMaximumWidth(150)
        suffix_input.setPlaceholderText("e.g. -alt, -2, _new")
        suffix_layout.addWidget(suffix_label)
        suffix_layout.addWidget(suffix_input)
        suffix_layout.addStretch()
        layout.addLayout(suffix_layout)
        
        # Enable/disable suffix input based on radio button
        def on_suffix_toggled():
            suffix_input.setEnabled(rb_suffix.isChecked())
        
        rb_suffix.toggled.connect(on_suffix_toggled)
        rb_replace.toggled.connect(on_suffix_toggled)
        rb_skip.toggled.connect(on_suffix_toggled)
        rb_cancel.toggled.connect(on_suffix_toggled)
        
        layout.addWidget(rb_skip)
        layout.addWidget(rb_cancel)
        
        # OK button
        btn_ok = QPushButton("OK")
        btn_ok.clicked.connect(dlg.accept)
        layout.addWidget(btn_ok)
        
        if dlg.exec() != QDialog.DialogCode.Accepted:
            return None
        
        # Handle based on selection
        if rb_cancel.isChecked():
            return None
        
        elif rb_skip.isChecked():
            # Remove duplicate rows
            dup_indices = {idx for idx, _ in duplicates}
            mapped_data = [row for i, row in enumerate(mapped_data) if i not in dup_indices]
            if not mapped_data:
                QMessageBox.information(self, "No Rows to Import", "All rows were duplicates and have been skipped.")
                return None
        
        elif rb_suffix.isChecked():
            # Add custom suffix to duplicate opening numbers
            suffix = suffix_input.text().strip()
            if not suffix:
                suffix = "-alt"  # Default if empty
            
            for row_idx, _ in duplicates:
                if opening_col_idx < len(mapped_data[row_idx]):
                    original_opening = mapped_data[row_idx][opening_col_idx].strip()
                    new_opening = f"{original_opening}{suffix}"
                    
                    # Find unique suffix if collision exists
                    if new_opening in existing_openings:
                        suffix_num = 2
                        new_opening = f"{original_opening}{suffix}{suffix_num}"
                        while new_opening in existing_openings:
                            suffix_num += 1
                            new_opening = f"{original_opening}{suffix}{suffix_num}"
                    
                    mapped_data[row_idx][opening_col_idx] = new_opening
                    existing_openings.add(new_opening)  # Prevent future collisions in this batch
        
        elif rb_replace.isChecked():
            # Find and replace existing rows in the table
            opening_to_row = {}
            for row_idx in range(table.rowCount()):
                table_col_idx = opening_col_idx + table_col_offset
                if table_col_idx >= table.columnCount():
                    continue
                item = table.item(row_idx, table_col_idx)
                if item and item.text().strip():
                    opening_to_row[item.text().strip()] = row_idx
            
            # Separate rows to replace vs rows to add
            rows_to_add = []
            for row_idx, row_data in enumerate(mapped_data):
                if opening_col_idx < len(row_data):
                    opening_value = row_data[opening_col_idx].strip()
                    if opening_value in opening_to_row:
                        # Replace this existing row
                        table_row_idx = opening_to_row[opening_value]
                        table.blockSignals(True)
                        for col_idx, cell_value in enumerate(row_data):
                            table_col_idx = col_idx + table_col_offset
                            if table_col_idx < table.columnCount():
                                item = QTableWidgetItem(cell_value)
                                table.setItem(table_row_idx, table_col_idx, item)
                        table.blockSignals(False)
                    else:
                        rows_to_add.append(row_data)
                else:
                    rows_to_add.append(row_data)
            
            # Return only non-duplicate rows to be added
            mapped_data = rows_to_add
        
        return mapped_data
    
    def _import_mapped_data(self, table, mapped_data, headers=None):
        """Import mapped data rows into the table."""
        if not mapped_data:
            return

        col_offset = 0
        if headers is not None and table.columnCount() == len(headers) + 1:
            col_offset = 1
        else:
            first_header = table.horizontalHeaderItem(0)
            if first_header and first_header.text().strip() == "":
                col_offset = 1

        checkbox_cols = [0] if col_offset == 1 else None

        if col_offset == 1 and table.rowCount() > 0:
            for row_idx in range(table.rowCount()):
                first_item = table.item(row_idx, 0)
                if first_item is None:
                    first_item = QTableWidgetItem("")
                    table.setItem(row_idx, 0, first_item)
                first_item.setFlags(first_item.flags() | Qt.ItemFlag.ItemIsUserCheckable)
                if first_item.checkState() != Qt.CheckState.Checked:
                    first_item.setCheckState(Qt.CheckState.Unchecked)
                first_item.setText("")
        
        # Reuse the existing trailing blank row when present so we don't leave
        # an internal blank row that can desync row-based formula/update logic.
        start_row = table.rowCount()
        if table.rowCount() > 0 and not _table_row_has_content(table, table.rowCount() - 1):
            start_row = table.rowCount() - 1
        
        # Ensure enough rows
        table.setRowCount(start_row + len(mapped_data) + 1)  # +1 for empty trailing row
        
        # Block signals to avoid marking as changed for each cell
        table.blockSignals(True)
        
        for row_offset, row_data in enumerate(mapped_data):
            target_row = start_row + row_offset
            if checkbox_cols:
                for checkbox_col in checkbox_cols:
                    if 0 <= checkbox_col < table.columnCount():
                        checkbox_item = table.item(target_row, checkbox_col)
                        if checkbox_item is None:
                            checkbox_item = QTableWidgetItem("")
                            table.setItem(target_row, checkbox_col, checkbox_item)
                        checkbox_item.setFlags(checkbox_item.flags() | Qt.ItemFlag.ItemIsUserCheckable)
                        if checkbox_item.checkState() != Qt.CheckState.Checked:
                            checkbox_item.setCheckState(Qt.CheckState.Unchecked)
                        checkbox_item.setText("")
            for col_idx, cell_value in enumerate(row_data):
                target_col = col_idx + col_offset
                if target_col < table.columnCount():
                    item = QTableWidgetItem(cell_value)
                    table.setItem(target_row, target_col, item)

        # Default count to 1 for any imported rows where count is empty
        if headers is not None:
            count_col = None
            for idx, h in enumerate(headers):
                if h.strip().lower() in ("count", "qty", "quantity"):
                    count_col = idx
                    break
            if count_col is not None:
                for row_offset in range(len(mapped_data)):
                    target_row = start_row + row_offset
                    target_col = count_col + col_offset
                    item = table.item(target_row, target_col)
                    if item is None or not item.text().strip():
                        table.setItem(target_row, target_col, QTableWidgetItem("1"))
        
        table.blockSignals(False)

        table.blockSignals(True)
        _ensure_single_trailing_blank_row(table, checkbox_cols)
        table.blockSignals(False)

    def create_item(self):
        if self.current_category == "bids":
            base_dir = self.paths.bids
            suggested = next_increment_name(base_dir, self.name_templates["bids"], "bids")
            dlg = CreateBidDialog(
                self,
                default_name=suggested,
                default_status="Pending",
                estimators=self.estimators_list,
                customers=self.customers_info,
                customer_contacts=self.customers_contacts,
                customer_manager_callback=self._open_customers_from_create_bid,
            )
            if dlg.exec() != QDialog.DialogCode.Accepted:
                return
            name, status, estimator, due_str, gc, poc, proposal_type, address, project_info = dlg.values()

            # Sanitize the name by removing invalid characters
            original_name = name
            name = sanitize_name(name)
            
            if not name:
                QMessageBox.warning(self, "Invalid Name", "Name resulted in empty string after removing invalid characters.")
                return

            # Notify user if the name was modified
            if name != original_name:
                QMessageBox.information(self, "Name Sanitized", f"Invalid characters removed.\nOriginal: {original_name}\nSanitized: {name}")

            dest_dir = base_dir / name
            if dest_dir.exists():
                QMessageBox.warning(self, "Exists", f"“{name}” already exists.")
                return

            try:
                dest_dir.mkdir(parents=True, exist_ok=False)
                
                # Copy template if it exists
                template_path = Path(__file__).parent / "data" / "Template"
                copy_template(template_path, dest_dir)
                
                info = {
                    "type": "bid",
                    "name": name,
                    "created_at": now_iso(),
                    "status": status,
                    "estimator": estimator,
                    "due_date": due_str,
                    "gc": gc,
                    "point_of_contact": poc,
                    "proposal_type": proposal_type,
                    "address": address,
                    "project_info": project_info,
                }
                write_info(dest_dir, info)
                self.refresh_list()
                self._select_name_in_list(name)
                self.statusBar().showMessage(f"Created Bid: {name} ({status}, due {due_str})", 6000)
            except Exception as e:
                QMessageBox.critical(self, "Create Failed", f"Could not create bid:\n{e}")

        else:
            name, ok = QInputDialog.getText(self, "Create Project", "Project name:")
            if not ok:
                return

            original_name = name.strip()
            name = sanitize_name(original_name)
            if not name:
                QMessageBox.warning(self, "Invalid Name", "Project name cannot be empty.")
                return

            if name != original_name:
                QMessageBox.information(self, "Name Sanitized", f"Invalid characters removed.\nOriginal: {original_name}\nSanitized: {name}")

            dest_dir = self.paths.projects / name
            if dest_dir.exists():
                QMessageBox.warning(self, "Exists", f"“{name}” already exists.")
                return

            try:
                dest_dir.mkdir(parents=True, exist_ok=False)
                info = {
                    "type": "project",
                    "name": name,
                    "created_at": now_iso(),
                    "status": "Active",
                    "project_manager": str(self.settings.value("username", "") or "").strip(),
                    "project_info": "",
                }
                write_info(dest_dir, info)
                self.refresh_list()
                self._select_name_in_list(name)
                self.statusBar().showMessage(f"Created Project: {name}", 6000)
            except Exception as e:
                QMessageBox.critical(self, "Create Failed", f"Could not create project:\n{e}")

    def rename_item(self):
        item = self.selected_item()
        if not item:
            QMessageBox.information(self, "Rename", "Select an item to rename.")
            return
        old_name = item.text()
        p = self.selected_path()
        if not p:
            return

        new_name, ok = QInputDialog.getText(self, "Rename", f"New name for “{old_name}”:", text=old_name)
        if not ok or new_name == old_name:
            return

        reason = invalid_name_reason(new_name)
        if reason:
            QMessageBox.warning(self, "Invalid Name", reason)
            return

        new_path = p.parent / new_name
        if new_path.exists():
            QMessageBox.warning(self, "Exists", f"“{new_name}” already exists.")
            return

        try:
            p.rename(new_path)
            info = read_info(new_path)
            info["name"] = new_name
            write_info(new_path, info)
            self.refresh_list()
            self._select_name_in_list(new_name)
            self.statusBar().showMessage(f"Renamed to: {new_name}", 5000)
        except Exception as e:
            QMessageBox.critical(self, "Rename Failed", f"Could not rename:\n{e}")

    def delete_item(self):
        item = self.selected_item()
        if not item:
            QMessageBox.information(self, "Delete", "Select an item to delete.")
            return
        p = self.selected_path()
        if not p:
            return

        verb = "Send to Trash" if HAS_SEND2TRASH else "Delete"
        ret = QMessageBox.warning(
            self, verb,
            f"{verb} “{item.text()}” and all its contents?\nThis cannot be undone.",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
            QMessageBox.StandardButton.No
        )
        if ret != QMessageBox.StandardButton.Yes:
            return

        try:
            if HAS_SEND2TRASH:
                send2trash(str(p))
            else:
                shutil.rmtree(p)
            self.refresh_list()
            self.statusBar().showMessage(f"Deleted “{item.text()}”.", 5000)
        except Exception as e:
            QMessageBox.critical(self, "Delete Failed", f"Could not delete:\n{e}")

    def open_item_folder(self):
        p = self.selected_path()
        if not p:
            QMessageBox.information(self, "Open Folder", "Select an item to open.")
            return
        if not p.exists():
            QMessageBox.warning(self, "Missing", "Folder no longer exists.")
            self.refresh_list()
            return
        open_in_file_manager(p)

    def change_status(self):
        if self.current_category != "bids":
            return
        item = self.selected_item()
        if not item:
            QMessageBox.information(self, "Change Status", "Select a Bid.")
            return

        p = self.selected_path()
        current_status = self.selected_status() or (read_info(p).get("status", "Pending") if p else "Pending")
        new_status, ok = QInputDialog.getItem(self, "Change Status", "New Status:",
                                              BID_STATUSES, BID_STATUSES.index(current_status) if current_status in BID_STATUSES else 0, False)
        if not ok or new_status == current_status:
            return

        p = self.selected_path()
        if not p:
            return

        try:
            info = read_info(p)
            previous_status = info.get("status", "")
            info["status"] = new_status
            write_info(p, info)
            self._invalidate_active_metrics_cache(p)
            self._on_bid_status_updated(p, previous_status, new_status)
            self.refresh_list()
            self._select_name_in_list(p.name)
            self.statusBar().showMessage(f"Status changed to {new_status}", 5000)
        except Exception as e:
            QMessageBox.critical(self, "Change Status Failed", f"Could not update status:\n{e}")

    def edit_due_date(self):
        if self.current_category != "bids":
            return
        p = self.selected_path()
        if not p:
            QMessageBox.information(self, "Edit Due Date", "Select a Bid.")
            return

        info = read_info(p)
        current_due = info.get("due_date")
        dlg = EditDueDateDialog(self, current_due=current_due)
        if dlg.exec() != QDialog.DialogCode.Accepted:
            return
        new_due = dlg.value()
        info["due_date"] = new_due
        write_info(p, info)
        self.refresh_list()
        self.statusBar().showMessage(f"Due date set to {new_due}", 5000)

    def promote_to_project(self):
        p = self.selected_path()
        if not p:
            QMessageBox.information(self, "Promote to Project", "Select a Bid to promote.")
            return

        if not self._prepare_bid_for_project_promotion(p):
            return

        try:
            project_path = self._convert_bid_to_project(p)
        except Exception as e:
            QMessageBox.warning(self, "Promote to Project", f"Could not promote bid to project:\n{e}")
            return

        self.current_category = "projects"
        self._current_editing_path = project_path
        self._update_category_ui()
        self.refresh_list()
        self._select_path_in_list(project_path)
        self.statusBar().showMessage(f"Promoted to Project: {project_path.name}", 6000)

    def duplicate_item(self):
        item = self.selected_item()
        if not item:
            QMessageBox.information(self, "Duplicate", "Select an item to duplicate.")
            return

        src = self.selected_path()
        if not src:
            return
        base_dir = src.parent
        suggested = available_copy_name(base_dir, src.name)

        new_name, ok = QInputDialog.getText(self, "Duplicate", "New name for the copy:", text=suggested)
        if not ok:
            return

        reason = invalid_name_reason(new_name)
        if reason:
            QMessageBox.warning(self, "Invalid Name", reason)
            return

        dst = base_dir / new_name
        if dst.exists():
            QMessageBox.warning(self, "Exists", f"A folder named “{new_name}” already exists.")
            return

        try:
            shutil.copytree(src, dst)
            # Update info.json in the copy
            info = read_info(dst)
            info["name"] = new_name
            info["type"] = "bid" if self.current_category == "bids" else "project"
            info["created_at"] = now_iso()
            info["status"] = self._normalize_status_for_current_category(self.lbl_status.currentText().strip())
            write_info(dst, info)

            self.refresh_list()
            self._select_name_in_list(new_name)
            self.statusBar().showMessage(f"Duplicated to “{new_name}”", 6000)
        except Exception as e:
            QMessageBox.critical(self, "Duplicate Failed", f"Could not duplicate:\n{e}")

    # ---------- Door Type Generation ----------

    def _generate_door_types(self, table: QTableWidget, door_type_col: int, headers: List[str], change_callback):
        """Generate door type strings from related columns (VBA ConcatenateDoors replication)."""
        popup_owner = _resolve_transient_parent(table if isinstance(table, QWidget) else self)
        # Show dialog to choose scope
        scope_dlg = QDialog(popup_owner)
        scope_dlg.setWindowTitle("Generate Door Types")
        scope_dlg.resize(400, 200)
        
        layout = QVBoxLayout(scope_dlg)
        layout.addWidget(QLabel("Which rows should be updated?"))
        
        btn_group = QButtonGroup(scope_dlg)
        rb_all = QRadioButton("All rows")
        rb_blanks = QRadioButton("Blank cells only")
        rb_filtered = QRadioButton("Currently visible rows (from filter)")
        
        rb_blanks.setChecked(True)  # Default
        
        btn_group.addButton(rb_all)
        btn_group.addButton(rb_blanks)
        btn_group.addButton(rb_filtered)
        
        layout.addWidget(rb_all)
        layout.addWidget(rb_blanks)
        layout.addWidget(rb_filtered)
        
        btn_box = QHBoxLayout()
        btn_ok = QPushButton("Generate")
        btn_cancel = QPushButton("Cancel")
        btn_ok.clicked.connect(scope_dlg.accept)
        btn_cancel.clicked.connect(scope_dlg.reject)
        btn_box.addWidget(btn_ok)
        btn_box.addWidget(btn_cancel)
        layout.addLayout(btn_box)
        
        if scope_dlg.exec() != QDialog.DialogCode.Accepted:
            return
        
        # Determine which rows to process
        rows_to_process = []
        for r in range(table.rowCount()):
            # Skip empty rows
            has_content = False
            for c in range(table.columnCount()):
                item = table.item(r, c)
                if item and item.text().strip():
                    has_content = True
                    break
            
            if not has_content:
                continue
            
            # Check scope
            if rb_all.isChecked():
                rows_to_process.append(r)
            elif rb_blanks.isChecked():
                door_type_item = table.item(r, door_type_col)
                if not door_type_item or not door_type_item.text().strip():
                    rows_to_process.append(r)
            elif rb_filtered.isChecked():
                if not table.isRowHidden(r):
                    rows_to_process.append(r)
        
        if not rows_to_process:
            QMessageBox.information(popup_owner, "Generate Door Types", "No rows match the selected criteria.")
            return
        
        # Process each row
        table.blockSignals(True)
        processed_count = 0
        
        for r in rows_to_process:
            try:
                # Get values from columns relative to Door Type column
                # Based on VBA: cell.Offset(0, -5), cell.Offset(0, -4), etc.
                def get_val(offset):
                    col_idx = door_type_col + offset
                    if 0 <= col_idx < table.columnCount():
                        item = table.item(r, col_idx)
                        if item and item.text().strip():
                            return item.text().strip()
                    return ""
                
                # Build the door type string using VBA logic
                parts = []
                
                # cell.Offset(0, -5)
                parts.append(get_val(-5))
                
                # cell.Offset(0, -4)
                parts.append(get_val(-4))
                
                # cell.Offset(0, -3)
                parts.append(get_val(-3))
                
                # cell.Offset(0, -2) - optional, only if not empty
                val_minus_2 = get_val(-2)
                if val_minus_2:
                    parts.append(val_minus_2)
                
                # cell.Offset(0, -1)
                parts.append(get_val(-1))
                
                # cell.Offset(0, -10) & cell.Offset(0, -9) - concatenated without separator
                combined = get_val(-10) + get_val(-9)
                if combined:
                    parts.append(combined)
                
                # cell.Offset(0, -7) - optional, exclude if "NR", "NA", or empty
                val_minus_7 = get_val(-7)
                if val_minus_7 and val_minus_7.upper() not in ("NR", "NA"):
                    parts.append(val_minus_7)
                
                # cell.Offset(0, -6) - optional, exclude if "NR", "NA", or empty, adds ".STC" prefix
                val_minus_6 = get_val(-6)
                if val_minus_6 and val_minus_6.upper() not in ("NR", "NA"):
                    parts.append(f"STC{val_minus_6}")
                
                # Join with "."
                result = ".".join(parts)
                
                # Clean up the result (matching VBA logic)
                result = result.replace(" ", "")
                result = result.replace("'", "")
                result = result.replace("-", "")
                result = result.replace('"', "")
                
                # Remove consecutive ".."
                while ".." in result:
                    result = result.replace("..", ".")
                
                # Remove leading "."
                if result.startswith("."):
                    result = result[1:]
                
                # Set the value
                door_type_item = table.item(r, door_type_col)
                if door_type_item is None:
                    door_type_item = QTableWidgetItem(result)
                    table.setItem(r, door_type_col, door_type_item)
                else:
                    door_type_item.setText(result)
                
                processed_count += 1
                
            except Exception as e:
                continue
        
        table.blockSignals(False)
        
        # Mark as changed
        if change_callback and processed_count > 0:
            change_callback()
        
        QMessageBox.information(
            popup_owner,
            "Generate Door Types",
            f"Successfully generated door types for {processed_count} row(s)."
        )

