    def _clean_column_values(self, table: QTableWidget, col: int, headers: List[str], change_callback):
        """Clean column values by removing spaces and quotes (VBA WIDTH/HEIGHT replication)."""
        col_name = headers[col].strip() if col < len(headers) else "Column"

        def round_up_fractional_inches(value: str) -> Optional[str]:
            if not value:
                return None
            cleaned = value.strip().lower()
            frac_match = re.search(r"(\d+)\s*/\s*(\d+)\s*(?:\"|in|inch|inches)?\s*$", cleaned)
            base = cleaned
            numerator = 0
            denominator = 1
            if frac_match:
                numerator = int(frac_match.group(1))
                denominator = int(frac_match.group(2))
                if denominator == 0:
                    return None
                base = cleaned[:frac_match.start()].strip()

            base = base.replace("feet", "'").replace("foot", "'").replace("ft", "'")
            base = base.replace("inches", "").replace("inch", "").replace("in", "")
            base = base.replace('"', "").strip()

            feet = 0
            inches = 0.0
            if "'" in base:
                left, right = base.split("'", 1)
                left = left.strip()
                if left.isdigit():
                    feet = int(left)
                rest = right.strip()
                rest = rest.replace("-", " ")
                nums = re.findall(r"\d+(?:\.\d+)?", rest)
                if nums:
                    inches = float(nums[0])
            else:
                rest = base.replace("-", " ")
                nums = re.findall(r"\d+(?:\.\d+)?", rest)
                if len(nums) == 2:
                    feet = int(float(nums[0]))
                    inches = float(nums[1])
                elif len(nums) == 1 and nums[0]:
                    inches = float(nums[0])
                else:
                    if frac_match:
                        return None

            total_inches = feet * 12.0 + inches
            if frac_match and numerator > 0:
                total_inches = int(total_inches) + 1
            else:
                total_inches = int(total_inches + 0.999999)

            feet = int(total_inches // 12)
            inches = int(total_inches % 12)
            return f"{feet}-{inches}"
        
        # Process all rows automatically
        table.blockSignals(True)
        processed_count = 0
        
        for r in range(table.rowCount()):
            try:
                item = table.item(r, col)
                if item is None:
                    continue
                
                original = item.text()
                result = original
                
                rounded = round_up_fractional_inches(result)
                if rounded is not None:
                    result = rounded

                # Clean up the value (matching VBA logic)
                result = result.replace(" ", "")
                result = result.replace('"', "")
                result = result.replace("'", "")
                
                # Only update if changed
                if result != original:
                    item.setText(result)
                    processed_count += 1
                
            except Exception as e:
                continue
        
        table.blockSignals(False)
        
        # Mark as changed
        if change_callback and processed_count > 0:
            change_callback()
        
        if processed_count > 0:
            QMessageBox.information(
                self,
                f"Clean {col_name}",
                f"Successfully cleaned {processed_count} cell(s)."
            )

    def _clean_fire_rating_column(self, table: QTableWidget, col: int, headers: List[str], change_callback, csv_files):
        """Clean fire rating column values to match dropdown options."""
        col_name = headers[col].strip() if col < len(headers) else "Column"

        # Load dropdown options from dropdown_options.csv
        dropdown_csv_path = None
        workbook_dir = None
        if csv_files:
            workbook_dir = csv_files[0].parent
            dropdown_csv_path = workbook_dir / "dropdown_options.csv"
        if not dropdown_csv_path or not dropdown_csv_path.exists():
            app_root = Path(__file__).parent
            dropdown_csv_path = app_root / "dropdown_options.csv"

        valid_options = []
        if dropdown_csv_path.exists():
            try:
                with open(dropdown_csv_path, 'r', encoding='utf-8-sig') as f:
                    reader = csv.DictReader(f)
                    for row in reader:
                        if 'Rating_Fire' in row and row['Rating_Fire'].strip():
                            valid_options.append(row['Rating_Fire'].strip())
                valid_options = sorted(set(valid_options))
            except Exception as e:
                pass

        if not valid_options:
            valid_options = ['NR', '20M', '45M', '60M', '90M', '180M', '250TR', '450TR', '650TR', '>650TR']

        def standardize_rating(value: str) -> Optional[str]:
            if not value or value.strip() in ('', '-'):
                return 'NR'
            cleaned = value.strip().upper()
            if cleaned in valid_options:
                return cleaned

            # Parse common patterns
            minute_match = re.match(r'^(\d+)\s*(?:MIN(?:UTE)?S?|M)?\.?$', cleaned)
            if minute_match:
                minutes = int(minute_match.group(1))
                return f"{minutes}M"

            hour_match = re.match(r'^(\d+)/(\d+)\s*(?:HOUR?|HR?)S?\.?$', cleaned)
            if hour_match:
                numerator = int(hour_match.group(1))
                denominator = int(hour_match.group(2))
                if denominator > 0:
                    minutes = int((numerator / denominator) * 60)
                    return f"{minutes}M"

            tr_match = re.match(r'^(\d+)\s*(?:TR|TEMP\s*RISE)?\.?$', cleaned)
            if tr_match:
                tr_value = int(tr_match.group(1))
                return f"{tr_value}TR"

            return None

        table.blockSignals(True)
        processed_count = 0
        unresolved = {}

        for r in range(table.rowCount()):
            try:
                item = table.item(r, col)
                if item is None:
                    continue

                original = item.text()
                standardized = standardize_rating(original)

                if standardized is not None and standardized in valid_options:
                    if standardized != original:
                        item.setText(standardized)
                        processed_count += 1
                elif original.strip() not in ('', '-'):
                    unresolved.setdefault(original, []).append(r + 1)

            except Exception as e:
                continue

        table.blockSignals(False)

        # Handle unresolved values
        if unresolved:
            dlg = QDialog(self)
            dlg.setWindowTitle("Unresolved Fire Ratings")
            dlg.setMinimumWidth(600)
            dlg.setMinimumHeight(400)

            layout = QVBoxLayout(dlg)
            layout.addWidget(QLabel("The following values could not be automatically standardized."))
            layout.addWidget(QLabel("Please select the correct option for each:"))

            scroll = QScrollArea()
            scroll_widget = QWidget()
            scroll_layout = QVBoxLayout(scroll_widget)

            combos = {}
            for original_value, row_list in sorted(unresolved.items()):
                label = QLabel(f"'{original_value}':")
                combo = QComboBox()
                combo.addItems(valid_options)
                combo.setEditable(False)
                if 'NR' in valid_options:
                    combo.setCurrentText('NR')
                scroll_layout.addWidget(label)
                scroll_layout.addWidget(combo)
                combos[original_value] = combo

            scroll_layout.addStretch()
            scroll.setWidget(scroll_widget)
            scroll.setWidgetResizable(True)
            layout.addWidget(scroll)

            btn_box = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
            btn_box.accepted.connect(dlg.accept)
            btn_box.rejected.connect(dlg.reject)
            layout.addWidget(btn_box)

            if dlg.exec() == QDialog.DialogCode.Accepted:
                table.blockSignals(True)
                for original_value, combo in combos.items():
                    selected = combo.currentText()
                    for row_idx in unresolved[original_value]:
                        item = table.item(row_idx - 1, col)
                        if item and item.text() == original_value:
                            item.setText(selected)
                            processed_count += 1
                table.blockSignals(False)

        if change_callback and processed_count > 0:
            change_callback()

        if processed_count > 0:
            QMessageBox.information(
                self,
                f"Clean {col_name}",
                f"Successfully standardized {processed_count} cell(s)."
            )

    def _clean_stc_column(self, table: QTableWidget, col: int, headers: List[str], change_callback, csv_files):
        """Clean STC column values by filling blanks with NA and extracting numbers."""
        col_name = headers[col].strip() if col < len(headers) else "Column"

        # Load dropdown options from dropdown_options.csv (if available)
        dropdown_csv_path = None
        workbook_dir = None
        if csv_files:
            workbook_dir = csv_files[0].parent
            dropdown_csv_path = workbook_dir / "dropdown_options.csv"
        if not dropdown_csv_path or not dropdown_csv_path.exists():
            app_root = Path(__file__).parent
            dropdown_csv_path = app_root / "dropdown_options.csv"

        valid_options = []
        if dropdown_csv_path.exists():
            try:
                with open(dropdown_csv_path, 'r', encoding='utf-8-sig') as f:
                    reader = csv.DictReader(f)
                    for row in reader:
                        # Check both STC and Rating_Acoustic columns
                        stc_value = row.get('STC', '').strip() or row.get('Rating_Acoustic', '').strip()
                        if stc_value:
                            valid_options.append(stc_value)
                valid_options = sorted(set(valid_options))
            except Exception as e:
                pass

        if not valid_options:
            valid_options = ['NA', '25', '30', '35', '40', '45', '50', '55']

        def standardize_stc(value: str) -> Optional[str]:
            if not value or value.strip() in ('', '-'):
                return 'NA'
            cleaned = value.strip().upper()
            if cleaned in valid_options:
                return cleaned

            # Extract numbers from the value
            numbers = re.findall(r'\d+', cleaned)
            if numbers:
                return numbers[0]
            
            # Can't parse - return None to trigger manual selection
            return None

        table.blockSignals(True)
        processed_count = 0
        unresolved = {}

        for r in range(table.rowCount()):
            try:
                item = table.item(r, col)
                if item is None:
                    continue

                original = item.text()
                standardized = standardize_stc(original)

                if standardized is not None:
                    if standardized != original:
                        item.setText(standardized)
                        processed_count += 1
                else:
                    # No number found - add to unresolved
                    unresolved.setdefault(original, []).append(r + 1)

            except Exception as e:
                continue

        table.blockSignals(False)

        # Handle unresolved values (no numbers found)
        if unresolved:
            dlg = QDialog(self)
            dlg.setWindowTitle("Unresolved STC Values")
            dlg.setMinimumWidth(600)
            dlg.setMinimumHeight(400)

            layout = QVBoxLayout(dlg)
            layout.addWidget(QLabel("The following values could not be automatically standardized."))
            layout.addWidget(QLabel("Please select the correct option for each:"))

            scroll = QScrollArea()
            scroll_widget = QWidget()
            scroll_layout = QVBoxLayout(scroll_widget)

            combos = {}
            for original_value, row_list in sorted(unresolved.items()):
                label = QLabel(f"'{original_value}':")
                combo = QComboBox()
                combo.addItems(valid_options)
                combo.setEditable(False)
                if 'NA' in valid_options:
                    combo.setCurrentText('NA')
                scroll_layout.addWidget(label)
                scroll_layout.addWidget(combo)
                combos[original_value] = combo

            scroll_layout.addStretch()
            scroll.setWidget(scroll_widget)
            scroll.setWidgetResizable(True)
            layout.addWidget(scroll)

            btn_box = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
            btn_box.accepted.connect(dlg.accept)
            btn_box.rejected.connect(dlg.reject)
            layout.addWidget(btn_box)

            if dlg.exec() == QDialog.DialogCode.Accepted:
                table.blockSignals(True)
                for original_value, combo in combos.items():
                    selected = combo.currentText()
                    for row_idx in unresolved[original_value]:
                        item = table.item(row_idx - 1, col)
                        if item and item.text() == original_value:
                            item.setText(selected)
                            processed_count += 1
                table.blockSignals(False)

        if change_callback and processed_count > 0:
            change_callback()

        if processed_count > 0:
            QMessageBox.information(
                self,
                f"Clean {col_name}",
                f"Successfully standardized {processed_count} cell(s)."
            )

    def _open_door_plan_elevations_dialog(self, table: QTableWidget, headers: List[str], change_callback, tables_data=None):
        door_plan_col = self._get_header_index(headers, "Door Plan Type")
        elevation_col = self._get_header_index(headers, "Elevation")
        if door_plan_col is None or elevation_col is None:
            QMessageBox.information(
                self,
                "Door Plan Elevations",
                "'Door Plan Type' and 'Elevation' columns are required in the Schedule table."
            )
            return

        # Schedule table includes a leading checkbox column (""); apply offset when reading/writing cells.
        table_col_offset = 0
        if table.columnCount() == len(headers) + 1:
            table_col_offset = 1
        else:
            first_header = table.horizontalHeaderItem(0)
            if first_header and first_header.text().strip() == "":
                table_col_offset = 1

        door_plan_col += table_col_offset
        elevation_col += table_col_offset

        dropdown_csv_path = None
        if tables_data:
            for t, path, _, _ in tables_data:
                if t is table:
                    dropdown_csv_path = Path(path).parent / "dropdown_options.csv"
                    break
        if not dropdown_csv_path or not dropdown_csv_path.exists():
            app_root = Path(__file__).parent
            dropdown_csv_path = app_root / "dropdown_options.csv"

        dropdown_options = load_dropdown_options(str(dropdown_csv_path))
        elevation_options = list(dropdown_options.get("Elevation", []))
        if "" not in elevation_options:
            elevation_options = [""] + elevation_options

        plan_types = []
        seen = set()
        for r in range(table.rowCount()):
            item = table.item(r, door_plan_col)
            if not item:
                continue
            value = item.text().strip()
            if not value:
                continue
            key = value.lower()
            if key in seen:
                continue
            seen.add(key)
            plan_types.append(value)

        if not plan_types:
            QMessageBox.information(
                self,
                "Door Plan Elevations",
                "No Door Plan Type values were found in the Schedule table."
            )
            return

        def find_current_elevation(plan_key):
            for r in range(table.rowCount()):
                item = table.item(r, door_plan_col)
                if not item:
                    continue
                if item.text().strip().lower() == plan_key:
                    elev_item = table.item(r, elevation_col)
                    if elev_item and elev_item.text().strip():
                        return elev_item.text().strip()
            return ""

        dlg = QDialog(self)
        dlg.setWindowTitle("Door Plan Elevations")
        dlg.resize(*clamped_size(600, 500))

        layout = QVBoxLayout(dlg)

        mode_row = QHBoxLayout()
        rb_blanks = QRadioButton("Only update blanks")
        rb_all = QRadioButton("Update all")
        rb_blanks.setChecked(True)
        mode_row.addWidget(rb_blanks)
        mode_row.addWidget(rb_all)
        mode_row.addStretch()
        chk_filtered = QCheckBox("Apply to filtered rows only")
        mode_row.addWidget(chk_filtered)
        layout.addLayout(mode_row)

        header_row = QHBoxLayout()
        header_row.addWidget(QLabel("Door Plan Type"))
        header_row.addStretch()
        header_row.addWidget(QLabel("Elevation"))
        layout.addLayout(header_row)

        scroll = QScrollArea()
        scroll_widget = QWidget()
        grid = QGridLayout(scroll_widget)
        grid.setColumnStretch(0, 1)
        grid.setColumnStretch(1, 0)

        combos = {}
        for row_idx, plan_type in enumerate(plan_types):
            label = QLabel(plan_type)
            combo = QComboBox()
            combo.setEditable(False)
            combo.addItems(elevation_options)
            current = find_current_elevation(plan_type.lower())
            if current and current not in elevation_options:
                combo.addItem(current)
            if current:
                combo.setCurrentText(current)
            grid.addWidget(label, row_idx, 0)
            grid.addWidget(combo, row_idx, 1)
            combos[plan_type.lower()] = combo

        grid.setRowStretch(len(plan_types), 1)
        scroll.setWidget(scroll_widget)
        scroll.setWidgetResizable(True)
        layout.addWidget(scroll)

        btn_row = QHBoxLayout()
        btn_apply = QPushButton("Apply")
        btn_cancel = QPushButton("Cancel")
        btn_row.addWidget(btn_apply)
        btn_row.addWidget(btn_cancel)
        layout.addLayout(btn_row)

        def apply_changes():
            selected = {}
            for plan_key, combo in combos.items():
                value = combo.currentText().strip()
                if value:
                    selected[plan_key] = value

            if not selected:
                QMessageBox.information(
                    dlg,
                    "Door Plan Elevations",
                    "Select at least one elevation value to apply."
                )
                return

            update_blanks_only = rb_blanks.isChecked()
            filtered_only = chk_filtered.isChecked()

            table.blockSignals(True)
            updated = 0
            for r in range(table.rowCount()):
                if filtered_only and table.isRowHidden(r):
                    continue
                plan_item = table.item(r, door_plan_col)
                if not plan_item:
                    continue
                plan_key = plan_item.text().strip().lower()
                if not plan_key or plan_key not in selected:
                    continue

                elev_item = table.item(r, elevation_col)
                if update_blanks_only and elev_item and elev_item.text().strip():
                    continue

                new_value = selected[plan_key]
                if elev_item is None:
                    elev_item = QTableWidgetItem(new_value)
                    table.setItem(r, elevation_col, elev_item)
                else:
                    elev_item.setText(new_value)
                updated += 1

            table.blockSignals(False)

            if change_callback and updated > 0:
                change_callback()

            QMessageBox.information(
                dlg,
                "Door Plan Elevations",
                f"Updated {updated} row(s)."
            )
            dlg.accept()

        btn_apply.clicked.connect(apply_changes)
        btn_cancel.clicked.connect(dlg.reject)

        dlg.exec()


    def _export_schedule_to_pdf(self, file_path: Path, headers: List[str], data_rows: List[List[str]], project_name: str) -> None:
        """Export Schedule data to PDF."""
        if not HAS_REPORTLAB:
            return
        
        try:
            from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer
            from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
            
            pagesize = (17 * inch, 11 * inch)
            doc = SimpleDocTemplate(str(file_path), pagesize=pagesize, leftMargin=0.5*inch, rightMargin=0.5*inch)
            styles = getSampleStyleSheet()
            
            wrap_style = getSampleStyleSheet()['BodyText']
            wrap_style.fontSize = 7
            wrap_style.leading = 9
            
            _accent = self._load_company_accent_color()
            _hdr_text = colors.HexColor(self._accent_text_color(_accent))
            header_wrap_style = getSampleStyleSheet()['BodyText']
            header_wrap_style.fontSize = 7
            header_wrap_style.leading = 9
            header_wrap_style.textColor = _hdr_text
            
            title_style = ParagraphStyle(
                'DarkTitle',
                parent=styles['Title'],
                textColor=colors.HexColor(_accent),
                fontSize=14,
                spaceAfter=12,
            )
            
            pdf_title = f"{project_name} - Door Schedule"
            elements = [Paragraph(pdf_title, title_style), Spacer(1, 12)]
            
            # Create wrapped cells
            wrapped_headers = [Paragraph(str(h), header_wrap_style) for h in headers]
            wrapped_rows = []
            for row in data_rows:
                wrapped_row = [Paragraph(str(cell), wrap_style) for cell in row]
                wrapped_rows.append(wrapped_row)
            
            data = [wrapped_headers] + wrapped_rows
            
            # Calculate column widths
            page_width = pagesize[0] - 1.0 * inch
            col_width = page_width / len(headers) if headers else page_width
            col_widths = [col_width] * len(headers)
            
            table = Table(data, colWidths=col_widths, repeatRows=1)
            table.setStyle(TableStyle([
                ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor(_accent)),
                ('TEXTCOLOR', (0, 0), (-1, 0), _hdr_text),
                ('GRID', (0, 0), (-1, -1), 0.5, colors.grey),
                ('FONTSIZE', (0, 0), (-1, -1), 7),
                ('BOTTOMPADDING', (0, 0), (-1, -1), 6),
                ('TOPPADDING', (0, 0), (-1, -1), 6),
                ('LEFTPADDING', (0, 0), (-1, -1), 3),
                ('RIGHTPADDING', (0, 0), (-1, -1), 3),
                ('VALIGN', (0, 0), (-1, -1), 'TOP'),
                ('ROWHEIGHT', (0, 1), (-1, -1), None),
            ]))
            elements.append(table)
            
            doc.build(elements)
        except Exception as e:
            print(f"Schedule PDF export error: {e}")

    def _export_proposal_pdf(self, parent: QWidget, fields: List[Tuple[str, str]], workbook_path: Optional[Path] = None) -> None:
        if not HAS_REPORTLAB:
            QMessageBox.warning(
                parent,
                "Proposal PDF",
                "ReportLab is not installed. Run: pip install reportlab"
            )
            return

        field_map = {name.strip().lower(): (value or "").strip() for name, value in fields}

        def get_value(name: str, default: str = "") -> str:
            return field_map.get(name.lower(), default)

        total_bid = get_value("Total Base Bid")
        if total_bid and total_bid != "-":
            numeric = self._parse_financials_number(total_bid)
            if numeric:
                total_bid = self._format_currency(numeric)

        def get_estimator_contact_info(estimator_name: str) -> Tuple[str, str, str]:
            if not self.company_contacts_csv.exists():
                return "", "", ""

            estimator_name_norm = (estimator_name or "").strip().lower()
            exact_match = None
            default_estimator = None
            first_estimator = None

            try:
                with open(self.company_contacts_csv, 'r', newline='', encoding='utf-8-sig') as f:
                    reader = csv.DictReader(f)
                    for row in reader:
                        position = (row.get("Position") or "").strip()
                        if not self._position_matches(position, "Estimator"):
                            continue

                        name = (row.get("Contact Name") or "").strip()
                        email = (row.get("Email") or "").strip()
                        phone = (row.get("Phone") or "").strip()
                        is_default = (row.get("Default") or "").strip().lower() == "true"
                        candidate = (name, email, phone)

                        if first_estimator is None:
                            first_estimator = candidate
                        if is_default and default_estimator is None:
                            default_estimator = candidate
                        if estimator_name_norm and name.lower() == estimator_name_norm:
                            exact_match = candidate

                selected = exact_match or default_estimator or first_estimator
                if not selected:
                    return "", "", ""
                return selected
            except Exception:
                return "", "", ""

        # Get proposal type from job info
        proposal_type = "Proposal"
        if workbook_path:
            job_path = workbook_path.parent.parent
            info = read_info(job_path)
            proposal_type = info.get("proposal_type", "Proposal") or "Proposal"

        project_name = get_value("Project")
        revision_value = get_value("Revision")
        timestamp_value = datetime.now().strftime("%Y-%m-%d %H%M")
        revision_suffix = sanitize_name(revision_value) if revision_value else "0"

        if project_name:
            safe_name = sanitize_name(project_name)
            default_name = f"{proposal_type} - {safe_name} - Rev {revision_suffix} - {timestamp_value}.pdf"
        else:
            default_name = f"{proposal_type} - Rev {revision_suffix} - {timestamp_value}.pdf"

        save_path: Optional[Path] = None
        if workbook_path:
            bid_path = workbook_path.parent.parent
            proposals_dir = bid_path / "3.Proposals"
            if not proposals_dir.exists():
                try:
                    for child in bid_path.iterdir():
                        if child.is_dir() and child.name.lower().startswith("3.proposal"):
                            proposals_dir = child
                            break
                except Exception:
                    pass
            proposals_dir.mkdir(parents=True, exist_ok=True)
            save_path = proposals_dir / default_name

        if save_path is None:
            default_dir = str(workbook_path) if workbook_path else ""
            default_path = str(Path(default_dir) / default_name) if default_dir else default_name
            file_path, _ = QFileDialog.getSaveFileName(
                parent,
                "Save Proposal PDF",
                default_path,
                "PDF Files (*.pdf)"
            )
            if not file_path:
                return
            save_path = Path(file_path)

        if save_path.suffix.lower() != ".pdf":
            save_path = save_path.with_suffix(".pdf")

        if save_path.exists():
            stem = save_path.stem
            suffix = save_path.suffix
            i = 2
            while True:
                candidate = save_path.with_name(f"{stem} ({i}){suffix}")
                if not candidate.exists():
                    save_path = candidate
                    break
                i += 1

        file_path = str(save_path)

        page_width, page_height = letter
        margin = 0.75 * inch
        content_width = page_width - (2 * margin)
        _accent_hex = self._load_company_accent_color()
        accent_bg = colors.HexColor(_accent_hex)
        accent_fg = colors.HexColor(self._accent_text_color(_accent_hex))

        def draw_section_bar(c, y, text):
            bar_height = 20
            c.setFillColor(accent_bg)
            c.rect(margin, y - bar_height, content_width, bar_height, stroke=0, fill=1)
            c.setFillColor(accent_fg)
            c.setFont("Helvetica-Bold", 8)
            c.drawCentredString(page_width / 2, y - bar_height + 6, text)
            c.setFillColor(colors.black)
            return y - bar_height - 8

        def draw_labeled_line(c, x, y, label, value, width, label_width=70):
            c.setFont("Helvetica-Bold", 9)
            c.drawString(x, y, f"{label}:")
            value_x = x + label_width
            c.setFont("Helvetica", 9)
            c.drawString(value_x, y, value)
            c.setLineWidth(0.5)
            c.line(value_x, y - 2, x + width, y - 2)
            return y - 16

        def draw_wrapped(c, x, y, text, max_width, leading=12, font="Helvetica", size=9):
            c.setFont(font, size)
            if not text:
                return y - leading
            lines = simpleSplit(text, font, size, max_width)
            for line in lines:
                c.drawString(x, y, line)
                y -= leading
            return y

        c = canvas.Canvas(file_path, pagesize=letter)
        y = page_height - margin

        def new_page():
            nonlocal y
            c.showPage()
            y = page_height - margin

        logo_path = Path.home() / ".goro" / "company_logo.png"
        if logo_path.exists():
            logo = ImageReader(str(logo_path))
            logo_width, logo_height = logo.getSize()
            max_logo_width = 170
            max_logo_height = 56
            logo_scale = min(max_logo_width / logo_width, max_logo_height / logo_height)
            target_width = logo_width * logo_scale
            target_height = logo_height * logo_scale
            c.drawImage(
                logo,
                (page_width - target_width) / 2,
                y - target_height,
                width=target_width,
                height=target_height,
                mask='auto'
            )
            y -= target_height + 14

        c.setFont("Helvetica-Bold", 16)
        c.setFillColor(accent_bg)
        c.drawCentredString(page_width / 2, y, "Proposal")
        y -= 18

        c.setFillColor(colors.black)
        c.setFont("Helvetica", 8)
        y -= 4

        col_gap = 10
        col_width = (content_width - col_gap) / 2
        left_x = margin
        right_x = margin + col_width + col_gap

        y = draw_labeled_line(c, left_x, y, "Date", get_value("Date"), col_width)
        y = draw_labeled_line(c, right_x, y + 16, "Rev", get_value("Revision"), col_width, label_width=40)
        y = draw_labeled_line(c, left_x, y, "Project", project_name, content_width, label_width=60)
        y = draw_labeled_line(c, left_x, y, "Address", get_value("Address"), content_width, label_width=60)
        y = draw_labeled_line(c, left_x, y, "Design Team", get_value("Design Team"), content_width, label_width=80)

        y = draw_labeled_line(c, left_x, y, "Plan Date", get_value("Plan Date"), col_width, label_width=60)
        y = draw_labeled_line(
            c,
            right_x,
            y + 16,
            "Total Base Bid",
            total_bid or "-",
            col_width,
            label_width=90
        )

        y -= 6
        
        sections = [
            ("SCOPE OF WORK", [(
                True,
                [("Division 8:", get_value("Scope of Work", "Doors, Frames & Hardware"))]
            )]),
            ("ALTERNATES", [(False, [("", get_value("Alternates"))])]),
            ("BREAKOUTS", [(False, [("", get_value("Breakouts"))])]),
            ("CLARIFICATIONS", [(False, [("", get_value("Clarifications"))])]),
            ("EXCLUSIONS", [(False, [("", get_value("Exclusions"))])]),
            ("LEAD TIME FROM APPROVED SUBMITTALS", [(True, [("", get_value("Lead Time"))])]),
        ]

        filtered_sections = []
        for section_title, content in sections:
            has_visible_content = False
            for _, items in content:
                for _, text in items:
                    if (text or "").strip():
                        has_visible_content = True
                        break
                if has_visible_content:
                    break
            if has_visible_content:
                filtered_sections.append((section_title, content))
        
        for section_title, content in filtered_sections:
            if y < margin + 200:
                new_page()
            y = draw_section_bar(c, y, section_title)
            
            for is_bold, items in content:
                for label, text in items:
                    if label:
                        if is_bold:
                            c.setFont("Helvetica-Bold", 9)
                        else:
                            c.setFont("Helvetica-Bold", 9)
                        c.drawString(left_x, y, label)
                        y = draw_wrapped(c, left_x + 70 if label else left_x, y, text, content_width - (70 if label else 0))
                    else:
                        if is_bold:
                            y = draw_wrapped(c, left_x, y, text, content_width, font="Helvetica-Bold", size=9)
                        else:
                            y = draw_wrapped(c, left_x, y, text, content_width)
                    y -= 4
                    # Check if we need a new page during content drawing
                    if y < margin + 80:
                        new_page()
                        y = draw_section_bar(c, y, section_title)
        
        closing_text = "Please feel free to contact me with any questions or requests. We appreciate being given the opportunity to continue to work with you on this project."
        closing_lines = simpleSplit(closing_text, "Helvetica", 9, content_width)
        required_footer_space = 20 + (len(closing_lines) * 12) + 8 + 24 + 14

        estimator_val = get_value("Estimator")
        estimator_name, estimator_email, estimator_phone = get_estimator_contact_info(estimator_val)
        if not estimator_val and estimator_name:
            estimator_val = estimator_name

        if estimator_email:
            required_footer_space += 16
        if estimator_phone:
            required_footer_space += 16

        if y < margin + required_footer_space:
            new_page()
        
        y -= 10
        y = draw_wrapped(
            c,
            left_x,
            y,
            closing_text,
            content_width
        )
        y -= 8
        c.setFont("Helvetica", 9)
        c.drawString(left_x, y, "Respectfully,")
        y -= 24
        c.setFont("Helvetica-Bold", 9)
        c.drawString(left_x, y, "Estimator:")
        c.setFont("Helvetica", 9)
        if estimator_val:
            c.drawString(left_x + 80, y, estimator_val)

        if estimator_email:
            y -= 14
            c.setFont("Helvetica-Bold", 9)
            c.drawString(left_x, y, "Email:")
            c.setFont("Helvetica", 9)
            c.drawString(left_x + 80, y, estimator_email)

        if estimator_phone:
            y -= 14
            c.setFont("Helvetica-Bold", 9)
            c.drawString(left_x, y, "Phone:")
            c.setFont("Helvetica", 9)
            c.drawString(left_x + 80, y, estimator_phone)

        c.save()
        
        # Ask user if they want to include the Schedule
        include_schedule_reply = QMessageBox.question(
            parent,
            "Include Schedule",
            "Would you like to include the Door Schedule PDF at the end of this proposal?",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
            QMessageBox.StandardButton.No
        )
        
        if include_schedule_reply == QMessageBox.StandardButton.Yes and workbook_path:
            try:
                # Create a temporary file for the Schedule PDF
                import tempfile
                temp_dir = tempfile.gettempdir()
                schedule_temp_pdf = Path(temp_dir) / f"schedule_temp_{uuid.uuid4().hex}.pdf"
                
                # Export Schedule to the temporary location
                schedule_csv_path = workbook_path / "Schedule.csv"
                if schedule_csv_path.exists():
                    # Read schedule data
                    with open(schedule_csv_path, 'r', newline='', encoding='utf-8-sig') as f:
                        reader = csv.reader(f)
                        rows = list(reader)
                    
                    if rows:
                        headers = [str(h) if h is not None else "" for h in rows[0]]
                        data_rows = rows[1:]
                        
                        # Check if CSV has checkbox column and normalize
                        has_checkbox_header = False
                        if headers and headers[0].strip() in ("", "", "", "", "Select", "Sel"):
                            has_checkbox_header = True
                        
                        if has_checkbox_header:
                            headers = headers[1:]
                            normalized_rows = []
                            for row in data_rows:
                                if len(row) > 1:
                                    normalized_rows.append(row[1:])
                                else:
                                    normalized_rows.append(row)
                            data_rows = normalized_rows
                        
                        # Trim trailing blank rows
                        while data_rows and not any(cell.strip() for cell in data_rows[-1]):
                            data_rows.pop()
                        
                        # Show column selection dialog
                        column_dialog = QDialog(parent)
                        column_dialog.setWindowTitle("Select Schedule Columns for Export")
                        column_dialog.setMinimumWidth(500)
                        layout = QVBoxLayout(column_dialog)
                        
                        # Radio buttons for mode selection
                        mode_group = QGroupBox("Export Mode")
                        mode_layout = QVBoxLayout(mode_group)
                        
                        current_view_radio = QRadioButton("Current View (show all visible columns)")
                        current_view_radio.setChecked(True)
                        manual_radio = QRadioButton("Select Columns Manually")
                        saved_view_radio = QRadioButton("Load Saved View")
                        
                        mode_layout.addWidget(current_view_radio)
                        mode_layout.addWidget(manual_radio)
                        mode_layout.addWidget(saved_view_radio)
                        layout.addWidget(mode_group)
                        
                        # Saved views for Schedule
                        saved_views = {}
                        views_str = self.settings.value("schedule_export_views_schedule", "")
                        if views_str:
                            try:
                                saved_views = json.loads(views_str)
                            except:
                                pass
                        
                        saved_view_combo = QComboBox()
                        saved_view_combo.addItems(list(saved_views.keys()))
                        saved_view_combo.setEnabled(False)
                        saved_view_layout = QHBoxLayout()
                        saved_view_layout.addWidget(QLabel("View:"))
                        saved_view_layout.addWidget(saved_view_combo)
                        
                        if not saved_views:
                            saved_view_radio.setEnabled(False)
                            saved_view_radio.setToolTip("No saved views yet.")
                        
                        layout.addLayout(saved_view_layout)
                        
                        # Scrollable column selection area
                        scroll = QScrollArea()
                        scroll.setWidgetResizable(True)
                        checkbox_widget = QWidget()
                        checkbox_layout = QVBoxLayout(checkbox_widget)
                        checkbox_layout.setContentsMargins(0, 0, 0, 0)
                        
                        checkboxes = {}
                        for header in headers:
                            cb = QCheckBox(header)
                            cb.setChecked(True)
                            checkboxes[header] = cb
                            checkbox_layout.addWidget(cb)
                        
                        checkbox_layout.addStretch()
                        scroll.setWidget(checkbox_widget)
                        scroll.setEnabled(False)
                        
                        layout.addWidget(QLabel("Columns:"))
                        layout.addWidget(scroll)
                        
                        # Save view button
                        save_view_btn = QPushButton("Save Current Selection as View")
                        save_view_btn.setMaximumWidth(220)
                        save_view_btn.setEnabled(False)
                        def save_current_view():
                            view_name, ok = QInputDialog.getText(column_dialog, "Save View", "View name:")
                            if ok and view_name.strip():
                                selected_cols = [h for h, cb in checkboxes.items() if cb.isChecked()]
                                saved_views[view_name.strip()] = selected_cols
                                self.settings.setValue("schedule_export_views_schedule", json.dumps(saved_views))
                                saved_view_combo.blockSignals(True)
                                saved_view_combo.clear()
                                saved_view_combo.addItems(list(saved_views.keys()))
                                saved_view_combo.setCurrentIndex(max(0, len(saved_views) - 1))
                                saved_view_combo.blockSignals(False)
                                if not saved_view_radio.isEnabled():
                                    saved_view_radio.setEnabled(True)
                                    saved_view_radio.setToolTip("")
                                QMessageBox.information(column_dialog, "View Saved", f"View '{view_name.strip()}' saved successfully.")
                        save_view_btn.clicked.connect(save_current_view)
                        layout.addWidget(save_view_btn)
                        
                        # Connect radio buttons
                        def on_mode_changed():
                            scroll.setEnabled(manual_radio.isChecked())
                            save_view_btn.setEnabled(manual_radio.isChecked())
                            saved_view_combo.setEnabled(saved_view_radio.isChecked())
                        
                        current_view_radio.toggled.connect(on_mode_changed)
                        manual_radio.toggled.connect(on_mode_changed)
                        saved_view_radio.toggled.connect(on_mode_changed)
                        
                        # Dialog buttons
                        button_box = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
                        button_box.accepted.connect(column_dialog.accept)
                        button_box.rejected.connect(column_dialog.reject)
                        layout.addWidget(button_box)
                        
                        if column_dialog.exec() == QDialog.DialogCode.Accepted:
                            # Determine which columns to keep
                            if current_view_radio.isChecked():
                                columns_to_keep = set(headers)
                            elif saved_view_radio.isChecked():
                                view_name = saved_view_combo.currentText()
                                columns_to_keep = set(saved_views.get(view_name, headers))
                            else:
                                columns_to_keep = {header for header, cb in checkboxes.items() if cb.isChecked()}
                            
                            if columns_to_keep:
                                # Filter columns
                                col_keep_indices = [i for i, h in enumerate(headers) if h in columns_to_keep]
                                filtered_headers = [headers[i] for i in col_keep_indices]
                                filtered_rows = [[row[i] if i < len(row) else '' for i in col_keep_indices] for row in data_rows]
                                
                                # Export to temporary PDF
                                project_name = workbook_path.parent.parent.name
                                self._export_schedule_to_pdf(schedule_temp_pdf, filtered_headers, filtered_rows, project_name)
                                
                                # Merge PDFs if Schedule export was successful
                                if schedule_temp_pdf.exists() and HAS_PYPDF2:
                                    try:
                                        merger = PdfMerger()
                                        merger.append(file_path)  # Proposal first
                                        merger.append(str(schedule_temp_pdf))  # Schedule second
                                        
                                        temp_merged = file_path + ".merged"
                                        merger.write(temp_merged)
                                        merger.close()
                                        
                                        # Replace original with merged
                                        shutil.move(temp_merged, file_path)
                                        
                                        # Clean up temp schedule PDF
                                        schedule_temp_pdf.unlink(missing_ok=True)
                                    except Exception as e:
                                        QMessageBox.warning(parent, "PDF Merge Error", f"Could not merge PDFs:\n{e}")
                                        schedule_temp_pdf.unlink(missing_ok=True)
                                elif schedule_temp_pdf.exists() and not HAS_PYPDF2:
                                    QMessageBox.warning(parent, "PDF Merge Error", "PDF merge library is not installed (PyPDF2 or pypdf).")
                                    schedule_temp_pdf.unlink(missing_ok=True)
            except Exception as e:
                QMessageBox.warning(parent, "Schedule Export Error", f"Could not export Schedule:\n{e}")

        # Offer to append Hardware Groups summary
        include_hw_reply = QMessageBox.question(
            parent,
            "Include Hardware Groups",
            "Would you like to include the Hardware Groups summary at the end of this proposal?",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
            QMessageBox.StandardButton.No,
        )
        if include_hw_reply == QMessageBox.StandardButton.Yes and workbook_path:
            try:
                hw_groups_csv = workbook_path / "Hardware_Groups.csv"
                hw_csv = workbook_path / "Hardware.csv"
                if hw_groups_csv.exists():
                    groups_data = build_hw_groups_data_from_csv(
                        hw_groups_csv,
                        hw_csv if hw_csv.exists() else None,
                    )
                    if groups_data:
                        hw_groups_temp_pdf = Path(tempfile.gettempdir()) / f"hw_groups_temp_{uuid.uuid4().hex}.pdf"
                        write_hardware_groups_pdf(str(hw_groups_temp_pdf), groups_data)
                        if hw_groups_temp_pdf.exists() and HAS_PYPDF2:
                            try:
                                merger = PdfMerger()
                                merger.append(file_path)
                                merger.append(str(hw_groups_temp_pdf))
                                temp_merged = file_path + ".merged"
                                merger.write(temp_merged)
                                merger.close()
                                shutil.move(temp_merged, file_path)
                                hw_groups_temp_pdf.unlink(missing_ok=True)
                            except Exception as merge_e:
                                QMessageBox.warning(parent, "PDF Merge Error", f"Could not merge Hardware Groups PDF:\n{merge_e}")
                                hw_groups_temp_pdf.unlink(missing_ok=True)
                        elif hw_groups_temp_pdf.exists() and not HAS_PYPDF2:
                            QMessageBox.warning(parent, "PDF Merge Error", "PDF merge library is not installed (PyPDF2 or pypdf).")
                            hw_groups_temp_pdf.unlink(missing_ok=True)
            except Exception as e:
                QMessageBox.warning(parent, "Hardware Groups Export Error", f"Could not export Hardware Groups:\n{e}")

        QMessageBox.information(parent, "Proposal PDF", f"PDF saved to:\n{file_path}")

    def upgrade_workbook_format(
        self,
        workbook_path: Path,
        tab_widget: "QTabWidget",
        tables_data: list,
        mark_schedule_changed,
        parent: Optional[QWidget] = None,
    ) -> None:
        """Upgrade workbook CSVs to match the current template column layout.

        For each CSV in the workbook that has a corresponding template in
        ``data/WB_Template/``, the function compares headers.  When they
        differ, existing data rows are re-mapped into the template column
        order by case-insensitive header name matching.  New template
        columns get blank values; old columns absent from the template are
        preserved at the end so no user data is lost.
        """
        template_dir = APP_ROOT / "data" / "WB_Template"
        if not template_dir.is_dir():
            QMessageBox.warning(
                parent or self,
                "Update Workbook Format",
                "Template directory not found.",
            )
            return

        # Gather all template header sets keyed by filename.
        templates: Dict[str, List[str]] = {}
        for tp in sorted(template_dir.glob("*.csv")):
            t_headers, _ = self._read_csv_table(tp)
            if t_headers:
                templates[tp.name] = t_headers

        if not templates:
            QMessageBox.warning(
                parent or self,
                "Update Workbook Format",
                "No template CSVs found.",
            )
            return

        upgraded_files: List[str] = []
        skipped_files: List[str] = []

        for entry_idx, (widget, csv_path, old_headers, quoted_col_idx) in enumerate(tables_data):
            csv_name = csv_path.name if isinstance(csv_path, Path) else str(csv_path)
            if csv_name not in templates:
                continue

            new_headers = templates[csv_name]

            # Normalise for comparison.
            old_norm = [h.strip().lower() for h in old_headers]
            new_norm = [h.strip().lower() for h in new_headers]

            if old_norm == new_norm:
                skipped_files.append(csv_name)
                continue

            # Build mapping: new-column-index → old-column-index (or None).
            old_lookup: Dict[str, int] = {}
            for i, h in enumerate(old_norm):
                if h and h not in old_lookup:
                    old_lookup[h] = i

            col_map: List[Optional[int]] = []
            for nh in new_norm:
                col_map.append(old_lookup.get(nh))

            # Identify old columns NOT present in the new template (extras).
            mapped_old_indices = {idx for idx in col_map if idx is not None}
            extra_old: List[int] = [i for i in range(len(old_headers)) if i not in mapped_old_indices]

            final_headers = list(new_headers) + [old_headers[i] for i in extra_old]

            # Re-read the on-disk CSV to get raw data (preserves formulas).
            if isinstance(csv_path, Path) and csv_path.exists():
                _, old_data = self._read_csv_table(csv_path)
            else:
                old_data = []

            new_data: List[List[str]] = []
            for row in old_data:
                new_row: List[str] = []
                for old_idx in col_map:
                    if old_idx is not None and old_idx < len(row):
                        new_row.append(row[old_idx])
                    else:
                        new_row.append("")
                for ei in extra_old:
                    new_row.append(row[ei] if ei < len(row) else "")
                new_data.append(new_row)

            # Write upgraded CSV.
            try:
                with open(csv_path, "w", newline="", encoding="utf-8-sig") as f:
                    writer = csv.writer(f)
                    writer.writerow(final_headers)
                    writer.writerows(new_data)
                upgraded_files.append(csv_name)
            except Exception as exc:
                QMessageBox.warning(
                    parent or self,
                    "Update Workbook Format",
                    f"Failed to write {csv_name}:\n{exc}",
                )

        if not upgraded_files:
            QMessageBox.information(
                parent or self,
                "Update Workbook Format",
                "All workbook tabs already match the current template format.",
            )
            return

        # Report results and ask to reload.
        summary = "Updated columns for:\n  • " + "\n  • ".join(upgraded_files)
        if skipped_files:
            summary += "\n\nAlready up to date:\n  • " + "\n  • ".join(skipped_files)
        summary += "\n\nThe workbook will now reload to apply the changes."

        QMessageBox.information(
            parent or self,
            "Update Workbook Format",
            summary,
        )

        # Close and re-open the schedule dialog to reload fresh data.
        if isinstance(parent, QDialog):
            parent.done(QDialog.DialogCode.Accepted)
            QTimer.singleShot(200, lambda: self.view_schedule(workbook_path))

    def export_to_protech_txt(self, workbook_path: Optional[Path] = None, parent: Optional[QWidget] = None) -> None:
        """Export Schedule data to ProTech format (tab-delimited text file).
        
        Maps Schedule columns to ProTech format:
        - Opening Number → Tag
        - Count → QTY
        - Width → Width
        - Height → Height
        - Rating_Fire → Label
        - Location → Location
        - Hardware Group → HdwSet
        - Phase → Phase
        - Handing → Hand
        - Frame Type → FrElev
        - Door Type → DrElev
        - Wall Tag → WallType
        - Wall Size → WallThick
        - UOM determines LeafQty (1 for single, 2 for pair)
        
        Args:
            workbook_path: Path to the workbook directory
            parent: Parent widget for dialogs
        """
        if workbook_path is None:
            return
        
        if parent is None:
            parent = self
        
        try:
            # Read Schedule.csv
            schedule_csv_path = workbook_path / "Schedule.csv"
            
            if not schedule_csv_path.exists():
                QMessageBox.warning(parent, "Export to ProTech", 
                                  "Schedule.csv not found in the workbook.")
                return
            
            # Read the CSV file
            try:
                with open(schedule_csv_path, 'r', newline='', encoding='utf-8-sig') as f:
                    reader = csv.reader(f)
                    rows = list(reader)
            except Exception as e:
                QMessageBox.critical(parent, "Export to ProTech", 
                                   f"Failed to read Schedule.csv:\n{e}")
                return
            
            if not rows:
                QMessageBox.warning(parent, "Export to ProTech", 
                                  "Schedule.csv is empty.")
                return
            
            # Get headers
            headers = [str(h).strip() if h else "" for h in rows[0]]
            data_rows = rows[1:]
            
            # Create lookup dictionary for header indices (case-insensitive)
            header_map = {h.lower(): i for i, h in enumerate(headers)}
            
            # Helper function to get column index by name or aliases
            def get_col_idx(names):
                if isinstance(names, str):
                    names = [names]
                for name in names:
                    idx = header_map.get(name.lower())
                    if idx is not None:
                        return idx
                return None
            
            # Find required columns
            col_opening_num = get_col_idx("opening number")
            col_count = get_col_idx("count")
            col_uom = get_col_idx("uom")
            col_width = get_col_idx("width")
            col_height = get_col_idx("height")
            col_rating = get_col_idx(["rating_fire", "rating fire", "fire rating"])
            col_location = get_col_idx("location")
            col_hw_group = get_col_idx(["hardware group", "hardware_group", "hdwset"])
            col_phase = get_col_idx("phase")
            col_hand = get_col_idx(["hand", "handing"])
            col_frame_type = get_col_idx(["frame type", "frame_type", "frelev"])
            col_door_type = get_col_idx(["door type", "door_type", "drelev"])
            col_wall_tag = get_col_idx(["wall tag", "wall_tag", "walltype"])
            col_wall_size = get_col_idx(["wall size", "wall_size", "wallthick"])
            
            # ProTech output headers
            protech_headers = ["Tag", "QTY", "UOM", "Width", "Height", "Label", "Location", 
                             "HdwSet", "Phase", "Hand", "FrElev", "DrElev", "WallType", "WallThick", "LeafQty"]
            
            # Build ProTech rows
            protech_rows = [protech_headers]
            
            for row in data_rows:
                # Skip empty rows
                if not any(cell.strip() for cell in row):
                    continue
                
                # Get cell value safely
                def get_cell(col_idx):
                    if col_idx is None or col_idx >= len(row):
                        return ""
                    return str(row[col_idx]).strip()
                
                tag = get_cell(col_opening_num)
                qty = get_cell(col_count)
                uom_val = get_cell(col_uom).upper()
                width = get_cell(col_width)
                height = get_cell(col_height)
                label = get_cell(col_rating)
                location = get_cell(col_location)
                hdwset = get_cell(col_hw_group)
                phase = get_cell(col_phase)
                hand = get_cell(col_hand)
                frelev = get_cell(col_frame_type)
                drelev = get_cell(col_door_type)
                walltype = get_cell(col_wall_tag)
                wallthick = get_cell(col_wall_size)
                
                # Determine LeafQty based on UOM (1 for single, 2 for pair)
                if "PAIR" in uom_val or "PR" in uom_val:
                    leaf_qty = "2"
                    if not uom_val:
                        uom_val = "PR"
                else:
                    leaf_qty = "1"
                    if not uom_val:
                        uom_val = "SGL"
                
                protech_row = [tag, qty, uom_val, width, height, label, location, 
                              hdwset, phase, hand, frelev, drelev, walltype, wallthick, leaf_qty]
                protech_rows.append(protech_row)
            
            if len(protech_rows) == 1:
                QMessageBox.warning(parent, "Export to ProTech", 
                                  "No data rows found in Schedule.csv.")
                return
            
            # Get the base name from Proposal sheet if available, otherwise from workbook folder
            base_name = None
            proposal_json_path = workbook_path / "Proposal.json"
            
            if proposal_json_path.exists():
                try:
                    with open(proposal_json_path, 'r', encoding='utf-8') as f:
                        proposal_data = json.load(f)
                        # Look for Project field
                        for field_list in proposal_data.get("fields", []):
                            if isinstance(field_list, (list, tuple)) and len(field_list) > 0:
                                if field_list[0] == "Project":
                                    base_name = field_list[1] if len(field_list) > 1 else None
                                    break
                except Exception:
                    pass
            
            # Fall back to workbook folder name if no project name found
            if not base_name:
                base_name = workbook_path.name
            
            if not base_name or not base_name.strip():
                QMessageBox.warning(parent, "Export to ProTech", 
                                  "Could not determine a project name.")
                return
            
            base_name = base_name.strip()
            
            # Sanitize the filename (remove invalid characters)
            clean_name = base_name
            invalid_chars = set('\\/:*?"<>|')
            clean_name = "".join(ch for ch in clean_name if ch not in invalid_chars)
            
            # Handle reserved DOS device names
            reserved_names = {
                "CON", "PRN", "AUX", "NUL",
                "COM1", "COM2", "COM3", "COM4", "COM5", "COM6", "COM7", "COM8", "COM9",
                "LPT1", "LPT2", "LPT3", "LPT4", "LPT5", "LPT6", "LPT7", "LPT8", "LPT9"
            }
            
            if clean_name.upper() in reserved_names:
                clean_name = clean_name + "_export"
            
            # Remove trailing spaces and dots
            while clean_name and clean_name[-1] in (' ', '.'):
                clean_name = clean_name[:-1]
            
            if not clean_name:
                QMessageBox.warning(parent, "Export to ProTech", 
                                  "The sanitized filename is empty.")
                return
            
            file_name = clean_name + "_Export.txt"
            
            # Determine Desktop path
            if get_system() == "Darwin":  # macOS
                desktop_path = Path.home() / "Desktop"
            else:  # Windows and others
                try:
                    # Try to get Desktop from Windows Shell
                    desktop_path = Path(os.environ.get("USERPROFILE", str(Path.home()))) / "Desktop"
                except Exception:
                    desktop_path = Path.home() / "Desktop"
            
            full_path = desktop_path / file_name
            
            # Ensure Desktop directory exists
            desktop_path.mkdir(parents=True, exist_ok=True)
            
            # Handle file name collision
            if full_path.exists():
                stem = full_path.stem
                suffix = full_path.suffix
                counter = 2
                while True:
                    new_name = f"{stem} ({counter}){suffix}"
                    full_path = desktop_path / new_name
                    if not full_path.exists():
                        break
                    counter += 1
            
            # Write tab-delimited text file
            try:
                with open(full_path, 'w', newline='', encoding='utf-8') as f:
                    writer = csv.writer(f, delimiter='\t')
                    writer.writerows(protech_rows)
            except Exception as e:
                QMessageBox.critical(parent, "Export to ProTech", 
                                   f"Failed to save file:\n{e}")
                return
            
            # Success message
            msg = f"Exported to Desktop:\n{file_name}\n\n({len(protech_rows) - 1} openings)"
            QMessageBox.information(parent, "Export to ProTech", msg)
            
            # Offer to open in file explorer
            if QMessageBox.question(parent, "Open Location", 
                                   "Would you like to open the file location?",
                                   QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No) == QMessageBox.StandardButton.Yes:
                open_in_file_manager(desktop_path)
        
        except Exception as e:
            QMessageBox.critical(parent, "Export to ProTech", 
                               f"Unexpected error:\n{e}")


    # ---------- Config & Templates ----------

    def choose_root(self):
        start = str(self.paths.root)
        dirpath = QFileDialog.getExistingDirectory(self, "Choose Data Root", start)
        if not dirpath:
            return
        root = Path(dirpath)
        bids, projects, submitted, awarded = ensure_dirs(root)
        self.paths = Paths(root, bids, projects, submitted, awarded)
        self.settings.setValue("root_dir", str(root))
        self._migrate_submitted_bids_to_submitted_folder()
        self.refresh_list()
        self.statusBar().showMessage(f"Root set to: {root}", 5000)

    def edit_templates(self):
        current_bid = self.name_templates["bids"]

        nbid, ok1 = QInputDialog.getText(
            self, "Bid Name Template",
            "Placeholders: {YYYY}, {###}\nExample: Bid_{YYYY}-{###}",
            text=current_bid
        )
        if ok1 and nbid.strip():
            self.name_templates["bids"] = nbid.strip()

        self.settings.setValue("template_bids", self.name_templates["bids"])
        self.statusBar().showMessage("Name templates updated.", 4000)

    def _create_milestone_for_workbook(self, workbook_path: Path):
        """Open dialog to create a milestone for the selected workbook."""
        try:
            owner = _resolve_transient_parent(self)
            if not workbook_path.exists():
                QMessageBox.warning(owner, "Milestone", "Workbook folder not found.")
                return
            
            # Open Create Milestone Dialog
            dlg = CreateMilestoneDialog(owner)
            result = dlg.exec()
            
            if result == QDialog.DialogCode.Accepted:
                milestone_name, description = dlg.get_data()
                
                if not milestone_name:
                    QMessageBox.warning(owner, "Milestone", "Please enter a milestone name.")
                    return
                
                # Create the milestone
                try:
                    create_milestone(workbook_path, milestone_name, description)
                    QMessageBox.information(
                        owner,
                        "Milestone Created", 
                        f"Milestone '{milestone_name}' created successfully."
                    )
                    self.statusBar().showMessage(f"Milestone '{milestone_name}' created.", 4000)
                except Exception as e:
                    QMessageBox.critical(
                        owner,
                        "Milestone Error", 
                        f"Failed to create milestone:\n{e}"
                    )
        except Exception as e:
            QMessageBox.critical(
                owner if 'owner' in locals() else self,
                "Milestone Error", 
                f"Error opening milestone dialog:\n{e}"
            )

    def _manage_milestones_for_workbook(self, workbook_path: Path):
        """Open dialog to manage milestones for the selected workbook."""
        try:
            owner = _resolve_transient_parent(self)
            if not workbook_path.exists():
                QMessageBox.warning(owner, "Milestone", "Workbook folder not found.")
                return
            
            # Get list of milestones
            milestones_list = list_milestones(workbook_path)
            
            if not milestones_list:
                QMessageBox.information(
                    owner,
                    "No Milestones", 
                    "This workbook has no milestones yet.\nCreate one using 'Create Milestone'."
                )
                return
            
            # Get workbook name from path
            workbook_name = workbook_path.name
            
            # Open Manage Milestones Dialog
            dlg = ManageMilestonesDialog(
                workbook_path,
                workbook_name,
                owner,
                view_schedule_callback=self.view_schedule,
            )
            result = dlg.exec()
            
            # The dialog handles the actual operations (revert, copy, compare, delete)
            # Refresh the subfolder list to show any changes
            p = self.selected_path()
            if p:
                self._update_subfolder_list(p)
                
        except Exception as e:
            QMessageBox.critical(
                owner if 'owner' in locals() else self,
                "Milestone Error", 
                f"Error managing milestones:\n{e}"
            )
    
    def _send_selected_to_alternate(self, schedule_table: QTableWidget, schedule_headers: List[str], 
                                    alternates_widget: 'AlternatesWidget', mark_changed_callback):
        """Send selected openings to an alternate."""
        # Get checked rows from checkbox column (column 0)
        selected_rows = []
        for row in range(schedule_table.rowCount()):
            chk_item = schedule_table.item(row, 0)
            if chk_item and chk_item.checkState() == Qt.CheckState.Checked:
                selected_rows.append(row)
        
        if not selected_rows:
            QMessageBox.warning(schedule_table.window(), "No Selection", "Please check one or more rows to send to an alternate.")
            return
        
        # Get existing alternates from all alternates datasets.
        existing_alternates = sorted(
            set(alternates_widget.alternates_openings_data.keys()) |
            set(alternates_widget.alternates_costs_data.keys()) |
            set(alternates_widget.alternates_subcontractor_data.keys()) |
            set(alternates_widget.alternates_details_data.keys())
        )
        
        # Show dialog
        dlg = SendToAlternateDialog(existing_alternates, schedule_table.window())
        if dlg.exec() != QDialog.DialogCode.Accepted:
            return
        
        alternate_num, remove_from_schedule = dlg.get_result()
        if alternate_num is None:
            return
        alternate_num = str(alternate_num).strip()
        
        # Find column indices (shifted by 1 due to checkbox column at position 0)
        opening_num_col = None
        door_type_col = None
        frame_type_col = None
        hw_group_col = None
        
        for idx, header in enumerate(schedule_headers):
            header_lower = header.strip().lower()
            if header_lower == "opening #" or header_lower == "opening number":
                opening_num_col = idx + 1  # Shift by 1 for checkbox column
            elif header_lower == "door type":
                door_type_col = idx + 1
            elif header_lower == "frame type":
                frame_type_col = idx + 1
            elif header_lower == "hardware group":
                hw_group_col = idx + 1
        
        if opening_num_col is None:
            QMessageBox.warning(schedule_table.window(), "Error", "Could not find 'Opening #' column in Schedule.")
            return
        
        # Collect openings to add to alternate
        openings_to_add = []
        for row in selected_rows:
            opening_num_item = schedule_table.item(row, opening_num_col)
            opening_num = opening_num_item.text().strip() if opening_num_item else ""
            
            door_type_item = schedule_table.item(row, door_type_col) if door_type_col is not None else None
            door_type = door_type_item.text().strip() if door_type_item else ""
            
            frame_type_item = schedule_table.item(row, frame_type_col) if frame_type_col is not None else None
            frame_type = frame_type_item.text().strip() if frame_type_item else ""
            
            hw_group_item = schedule_table.item(row, hw_group_col) if hw_group_col is not None else None
            hw_group = hw_group_item.text().strip() if hw_group_item else ""
            
            if opening_num:
                openings_to_add.append((opening_num, door_type, frame_type, hw_group, "Add"))
        
        if not openings_to_add:
            QMessageBox.warning(schedule_table.window(), "No Valid Openings", "No valid openings found in the selected rows.")
            return
        
        # Add openings to alternate
        if alternate_num not in alternates_widget.alternates_openings_data:
            alternates_widget.alternates_openings_data[alternate_num] = []
        
        alternates_widget.alternates_openings_data[alternate_num].extend(openings_to_add)
        alternates_widget.changes_made = True
        
        # Remove from schedule if requested
        if remove_from_schedule:
            # Sort rows in descending order to delete from bottom to top
            for row in sorted(selected_rows, reverse=True):
                schedule_table.removeRow(row)
            mark_changed_callback()
        
        # Update alternates widget UI
        alternates_widget.update_alternates_list()
        if alternates_widget.current_alternate == alternate_num:
            alternates_widget.load_alternate_openings()
            alternates_widget._recalculate_current_alternate_sell()
        
        # Show confirmation
        QMessageBox.information(
            schedule_table.window(),
            "Success",
            f"Added {len(openings_to_add)} opening(s) to Alternate {alternate_num}."
        )

    def _delete_selected_schedule_rows(self, schedule_table: QTableWidget, schedule_headers: List[str], mark_changed_callback):
        """Delete schedule rows selected via checkbox column (same selection model as Send to Alternate)."""
        selected_rows = []
        for row in range(schedule_table.rowCount()):
            chk_item = schedule_table.item(row, 0)
            if chk_item and chk_item.checkState() == Qt.CheckState.Checked:
                selected_rows.append(row)

        if not selected_rows:
            QMessageBox.warning(schedule_table.window(), "No Selection", "Please check one or more rows to delete.")
            return

        reply = QMessageBox.question(
            schedule_table.window(),
            "Delete Selected Rows",
            f"Delete {len(selected_rows)} checked row(s) from Schedule?",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
            QMessageBox.StandardButton.No,
        )
        if reply != QMessageBox.StandardButton.Yes:
            return

        for row in sorted(selected_rows, reverse=True):
            schedule_table.removeRow(row)

        quoted_col_idx = None
        for idx, header in enumerate(schedule_headers):
            if header.strip().lower() == "quoted":
                quoted_col_idx = idx + 1
                break
        checkbox_cols = [0]
        if quoted_col_idx is not None:
            checkbox_cols.append(quoted_col_idx)
        _ensure_single_trailing_blank_row(schedule_table, checkbox_cols)

        mark_changed_callback()
        trigger_unit_costs = getattr(schedule_table, "_trigger_unit_costs", None)
        if callable(trigger_unit_costs):
            trigger_unit_costs()

